// Genera y abre un HTML imprimible como PDF desde una tabla de datos
function exportarPDF({ titulo, subtitulo, columnas, filas, totales, consorcioNombre, logoB64 }) {
  const fmtN = n => (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2 })
  const logo = logoB64 ? `<img src="${logoB64}" style="height:48px;width:auto;object-fit:contain"/>` : ''
  const encHTML = columnas.map(c=>`<th style="padding:4px 7px;background:#2e4057;color:#fff;font-size:8pt;white-space:nowrap;text-align:${c.align||'left'}">${c.label}</th>`).join('')
  const filasHTML = filas.map((f,i)=>`<tr style="background:${i%2===0?'#fff':'#f4f8fc'};border-bottom:1px solid #e0e8f0">${
    columnas.map(c=>`<td style="padding:3px 7px;font-size:8pt;text-align:${c.align||'left'};white-space:${c.nowrap?'nowrap':'normal'}">${f[c.key]??'—'}</td>`).join('')
  }</tr>`).join('')
  const totalesHTML = totales ? `<tr style="background:#0d2b3e;color:#fff;font-weight:700">${
    columnas.map(c=>`<td style="padding:4px 7px;font-size:8pt;text-align:${c.align||'left'}">${totales[c.key]??''}</td>`).join('')
  }</tr>` : ''
  const html = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><style>
    *{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;font-size:9pt;color:#111}
    .page{width:210mm;padding:10mm 11mm 8mm}
    @page{size:A4 portrait;margin:0}@media print{body{margin:0}.no-print{display:none!important}*{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}}
    .hdr{display:flex;align-items:center;gap:12px;border-bottom:3px solid #1A3FA0;padding-bottom:6px;margin-bottom:10px}
    table{width:100%;border-collapse:collapse}
    .footer{margin-top:10px;border-top:1px solid #ccc;padding-top:3px;font-size:6.5pt;color:#666;display:flex;justify-content:space-between}
    .btn-imp{display:block;margin:10px auto;padding:8px 22px;background:#1A3FA0;color:#fff;border:none;border-radius:5px;font-size:13px;cursor:pointer}
  </style></head><body>
  <button class="btn-imp no-print" onclick="window.print()">🖨️ Imprimir / Guardar PDF</button>
  <div class="page">
    <div class="hdr">
      ${logo}
      <div style="flex:1">
        <div style="font-size:12pt;font-weight:700;color:#1A3FA0">${titulo}</div>
        ${subtitulo?`<div style="font-size:9pt;color:#374151">${subtitulo}</div>`:''}
        ${consorcioNombre?`<div style="font-size:8.5pt;color:#6b7280">Consorcio: ${consorcioNombre}</div>`:''}
        <div style="font-size:8pt;color:#9ca3af">Generado: ${new Date().toLocaleDateString('es-AR')} — Administración de Consorcios Pinamar — R.P.A.C. N° 83</div>
      </div>
    </div>
    <table><thead><tr>${encHTML}</tr></thead><tbody>${filasHTML}</tbody>${totalesHTML?`<tfoot>${totalesHTML}</tfoot>`:''}</table>
    <div class="footer"><span>${titulo}</span><span>R.P.A.C. N°83 | Administración Pinamar</span><span>${new Date().toLocaleDateString('es-AR')}</span></div>
  </div></body></html>`
  const blob = new Blob([html], { type:'text/html;charset=utf-8' })
  const url  = URL.createObjectURL(blob)
  window.open(url, '_blank', 'width=950,height=700')
  setTimeout(()=>URL.revokeObjectURL(url), 60000)
}

// Exporta los datos como archivo Excel/CSV descargable
function exportarExcel({ titulo, columnas, filas }) {
  const BOM = '\uFEFF'
  const headers = columnas.map(c => `"${c.label}"`).join(';')
  const rows = filas.map(f =>
    columnas.map(c => {
      const val = f[c.key] ?? ''
      const str = String(val).replace(/"/g, '""')
      return `"${str}"`
    }).join(';')
  )
  const csv = BOM + [headers, ...rows].join('\r\n')
  const blob = new Blob([csv], { type:'text/csv;charset=utf-8' })
  const url  = URL.createObjectURL(blob)
  const a    = document.createElement('a')
  a.href = url; a.download = `${titulo.replace(/\s/g,'-')}-${new Date().toISOString().split('T')[0]}.csv`
  a.click()
  setTimeout(()=>URL.revokeObjectURL(url), 5000)
}

// Componente de barra de búsqueda + botones de exportación reutilizable
function BarraListado({ busqueda, onBuscar, onPDF, onExcel, placeholder = 'Buscar...' }) {
  return (
    <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap', alignItems:'center' }}>
      <div style={{ flex:1, minWidth:200, position:'relative' }}>
        <span style={{ position:'absolute', left:10, top:'50%', transform:'translateY(-50%)', color:GR, fontSize:14 }}>🔍</span>
        <input value={busqueda} onChange={e=>onBuscar(e.target.value)}
          placeholder={placeholder}
          style={{ width:'100%', paddingLeft:34, paddingRight:10, padding:'8px 10px 8px 34px',
            border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
      </div>
      <Btn small color={GR} onClick={onPDF}>🖨️ PDF</Btn>
      <Btn small color={VD} onClick={onExcel}>📊 Excel</Btn>
    </div>
  )
}

function Card({ children, style, onClick }) {
  return <div style={{ background:'#fff', border:'0.5px solid #ddd', borderRadius:10, padding:16, ...style, cursor:onClick?'pointer':undefined }} onClick={onClick}>{children}</div>
}
function Btn({ children, onClick, color, small, disabled, style }) {
  return (
    <button onClick={onClick} disabled={disabled}
      style={{ padding:small?'5px 12px':'8px 18px', borderRadius:7, border:'none',
        background:disabled?'#e5e7eb':(color||AZ), color:disabled?'#9ca3af':'#fff',
        cursor:disabled?'not-allowed':'pointer', fontSize:small?12:13, fontWeight:600, ...style }}>
      {children}
    </button>
  )
}
function BtnSec({ children, onClick, small, style }) {
  return (
    <button onClick={onClick}
      style={{ padding:small?'5px 12px':'8px 18px', borderRadius:7,
        border:'1px solid #d1d5db', background:'#fff', cursor:'pointer',
        fontSize:small?12:13, color:'#374151', ...style }}>
      {children}
    </button>
  )
}
function Input({ label, value, onChange, type='text', placeholder, required }) {
  return (
    <div>
      <div style={{ fontSize:12, color:'#6b7280', marginBottom:4, fontWeight:500 }}>
        {label}{required && <span style={{color:RJ}}> *</span>}
      </div>
      <input type={type} value={value||''} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
        style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, fontFamily:'inherit', boxSizing:'border-box', outline:'none' }} />
    </div>
  )
}
function Sel({ label, value, onChange, opts, required }) {
  return (
    <div>
      <div style={{ fontSize:12, color:'#6b7280', marginBottom:4, fontWeight:500 }}>
        {label}{required && <span style={{color:RJ}}> *</span>}
      </div>
      <select value={value||''} onChange={e=>onChange(e.target.value)}
        style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, fontFamily:'inherit', background:'#fff' }}>
        {opts.map(o => <option key={o.v||o} value={o.v||o}>{o.l||o}</option>)}
      </select>
    </div>
  )
}
function Badge({ text, color='#6b7280', bg }) {
  return (
    <span style={{ fontSize:10, padding:'2px 8px', borderRadius:10, fontWeight:'bold', background:bg||color+'20', color }}>
      {text}
    </span>
  )
}
function Msg({ data }) {
  if (!data) return null
  const colors = { ok:{bg:'#dcfce7',c:'#166534'}, error:{bg:'#fee2e2',c:'#991b1b'}, warn:{bg:'#fef9c3',c:'#854d0e'}, info:{bg:'#dbeafe',c:'#1e40af'} }
  const s = colors[data.tipo] || colors.info
  return <div style={{ background:s.bg, color:s.c, borderRadius:8, padding:'10px 14px', fontSize:13, marginBottom:14 }}>{data.texto}</div>
}

