      <div style="padding-top:14px"><strong>Alias:</strong> ${consorcioActivo.alias_cbu||'—'}<br/><strong>Banco:</strong> ${consorcioActivo.banco||'—'}<br/><strong>Sucursal:</strong> ${consorcioActivo.sucursal||'—'}</div>
