// Constantes para BalanceAnual — estructura fiel al PDF de Constitución 1910
const BA_CATS_ORDER = ['contratos_abonos','gastos_bancarios','honorarios_admin','impuesto_municipal','mantenimiento','otros','seguros','servicios_publicos','varios']
const BA_CATS_LABEL = {
  contratos_abonos:'CONTRATOS Y ABONOS', gastos_bancarios:'GASTOS BANCARIOS',
  honorarios_admin:'GASTOS DE ADMINISTRACIÓN', impuesto_municipal:'IMPUESTO MUNICIPAL',
  mantenimiento:'MANTENIMIENTO GENERAL', otros:'OTROS EGRESOS',
  seguros:'SEGUROS', servicios_publicos:'SERVICIOS PÚBLICOS', varios:'VARIOS'
}
function baNormCat(c) {
  const cc = (c||'').toLowerCase()
    .replace(/[áàä]/g,'a').replace(/[éèë]/g,'e').replace(/[íìï]/g,'i')
    .replace(/[óòö]/g,'o').replace(/[úùü]/g,'u').trim()
  if (cc.includes('contrat')||cc.includes('abon')||cc.includes('piscin')||cc.includes('limpiez')||cc.includes('porton')||cc.includes('portón')) return 'contratos_abonos'
  if (cc.includes('banc')||cc.includes('financiero')) return 'gastos_bancarios'
  if (cc.includes('honorar')||cc.includes('admin')) return 'honorarios_admin'
  if (cc.includes('municipal')||cc.includes('impuest')) return 'impuesto_municipal'
  if (cc.includes('manten')||cc.includes('parque')||cc.includes('ascensor')||cc.includes('bomba')||cc.includes('pintura')||cc.includes('matafuego')||cc.includes('construc')||cc.includes('electric')||cc.includes('gas mant')) return 'mantenimiento'
  if (cc.includes('seguro')) return 'seguros'
  if (cc.includes('energia')||cc.includes('energía')||cc.includes('gas serv')||cc.includes('servicio publ')||cc.includes('calp')||cc.includes('camuzzi')||cc.includes('edenor')||cc.includes('edea')) return 'servicios_publicos'
  if (cc.includes('varios')||cc.includes('material')||cc.includes('ferret')) return 'varios'
  return 'otros'
}

// ── GraficosBalance: función de módulo (fuera del componente) — sin IIFE en JSX ──
function GraficosBalance(datos) {
  if (!datos) return null
  const topCats    = datos.topCats    || []
  const evolucion  = datos.evolucion  || []
  const detalleTop = datos.detalleTopCat || []
  if (!topCats.length && !evolucion.length) return null

  const SVG_W = 480, SVG_H = 220
  const PAD   = { top:20, right:52, bottom:24, left:132 }
  const IW    = SVG_W - PAD.left - PAD.right
  const IH    = SVG_H - PAD.top  - PAD.bottom
  const COLORS= ['#1A3FA0','#1B6B35','#B91C1C','#C07D10','#6B21A8','#0891B2','#B45309','#0F766E','#7C3AED']
  const fmtM  = v => v >= 1e6 ? '$'+(v/1e6).toFixed(1)+'M' : v >= 1e3 ? '$'+(v/1e3).toFixed(0)+'K' : '$'+Math.round(v||0)
  const abbr  = s => (s||'').replace('MANTENIMIENTO GENERAL','MANT. GENERAL').replace('SERVICIOS PÚBLICOS','SERV. PÚBLICOS').replace('CONTRATOS Y ABONOS','CONTR./ABONOS').replace('GASTOS DE ADMINISTRACIÓN','GASTOS ADMIN.').replace('GASTOS BANCARIOS','G. BANCARIOS').replace('IMPUESTO MUNICIPAL','IMP. MUNICIPAL')

  const cats   = topCats.slice(0, 9)
  const maxCat = Math.max(...cats.map(c => c.total || 0), 1)
  const rowH1  = cats.length ? IH / cats.length : IH
  const barH1  = Math.min(22, Math.floor(rowH1) - 4)

  const maxEv  = Math.max(...evolucion.map(e => Math.max(e.ingresos||0, e.egresos||0)), 1)
  const colW2  = evolucion.length ? IW / evolucion.length : IW
  const barW2  = Math.max(3, Math.floor(colW2 / 2) - 1)

  const saldos  = evolucion.map(e => e.saldo || 0)
  const minS    = Math.min(...saldos, 0)
  const maxS    = Math.max(...saldos, 0)
  const rangeS  = (maxS - minS) || 1
  const sxFn    = i => PAD.left + (evolucion.length > 1 ? i/(evolucion.length-1)*IW : IW/2)
  const syFn    = s => PAD.top + (1 - (s - minS)/rangeS)*IH
  const y0line  = Math.min(Math.max(syFn(0), PAD.top), PAD.top + IH)
  const polyPts = evolucion.map((e,i) => sxFn(i).toFixed(1)+','+syFn(e.saldo||0).toFixed(1)).join(' ')
  const areaPath = evolucion.length > 1
    ? 'M '+evolucion.map((e,i)=>sxFn(i).toFixed(1)+' '+syFn(e.saldo||0).toFixed(1)).join(' L ')
      +' L '+sxFn(evolucion.length-1).toFixed(1)+' '+y0line.toFixed(1)
      +' L '+sxFn(0).toFixed(1)+' '+y0line.toFixed(1)+' Z'
    : ''

  const det    = detalleTop.slice(0, 8)
  const maxDet = Math.max(...det.map(d => d.total||0), 1)
  const rowH4  = det.length ? IH/det.length : IH
  const barH4  = Math.min(22, Math.floor(rowH4) - 4)

  const cardStyle = {background:'#fff', border:'1px solid #e5e7eb', borderRadius:8, padding:'12px 8px'}
  const titleStyle = {fontWeight:700, fontSize:11, marginBottom:6}

  return (
    <div style={{marginBottom:16}}>
      <div style={{fontWeight:700, fontSize:13, marginBottom:12, color:'#1A3FA0'}}>📈 Gráficos</div>
      <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:12}}>

        <div style={cardStyle}>
          <div style={{...titleStyle, color:'#1A3FA0'}}>Distribución de egresos por categoría</div>
          <svg width="100%" viewBox={'0 0 '+SVG_W+' '+SVG_H} style={{overflow:'visible'}}>
            {cats.map((c,i) => {
              const y = PAD.top + i*rowH1 + (rowH1-barH1)/2
              const w = Math.max(2, (c.total/maxCat)*IW)
              return <g key={i}>
                <text x={PAD.left-4} y={y+barH1/2+4} textAnchor="end" fontSize={8} fill="#374151">{abbr(c.label)}</text>
                <rect x={PAD.left} y={y} width={w} height={barH1} fill={COLORS[i%COLORS.length]} rx={2}/>
                <text x={PAD.left+w+3} y={y+barH1/2+4} fontSize={7} fill="#374151">{fmtM(c.total)}</text>
              </g>
            })}
            <line x1={PAD.left} y1={PAD.top} x2={PAD.left} y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
          </svg>
        </div>

        <div style={cardStyle}>
          <div style={{...titleStyle, color:'#1A3FA0'}}>Ingresos vs Egresos Mensuales</div>
          <svg width="100%" viewBox={'0 0 '+SVG_W+' '+SVG_H} style={{overflow:'visible'}}>
            {evolucion.map((e,i) => {
              const x  = PAD.left + i*colW2
              const hI = Math.max(0, ((e.ingresos||0)/maxEv)*IH)
              const hE = Math.max(0, ((e.egresos||0)/maxEv)*IH)
              return <g key={i}>
                <rect x={x+2}         y={PAD.top+IH-hI} width={barW2} height={hI} fill="#1B6B35" rx={1}/>
                <rect x={x+barW2+3}   y={PAD.top+IH-hE} width={barW2} height={hE} fill="#B91C1C" rx={1}/>
                <text x={x+barW2+1} y={PAD.top+IH+12} textAnchor="middle" fontSize={7} fill="#6B7280">{e.mes}</text>
              </g>
            })}
            <line x1={PAD.left} y1={PAD.top+IH} x2={PAD.left+IW} y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
            <line x1={PAD.left} y1={PAD.top}     x2={PAD.left}     y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
            <rect x={PAD.left}      y={PAD.top-14} width={10} height={8} fill="#1B6B35" rx={1}/><text x={PAD.left+13} y={PAD.top-7} fontSize={8} fill="#374151">Ingresos</text>
            <rect x={PAD.left+70}   y={PAD.top-14} width={10} height={8} fill="#B91C1C" rx={1}/><text x={PAD.left+83} y={PAD.top-7} fontSize={8} fill="#374151">Egresos</text>
          </svg>
        </div>
      </div>

      <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:12}}>
        <div style={cardStyle}>
          <div style={{...titleStyle, color:'#1A3FA0'}}>Evolución del Saldo Final</div>
          <svg width="100%" viewBox={'0 0 '+SVG_W+' '+SVG_H} style={{overflow:'visible'}}>
            {areaPath && <path d={areaPath} fill="#1A3FA0" fillOpacity={0.12}/>}
            {evolucion.length > 1 && <polyline points={polyPts} fill="none" stroke="#1A3FA0" strokeWidth={2}/>}
            {evolucion.map((e,i) => <circle key={i} cx={sxFn(i)} cy={syFn(e.saldo||0)} r={3} fill="#1A3FA0"/>)}
            {minS < 0 && maxS > 0 && <line x1={PAD.left} y1={y0line} x2={PAD.left+IW} y2={y0line} stroke="#999" strokeDasharray="4 3" strokeWidth={1}/>}
            {evolucion.map((e,i) => <text key={i} x={sxFn(i)} y={PAD.top+IH+12} textAnchor="middle" fontSize={7} fill="#6B7280">{e.mes}</text>)}
            <line x1={PAD.left} y1={PAD.top+IH} x2={PAD.left+IW} y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
            <line x1={PAD.left} y1={PAD.top}     x2={PAD.left}     y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
          </svg>
        </div>

        {det.length > 0 && (
          <div style={cardStyle}>
            <div style={{...titleStyle, color:'#0f2d7a'}}>Desglose de {datos.topCatLabel||''}</div>
            <svg width="100%" viewBox={'0 0 '+SVG_W+' '+SVG_H} style={{overflow:'visible'}}>
              {det.map((d,i) => {
                const y   = PAD.top + i*rowH4 + (rowH4-barH4)/2
                const w   = Math.max(2, (d.total/maxDet)*IW)
                const lbl = (d.concepto||'').length>18 ? d.concepto.slice(0,18)+'…' : (d.concepto||'')
                return <g key={i}>
                  <text x={PAD.left-4} y={y+barH4/2+4} textAnchor="end" fontSize={8} fill="#374151">{lbl}</text>
                  <rect x={PAD.left} y={y} width={w} height={barH4} fill={COLORS[(i+2)%COLORS.length]} rx={2}/>
                  <text x={PAD.left+w+3} y={y+barH4/2+4} fontSize={7} fill="#374151">{fmtM(d.total)}</text>
                </g>
              })}
              <line x1={PAD.left} y1={PAD.top} x2={PAD.left} y2={PAD.top+IH} stroke="#ccc" strokeWidth={1}/>
            </svg>
          </div>
        )}
      </div>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// BALANCE ANUAL — Rendición de cuentas | Estructura fiel al balance formal
// ══════════════════════════════════════════════════════════════════════════════
function BalanceAnual({ session, consorcioId, consorcioActivo }) {
  const [periodoDesde, setPeriodoDesde] = useState(() => {
    const d = new Date(); d.setFullYear(d.getFullYear()-1); return d.toISOString().slice(0,7)
  })
  const [periodoHasta, setPeriodoHasta] = useState(() => new Date().toISOString().slice(0,7))
  const [datos, setDatos]       = useState(null)
  const [cargando, setCargando] = useState(false)
  const [msg, setMsg]           = useState(null)
  const [vista, setVista]       = useState('tabla') // 'tabla' | 'analisis'

  const fmt  = n => (Number(n)||0).toLocaleString('es-AR',{minimumFractionDigits:2,maximumFractionDigits:2})
  const fmtS = (n, forzarSigno) => {
    const v = Number(n)||0; if (v===0) return '—'
    const s = '$' + Math.abs(v).toLocaleString('es-AR',{minimumFractionDigits:2})
    return v < 0 ? '-' + s : (forzarSigno && v > 0 ? '+' + s : s)
  }
  const perLabel = p => {
    if (!p) return ''
    const [y,m] = p.split('-')
    return (['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'][parseInt(m)-1]||m) + ' ' + y.slice(2)
  }

  async function generar() {
    if (!periodoDesde || !periodoHasta || periodoDesde > periodoHasta)
      return setMsg({tipo:'warn', texto:'Seleccioná un rango de períodos válido'})
    setCargando(true); setDatos(null); setMsg(null)
    try {
      // 1) Expensas del rango
      const {data: expensas, error: errExp} = await supabase.from('con_expensas')
        .select('id,periodo,total_cobrado,saldo_caja_final,ingresos_termino,ingresos_adeudados,ingresos_intereses')
        .eq('consorcio_id', consorcioId)
        .gte('periodo', periodoDesde).lte('periodo', periodoHasta)
        .order('periodo')
      if (errExp) throw new Error(errExp.message)
      if (!expensas || expensas.length === 0) {
        setMsg({tipo:'warn', texto:'No hay períodos en el rango seleccionado'})
        setCargando(false); return
      }

      const expIds = expensas.map(e => e.id)

      // 2) Ítems de liquidación (rubros estructurados) — fuente principal de gastos
      const {data: items} = await supabase.from('con_liquidacion_items')
        .select('rubro_nro,rubro_nombre,concepto,proveedor_nombre,importe_total,expensa_id')
        .in('expensa_id', expIds)

      // 3) Gastos adicionales (no importados desde PDF)
      const {data: gastos} = await supabase.from('con_gastos')
        .select('categoria,concepto,monto,expensa_id')
        .in('expensa_id', expIds)
        .not('id','like','GHIST-%') // excluir los gastos generados automáticamente desde historial

      // 4) Saldo anterior al primer período
      let saldoInicial0 = 0
      const {data: expAnt} = await supabase.from('con_expensas')
        .select('saldo_caja_final').eq('consorcio_id', consorcioId)
        .lt('periodo', periodoDesde).order('periodo', {ascending:false}).limit(1)
      if (expAnt && expAnt[0]) saldoInicial0 = parseFloat(expAnt[0].saldo_caja_final)||0

      // ── Construir mapas de ingresos y saldos por período ──
      const saldoInicialPorPeriodo = {}
      const saldoFinalPorPeriodo   = {}
      const ingExpensasPorPeriodo  = {}
      const ingVariosPorPeriodo    = {}
      const ingInteresesPorPeriodo = {}
      let totalIngresos = 0, totalIngExpensas = 0, totalIngVarios = 0

      for (let i = 0; i < expensas.length; i++) {
        const p  = expensas[i].periodo
        const sf = parseFloat(expensas[i].saldo_caja_final)||0
        const tc = parseFloat(expensas[i].ingresos_termino) || parseFloat(expensas[i].total_cobrado)||0
        const iv = parseFloat(expensas[i].ingresos_adeudados)||0
        const ii = parseFloat(expensas[i].ingresos_intereses)||0
        saldoInicialPorPeriodo[p] = i===0 ? saldoInicial0 : (parseFloat(expensas[i-1].saldo_caja_final)||0)
        saldoFinalPorPeriodo[p]   = sf
        ingExpensasPorPeriodo[p]  = tc
        ingVariosPorPeriodo[p]    = iv
        ingInteresesPorPeriodo[p] = ii
        totalIngExpensas += tc; totalIngVarios += iv
        totalIngresos    += tc + iv + ii
      }

      // ── Construir mapa de egresos: cat → concepto → período → monto ──
      // Priorizar con_liquidacion_items (rubros del PDF)
      const mapa        = {}  // cat → concepto → { per → monto }
      const totalsCat   = {}  // cat → { per → monto }
      const totalsGlobal = {} // per → monto
      let totalAnual = 0

      const registrarGasto = (cat, concepto, per, monto) => {
        if (!per || !monto) return
        if (!mapa[cat])               mapa[cat] = {}
        if (!mapa[cat][concepto])     mapa[cat][concepto] = {}
        if (!totalsCat[cat])          totalsCat[cat] = {}
        mapa[cat][concepto][per]  = (mapa[cat][concepto][per]  || 0) + monto
        totalsCat[cat][per]       = (totalsCat[cat][per]       || 0) + monto
        totalsGlobal[per]         = (totalsGlobal[per]         || 0) + monto
        totalAnual += monto
      }

      // Ítems del PDF (fuente estructurada)
      const expMap = new Map(expensas.map(e => [e.id, e.periodo]))
      for (const it of (items||[])) {
        const per    = expMap.get(it.expensa_id)
        const monto  = parseFloat(it.importe_total)||0
        if (!per || !monto) continue
        // Usar rubro_nombre como categoría (más preciso que categoria libre)
        const cat    = baNormCat(it.rubro_nombre)
        // Concepto: proveedor_nombre o concepto, acortado
        const conc   = (it.proveedor_nombre || it.concepto || it.rubro_nombre || '').slice(0,60)
        registrarGasto(cat, conc, per, monto)
      }

      // Gastos adicionales no derivados del historial
      for (const g of (gastos||[])) {
        const per   = expMap.get(g.expensa_id)
        const monto = parseFloat(g.monto)||0
        const cat   = baNormCat(g.categoria)
        const conc  = (g.concepto||'').slice(0,60)
        registrarGasto(cat, conc, per, monto)
      }

      const periodos       = expensas.map(e => e.periodo)
      const resultadoNeto  = totalIngresos - totalAnual

      // ── Análisis ejecutivo ──
      // Ingresos vs egresos por período
      const evolucion = periodos.map(p => ({
        mes: perLabel(p),
        ingresos: (ingExpensasPorPeriodo[p]||0) + (ingVariosPorPeriodo[p]||0),
        egresos:   totalsGlobal[p]||0,
        diferencia: ((ingExpensasPorPeriodo[p]||0) + (ingVariosPorPeriodo[p]||0)) - (totalsGlobal[p]||0),
        saldo: saldoFinalPorPeriodo[p]||0
      }))

      // Top categorías por egreso total
      const topCats = BA_CATS_ORDER
        .map(cat => ({
          label: BA_CATS_LABEL[cat],
          total: Object.values(totalsCat[cat]||{}).reduce((a,b)=>a+b,0),
          pct:   0
        }))
        .filter(c => c.total > 0)
        .sort((a,b) => b.total - a.total)
      if (totalAnual > 0) topCats.forEach(c => { c.pct = (c.total/totalAnual*100).toFixed(2) })

      // Detalle del bloque más grande
      const topCatKey = BA_CATS_ORDER
        .map(cat => [cat, Object.values(totalsCat[cat]||{}).reduce((a,b)=>a+b,0)])
        .sort((a,b)=>b[1]-a[1])[0]?.[0]
      const topCatLabel = BA_CATS_LABEL[topCatKey] || ''
      const topCatTotal = topCatKey ? Object.values(totalsCat[topCatKey]||{}).reduce((a,b)=>a+b,0) : 0
      const detalleTopCat = topCatKey ? Object.entries(mapa[topCatKey]||{}).map(([conc,perMap]) => ({
        concepto: conc,
        total: Object.values(perMap).reduce((a,b)=>a+b,0),
        pct: 0
      })).sort((a,b)=>b.total-a.total) : []
      if (topCatTotal > 0) detalleTopCat.forEach(d => { d.pct = (d.total/topCatTotal*100).toFixed(1) })

      const mesMayorIngreso = evolucion.reduce((a,b) => b.ingresos>a.ingresos?b:a, evolucion[0]||{})
      const mesMayorEgreso  = evolucion.reduce((a,b) => b.egresos>a.egresos?b:a, evolucion[0]||{})
      const mesMejorDif     = evolucion.reduce((a,b) => b.diferencia>a.diferencia?b:a, evolucion[0]||{})
      const mesPeorDif      = evolucion.reduce((a,b) => b.diferencia<a.diferencia?b:a, evolucion[0]||{})
      const mesesPositivo   = evolucion.filter(e=>e.saldo>=0).length
      const saldoMinimo     = evolucion.reduce((a,b)=>b.saldo<a.saldo?b:a, evolucion[0]||{})
      const saldoMaximo     = evolucion.reduce((a,b)=>b.saldo>a.saldo?b:a, evolucion[0]||{})

      setDatos({
        periodos, mapa, totalsCat, totalsGlobal, totalAnual, totalIngresos,
        totalIngExpensas, totalIngVarios,
        ingExpensasPorPeriodo, ingVariosPorPeriodo,
        saldoInicialPorPeriodo, saldoFinalPorPeriodo,
        promedioIngresos: periodos.length>0 ? totalIngresos/periodos.length : 0,
        promedioEgresos:  periodos.length>0 ? totalAnual/periodos.length    : 0,
        resultadoNeto, mesesPositivo, evolucion, topCats, topCatLabel, topCatTotal,
        detalleTopCat, mesMayorIngreso, mesMayorEgreso, mesMejorDif, mesPeorDif,
        saldoMinimo, saldoMaximo,
      })
    } catch (err) {
      setMsg({tipo:'error', texto:'Error al generar: ' + (err.message || String(err))})
    }
    setCargando(false)
  }

  function exportarPDFBalance() {
    if (!datos) return
    const d   = datos
    const w   = window.open('', '_blank')
    if (!w) { alert('Habilitá las ventanas emergentes para imprimir.'); return }
    const hoy = new Date().toLocaleDateString('es-AR')
    const f2  = n => { const v=Number(n)||0; return v!==0 ? v.toLocaleString('es-AR',{minimumFractionDigits:2}) : '—' }
    const f2s = n => { const v=Number(n)||0; if(v===0) return '—'; const s=Math.abs(v).toLocaleString('es-AR',{minimumFractionDigits:2}); return v<0?'-$'+s:'$'+s }
    const nCols = d.periodos.length + 4 // concepto + períodos + total + % + prom

    let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Balance Anual</title><style>
      *{box-sizing:border-box;margin:0;padding:0}
      body{font-family:Arial,sans-serif;font-size:7.5px;padding:8px;color:#111}
      h2{font-size:13px;font-weight:800;margin-bottom:1px}
      .sub{font-size:9px;color:#555;margin-bottom:8px}
      table{width:100%;border-collapse:collapse;margin-bottom:8px}
      th{background:#1A3FA0;color:#fff;padding:3px 4px;text-align:right;white-space:nowrap;font-size:7px}
      th.l{text-align:left;min-width:160px}
      td{padding:2px 4px;border-bottom:1px solid #e5e7eb;text-align:right;white-space:nowrap}
      td.l{text-align:left}
      .si{background:#f0fdf4;font-weight:700;font-size:8px}
      .ing-h{background:#dbeafe;font-weight:700;font-size:7px;text-transform:uppercase}
      .ing-sub{background:#eff6ff;font-weight:700;font-size:7.5px}
      .ing-row td{color:#15803d}
      .eg-h{background:#fee2e2;font-weight:700;font-size:7px;text-transform:uppercase}
      .cat{background:#eff6ff;font-weight:700;font-size:7px;text-transform:uppercase}
      .sub-cat{background:#e0e7ff;font-weight:700;font-size:7px}
      .conc td{color:#555;font-size:7px}
      .tot-eg{background:#1A3FA0;color:#fff;font-weight:700;font-size:8px}
      .sf{background:#f0fdf4;font-weight:700;font-size:8px}
      .neg{color:#dc2626}.pos{color:#15803d}
      .foot{font-size:7.5px;border-top:1px solid #1A3FA0;padding-top:4px;margin-top:4px;color:#555}
      @media print{@page{size:A3 landscape;margin:5mm}body{padding:0}}
    </style></head><body>
    <h2>RENDICIÓN DE CUENTAS ${d.periodos[0]} / ${d.periodos[d.periodos.length-1]}</h2>
    <div class="sub">${consorcioActivo?consorcioActivo.nombre:''} &nbsp;·&nbsp; Javier García Pérez · RPAC N° 83 &nbsp;·&nbsp; ${hoy}</div>
    <table><thead><tr>
      <th class="l">Categoría / Concepto</th>
      ${d.periodos.map(p=>'<th>'+perLabel(p)+'</th>').join('')}
      <th>TOTAL</th><th>%</th><th>PROM.</th>
    </tr></thead><tbody>`

    // Saldo inicial
    html += '<tr class="si"><td class="l">SALDO INICIAL</td>'
    html += d.periodos.map(p=>{const v=d.saldoInicialPorPeriodo[p]||0; return '<td class="'+(v<0?'neg':'pos')+'">'+f2s(v)+'</td>'}).join('')
    html += '<td></td><td></td><td></td></tr>'

    // Ingresos
    html += `<tr class="ing-h"><td class="l" colspan="${nCols}">INGRESOS</td></tr>`
    if (Object.values(d.ingVariosPorPeriodo).some(v=>v>0)) {
      const totV = Object.values(d.ingVariosPorPeriodo).reduce((a,b)=>a+b,0)
      html += '<tr class="ing-row"><td class="l" style="padding-left:10px">Ingresos varios</td>'
      html += d.periodos.map(p=>'<td class="pos">'+f2(d.ingVariosPorPeriodo[p])+'</td>').join('')
      html += `<td class="pos"><b>${f2(totV)}</b></td><td>—</td><td>${f2(totV/d.periodos.length)}</td></tr>`
    }
    html += '<tr class="ing-row"><td class="l" style="padding-left:10px">Expensas</td>'
    html += d.periodos.map(p=>'<td class="pos">'+f2(d.ingExpensasPorPeriodo[p])+'</td>').join('')
    html += `<td class="pos"><b>${f2(d.totalIngExpensas)}</b></td><td style="font-size:7px;color:#555">Incidencia</td><td style="color:#555">Promedio</td></tr>`
    html += '<tr class="ing-sub"><td class="l">Total ingresos</td>'
    html += d.periodos.map(p=>{
      const v=(d.ingExpensasPorPeriodo[p]||0)+(d.ingVariosPorPeriodo[p]||0)
      return '<td class="pos">'+f2(v)+'</td>'
    }).join('')
    html += `<td class="pos"><b>${f2(d.totalIngresos)}</b></td><td></td><td>${f2(d.promedioIngresos)}</td></tr>`

    // Egresos
    html += `<tr class="eg-h"><td class="l" colspan="${nCols}">EGRESOS</td></tr>`
    for (const cat of BA_CATS_ORDER) {
      const conceps = Object.keys(d.mapa[cat]||{})
      if (!conceps.length) continue
      const totalCat = Object.values(d.totalsCat[cat]||{}).reduce((a,b)=>a+b,0)
      const pct = d.totalAnual>0 ? (totalCat/d.totalAnual*100).toFixed(2)+'%' : '0%'
      // Conceptos individuales
      for (const con of conceps) {
        const totalCon = Object.values(d.mapa[cat][con]).reduce((a,b)=>a+b,0)
        html += '<tr class="conc"><td class="l" style="padding-left:12px">'+con+'</td>'
        html += d.periodos.map(p=>'<td>'+f2(d.mapa[cat][con][p])+'</td>').join('')
        html += `<td>${f2(totalCon)}</td><td></td><td>${f2(totalCon/d.periodos.length)}</td></tr>`
      }
      // Subtotal categoría
      html += '<tr class="sub-cat"><td class="l">Subtotal '+BA_CATS_LABEL[cat]+'</td>'
      html += d.periodos.map(p=>'<td><b>'+f2(d.totalsCat[cat]?d.totalsCat[cat][p]:0)+'</b></td>').join('')
      html += `<td><b>${f2(totalCat)}</b></td><td>${pct}</td><td>${f2(totalCat/d.periodos.length)}</td></tr>`
    }
    // Total egresos
    html += '<tr class="tot-eg"><td class="l">Total egresos</td>'
    html += d.periodos.map(p=>'<td>'+f2(d.totalsGlobal[p]||0)+'</td>').join('')
    html += `<td><b>${f2(d.totalAnual)}</b></td><td>100%</td><td>${f2(d.promedioEgresos)}</td></tr>`
    // Saldo final
    html += '<tr class="sf"><td class="l">SALDO FINAL</td>'
    html += d.periodos.map(p=>{const v=d.saldoFinalPorPeriodo[p]||0; return '<td class="'+(v<0?'neg':'pos')+'"><b>'+f2s(v)+'</b></td>'}).join('')
    html += '<td></td><td></td><td></td></tr>'
    html += '</tbody></table>'

    // Resumen pie
    html += `<div class="foot">Ingresos: $${f2(d.totalIngresos)} &nbsp;|&nbsp; Egresos: $${f2(d.totalAnual)} &nbsp;|&nbsp; Resultado neto: $${f2(d.resultadoNeto)} &nbsp;|&nbsp; Meses con saldo positivo: ${d.mesesPositivo}/${d.periodos.length}</div>`

    // ── PÁGINA 2: ANÁLISIS EJECUTIVO ──────────────────────────────────────
    html += `<div style="page-break-before:always"></div>`
    html += `<h2>ANÁLISIS EJECUTIVO — ${d.periodos[0]} / ${d.periodos[d.periodos.length-1]}</h2>`
    html += `<div class="sub">${consorcioActivo?consorcioActivo.nombre:''} &nbsp;·&nbsp; Javier García Pérez · RPAC N° 83 &nbsp;·&nbsp; ${hoy}</div>`

    // KPIs
    html += `<table style="margin-bottom:8px"><tr>
      <th class="l" style="background:#0f2d7a">Indicador</th><th style="background:#0f2d7a">Valor</th></tr>
      <tr><td class="l">Total ingresos anual</td><td class="pos"><b>$${f2(d.totalIngresos)}</b></td></tr>
      <tr><td class="l">Total egresos anual</td><td class="neg"><b>$${f2(d.totalAnual)}</b></td></tr>
      <tr><td class="l">Resultado neto</td><td class="${d.resultadoNeto>=0?'pos':'neg'}"><b>${d.resultadoNeto>=0?'+':''}$${f2(Math.abs(d.resultadoNeto))}</b></td></tr>
      <tr><td class="l">Promedio mensual ingresos</td><td>$${f2(d.promedioIngresos)}</td></tr>
      <tr><td class="l">Promedio mensual egresos</td><td>$${f2(d.promedioEgresos)}</td></tr>
      <tr><td class="l">Meses con saldo positivo</td><td>${d.mesesPositivo} / ${d.periodos.length}</td></tr>
    </table>`

    // Hallazgos
    const topCats3pct = (d.topCats||[]).length>=3
      ? ((d.topCats.slice(0,3).reduce((a,c)=>a+parseFloat(c.pct||0),0)).toFixed(1))
      : '—'
    const hallazgos = [
      `El período cierra con un resultado neto de ${d.resultadoNeto>=0?'superávit':'déficit'} de $${f2(Math.abs(d.resultadoNeto))} (${d.totalIngresos>0?(Math.abs(d.resultadoNeto)/d.totalIngresos*100).toFixed(1):'0'}% de los ingresos).`,
      `${d.mesMayorIngreso?.mes||'—'} fue el mes de mayor ingreso ($${f2(d.mesMayorIngreso?.ingresos||0)}).`,
      `${d.mesMayorEgreso?.mes||'—'} registró el mayor egreso ($${f2(d.mesMayorEgreso?.egresos||0)}).`,
      `El saldo final tocó su mínimo en ${d.saldoMinimo?.mes||'—'} ($${f2(d.saldoMinimo?.saldo||0)}) y su máximo en ${d.saldoMaximo?.mes||'—'} ($${f2(d.saldoMaximo?.saldo||0)}).`,
      `Las 3 categorías más grandes concentran ${topCats3pct}% del gasto: ${(d.topCats||[]).slice(0,3).map(c=>c.label).join(', ')}.`,
      `La mejor diferencia mensual fue ${d.mesMejorDif?.mes||'—'} ($${f2(d.mesMejorDif?.diferencia||0)}) y la peor fue ${d.mesPeorDif?.mes||'—'} ($${f2(d.mesPeorDif?.diferencia||0)}).`,
      `Hubo ${d.mesesPositivo} ${d.mesesPositivo!==1?'meses':'mes'} con saldo final positivo y ${d.periodos.length-d.mesesPositivo} con saldo negativo.`,
      `Mayor concentración de gasto: ${(d.topCats||[])[0]?.label||'—'} ($${f2((d.topCats||[])[0]?.total||0)}, ${(d.topCats||[])[0]?.pct||0}%).`,
    ]
    html += `<div style="margin-bottom:8px;padding:6px 8px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:4px">
      <div style="font-weight:700;font-size:9px;margin-bottom:5px;color:#1A3FA0">🧠 Hallazgos del período</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px">
        ${hallazgos.map(t=>`<div style="font-size:7.5px;padding:3px 5px;background:#fff;border:1px solid #e5e7eb;border-radius:3px;line-height:1.4"><span style="color:#1A3FA0;margin-right:3px">•</span>${t}</div>`).join('')}
      </div>
    </div>`

    // Tabla de 3 columnas
    html += `<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-bottom:8px">`

    // Col 1: Top categorías
    html += `<table><thead><tr>
      <th class="l" colspan="3">Top categorías de egresos</th></tr>
      <tr style="background:#f8fafc"><th class="l" style="background:#f8fafc;color:#555;font-size:7px">Categoría</th>
      <th style="background:#f8fafc;color:#555;font-size:7px">Total</th>
      <th style="background:#f8fafc;color:#555;font-size:7px">%</th></tr>
    </thead><tbody>`
    ;(d.topCats||[]).forEach(c => {
      html += `<tr><td class="l">${c.label}</td><td><b>$${f2(c.total)}</b></td><td style="color:#4338ca">${c.pct}%</td></tr>`
    })
    html += `<tr class="sub-cat"><td class="l">TOTAL</td><td><b>$${f2(d.totalAnual)}</b></td><td>100%</td></tr>`
    html += `</tbody></table>`

    // Col 2: Ingresos vs egresos por mes
    html += `<table><thead><tr>
      <th class="l" colspan="4">Ingresos vs Egresos por mes</th></tr>
      <tr style="background:#f8fafc">
      <th class="l" style="background:#f8fafc;color:#555;font-size:7px">Mes</th>
      <th style="background:#f8fafc;color:#15803d;font-size:7px">Ingresos</th>
      <th style="background:#f8fafc;color:#dc2626;font-size:7px">Egresos</th>
      <th style="background:#f8fafc;color:#555;font-size:7px">Diferencia</th></tr>
    </thead><tbody>`
    ;(d.evolucion||[]).forEach(e => {
      const dif = e.diferencia||0
      html += `<tr><td class="l">${e.mes}</td><td class="pos">$${f2(e.ingresos)}</td><td class="neg">$${f2(e.egresos)}</td><td class="${dif>=0?'pos':'neg'}">${dif>=0?'+':''}$${f2(dif)}</td></tr>`
    })
    html += `<tr class="sub-cat"><td class="l">TOTAL</td><td class="pos"><b>$${f2(d.totalIngresos)}</b></td><td class="neg"><b>$${f2(d.totalAnual)}</b></td><td class="${d.resultadoNeto>=0?'pos':'neg'}"><b>${d.resultadoNeto>=0?'+':''}$${f2(d.resultadoNeto)}</b></td></tr>`
    html += `</tbody></table>`

    // Col 3: Evolución saldo final
    html += `<table><thead><tr>
      <th class="l" colspan="2">Evolución del saldo final</th></tr>
      <tr style="background:#f8fafc">
      <th class="l" style="background:#f8fafc;color:#555;font-size:7px">Mes</th>
      <th style="background:#f8fafc;color:#555;font-size:7px">Saldo final</th></tr>
    </thead><tbody>`
    ;(d.evolucion||[]).forEach(e => {
      const sf = e.saldo||0
      html += `<tr${sf<0?' style="background:#fff5f5"':''}><td class="l">${e.mes}</td><td class="${sf<0?'neg':'pos'}"><b>${sf!==0?(sf>0?'+':'')+'$'+f2(sf):'—'}</b></td></tr>`
    })
    html += `</tbody></table>`
    html += `</div>` // cierra grid 3 columnas

    // Detalle bloque mayor
    if ((d.detalleTopCat||[]).length > 0) {
      html += `<table style="margin-top:4px"><thead><tr>
        <th class="l" colspan="3">Detalle de ${d.topCatLabel||''} — mayor concentración de gasto</th></tr>
        <tr style="background:#f8fafc">
        <th class="l" style="background:#f8fafc;color:#555;font-size:7px">Concepto</th>
        <th style="background:#f8fafc;color:#555;font-size:7px">Total anual</th>
        <th style="background:#f8fafc;color:#555;font-size:7px">% del total</th></tr>
      </thead><tbody>`
      ;(d.detalleTopCat||[]).forEach(dt => {
        html += `<tr><td class="l">${dt.concepto||''}</td><td><b>$${f2(dt.total)}</b></td><td style="color:#4338ca">${dt.pct}%</td></tr>`
      })
      html += `<tr class="sub-cat"><td class="l">TOTAL ${d.topCatLabel||''}</td><td><b>$${f2(d.topCatTotal)}</b></td><td>100%</td></tr>`
      html += `</tbody></table>`
    }

    html += `<div class="foot" style="margin-top:6px">Rendición de cuentas generada por GASP Consorcios · administracionpinamar.com · ${hoy}</div>`
    html += '</body></html>'
    w.document.write(html); w.document.close(); w.focus()
    setTimeout(()=>{try{w.print()}catch(e){}},600)
  }

  async function exportarExcelBalance() {
    if (!datos) return
    if (!window.XLSX) {
      await new Promise((res,rej)=>{
        const s=document.createElement('script'); s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js'
        s.onload=res; s.onerror=rej; document.head.appendChild(s)
      })
    }
    const XLSX = window.XLSX; const d = datos; const fv = n => Number(n)||0
    const rows = [
      ['Rendición de cuentas — '+(consorcioActivo?consorcioActivo.nombre:'')],
      ['Período: '+d.periodos[0]+' al '+d.periodos[d.periodos.length-1]],
      [],
      ['Concepto',...d.periodos,'TOTAL','%','PROMEDIO'],
      ['SALDO INICIAL',...d.periodos.map(p=>fv(d.saldoInicialPorPeriodo[p])),'','',''],
      ['INGRESOS',...d.periodos.map(()=>''),'','',''],
    ]
    if (Object.values(d.ingVariosPorPeriodo).some(v=>v>0)) {
      const totV = Object.values(d.ingVariosPorPeriodo).reduce((a,b)=>a+b,0)
      rows.push(['  Ingresos varios',...d.periodos.map(p=>fv(d.ingVariosPorPeriodo[p])),totV,'',totV/d.periodos.length])
    }
    rows.push(['  Expensas',...d.periodos.map(p=>fv(d.ingExpensasPorPeriodo[p])),d.totalIngExpensas,'Incidencia','Promedio'])
    rows.push(['Total ingresos',...d.periodos.map(p=>(fv(d.ingExpensasPorPeriodo[p])+fv(d.ingVariosPorPeriodo[p]))),d.totalIngresos,'',d.promedioIngresos])
    rows.push(['EGRESOS',...d.periodos.map(()=>''),'','',''])
    for (const cat of BA_CATS_ORDER) {
      const conceps = Object.keys(d.mapa[cat]||{})
      if (!conceps.length) continue
      const totalCat = Object.values(d.totalsCat[cat]||{}).reduce((a,b)=>a+b,0)
      const pct = d.totalAnual>0 ? (totalCat/d.totalAnual*100).toFixed(2)+'%' : '0%'
      for (const con of conceps) {
        const totalCon = Object.values(d.mapa[cat][con]).reduce((a,b)=>a+b,0)
        rows.push(['  '+con,...d.periodos.map(p=>fv(d.mapa[cat][con][p])),totalCon,'',totalCon/d.periodos.length])
      }
      rows.push(['Subtotal '+BA_CATS_LABEL[cat],...d.periodos.map(p=>fv(d.totalsCat[cat]?d.totalsCat[cat][p]:0)),totalCat,pct,totalCat/d.periodos.length])
    }
    rows.push(['Total egresos',...d.periodos.map(p=>fv(d.totalsGlobal[p])),d.totalAnual,'100%',d.promedioEgresos])
    rows.push(['SALDO FINAL',...d.periodos.map(p=>fv(d.saldoFinalPorPeriodo[p])),'','',''])
    rows.push([],['Total ingresos',fv(d.totalIngresos)],['Total egresos',fv(d.totalAnual)],['Resultado neto',fv(d.resultadoNeto)])
    const wb = XLSX.utils.book_new()
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(rows), 'Balance Anual')
    const nombre = consorcioActivo ? consorcioActivo.id : 'cons'
    XLSX.writeFile(wb, 'BalanceAnual_'+nombre+'_'+d.periodos[0]+'_'+d.periodos[d.periodos.length-1]+'.xlsx')
  }

  // ── Construcción de filas de la tabla principal ──
  function buildTablaRows(d) {
    if (!d) return []
    const rows = []

    // Saldo inicial
    rows.push(
      <tr key="si" style={{background:'#f0fdf4',fontWeight:700}}>
        <td style={{padding:'5px 10px',fontSize:10,position:'sticky',left:0,background:'#f0fdf4',fontWeight:700}}>SALDO INICIAL</td>
        {d.periodos.map(p=>{const v=d.saldoInicialPorPeriodo[p]||0
          return <td key={p} style={{padding:'5px 6px',textAlign:'right',color:v<0?RJ:VD,fontSize:9,fontWeight:700}}>{v!==0?fmtS(v,true):'—'}</td>
        })}
        <td colSpan={3}></td>
      </tr>
    )

    // Ingresos header
    rows.push(
      <tr key="ing-h" style={{background:'#dbeafe',fontWeight:700}}>
        <td style={{padding:'5px 10px',fontSize:9,textTransform:'uppercase',position:'sticky',left:0,background:'#dbeafe',fontWeight:700}}>INGRESOS</td>
        {d.periodos.map(p=><td key={p}></td>)}
        <td colSpan={3}></td>
      </tr>
    )

    // Ingresos varios (si los hay)
    if (Object.values(d.ingVariosPorPeriodo).some(v=>v>0)) {
      const totV = Object.values(d.ingVariosPorPeriodo).reduce((a,b)=>a+b,0)
      rows.push(
        <tr key="ing-varios">
          <td style={{padding:'4px 10px',paddingLeft:18,fontSize:9,position:'sticky',left:0,background:'#fff'}}>Ingresos varios</td>
          {d.periodos.map(p=>(
            <td key={p} style={{padding:'4px 6px',textAlign:'right',color:VD,fontSize:9}}>
              {d.ingVariosPorPeriodo[p]>0?'$'+fmt(d.ingVariosPorPeriodo[p]):'—'}
            </td>
          ))}
          <td style={{padding:'4px 6px',textAlign:'right',fontWeight:700,color:VD,fontSize:9}}>${fmt(totV)}</td>
          <td><span style={{fontSize:8,color:GR}}>—</span></td>
          <td style={{padding:'4px 6px',textAlign:'right',fontSize:8,color:GR}}>${fmt(totV/d.periodos.length)}</td>
        </tr>
      )
    }

    // Expensas
    rows.push(
      <tr key="ing-exp">
        <td style={{padding:'4px 10px',paddingLeft:18,fontSize:9,position:'sticky',left:0,background:'#fff'}}>Expensas</td>
        {d.periodos.map(p=>(
          <td key={p} style={{padding:'4px 6px',textAlign:'right',color:VD,fontSize:9}}>
            {d.ingExpensasPorPeriodo[p]>0?'$'+fmt(d.ingExpensasPorPeriodo[p]):'—'}
          </td>
        ))}
        <td style={{padding:'4px 6px',textAlign:'right',fontWeight:700,color:VD,fontSize:9}}>${fmt(d.totalIngExpensas)}</td>
        <td style={{fontSize:8,color:GR,textAlign:'right'}}>Incid.</td>
        <td style={{padding:'4px 6px',textAlign:'right',fontSize:8,color:GR}}>Promedio</td>
      </tr>
    )

    // Total ingresos
    rows.push(
      <tr key="ing-tot" style={{background:'#eff6ff',fontWeight:700}}>
        <td style={{padding:'5px 10px',fontSize:9,position:'sticky',left:0,background:'#eff6ff',fontWeight:700}}>Total ingresos</td>
        {d.periodos.map(p=>{
          const v=(d.ingExpensasPorPeriodo[p]||0)+(d.ingVariosPorPeriodo[p]||0)
          return <td key={p} style={{padding:'5px 6px',textAlign:'right',color:VD,fontWeight:600,fontSize:9}}>${fmt(v)}</td>
        })}
        <td style={{padding:'5px 6px',textAlign:'right',fontWeight:800,color:VD,fontSize:10}}>${fmt(d.totalIngresos)}</td>
        <td></td>
        <td style={{padding:'5px 6px',textAlign:'right',fontSize:9,color:GR}}>${fmt(d.promedioIngresos)}</td>
      </tr>
    )

    // Egresos header
    rows.push(
      <tr key="eg-h" style={{background:'#fee2e2',fontWeight:700}}>
        <td style={{padding:'5px 10px',fontSize:9,textTransform:'uppercase',position:'sticky',left:0,background:'#fee2e2',fontWeight:700}}>EGRESOS</td>
        {d.periodos.map(p=><td key={p}></td>)}
        <td colSpan={3}></td>
      </tr>
    )

    // Categorías con subtotales
    for (const cat of BA_CATS_ORDER) {
      const conceps = Object.keys(d.mapa[cat]||{})
      if (!conceps.length) continue
      const totalCat = Object.values(d.totalsCat[cat]||{}).reduce((a,b)=>a+b,0)
      const pct      = d.totalAnual>0 ? (totalCat/d.totalAnual*100).toFixed(2) : '0'

      // Conceptos individuales
      for (const con of conceps) {
        const totalCon = Object.values(d.mapa[cat][con]).reduce((a,b)=>a+b,0)
        rows.push(
          <tr key={'con-'+cat+'-'+con} style={{borderBottom:'1px solid #f3f4f6'}}>
            <td style={{padding:'3px 10px',paddingLeft:20,fontSize:9,color:GR,position:'sticky',left:0,background:'#fff'}}>{con}</td>
            {d.periodos.map(p=>(
              <td key={p} style={{padding:'3px 6px',textAlign:'right',fontSize:8}}>
                {d.mapa[cat][con][p]?'$'+fmt(d.mapa[cat][con][p]):'—'}
              </td>
            ))}
            <td style={{padding:'3px 6px',textAlign:'right',fontSize:8}}>${fmt(totalCon)}</td>
            <td></td>
            <td style={{padding:'3px 6px',textAlign:'right',fontSize:8,color:GR}}>${fmt(totalCon/d.periodos.length)}</td>
          </tr>
        )
      }

      // Subtotal categoría
      rows.push(
        <tr key={'subtot-'+cat} style={{background:'#e0e7ff',borderTop:'2px solid #c7d2fe'}}>
          <td style={{padding:'4px 10px',fontWeight:700,fontSize:9,position:'sticky',left:0,background:'#e0e7ff'}}>Subtotal {BA_CATS_LABEL[cat]}</td>
          {d.periodos.map(p=>(
            <td key={p} style={{padding:'4px 6px',textAlign:'right',fontWeight:700,fontSize:9}}>
              {(d.totalsCat[cat]&&d.totalsCat[cat][p])?'$'+fmt(d.totalsCat[cat][p]):'—'}
            </td>
          ))}
          <td style={{padding:'4px 6px',textAlign:'right',fontWeight:800,fontSize:9}}>${fmt(totalCat)}</td>
          <td style={{padding:'4px 6px',textAlign:'right',fontSize:8,color:'#4338ca'}}>{pct}%</td>
          <td style={{padding:'4px 6px',textAlign:'right',fontSize:8,color:GR}}>${fmt(totalCat/d.periodos.length)}</td>
        </tr>
      )
    }

    // Total egresos
    rows.push(
      <tr key="total-eg" style={{background:AZ,color:'#fff',fontWeight:700}}>
        <td style={{padding:'6px 10px',fontSize:10,position:'sticky',left:0,background:AZ,fontWeight:700}}>Total egresos</td>
        {d.periodos.map(p=>(
          <td key={p} style={{padding:'6px 6px',textAlign:'right',fontSize:9}}>${fmt(d.totalsGlobal[p]||0)}</td>
        ))}
        <td style={{padding:'6px 6px',textAlign:'right',fontWeight:800,fontSize:10}}>${fmt(d.totalAnual)}</td>
        <td style={{padding:'6px 6px',textAlign:'right',fontSize:8}}>100%</td>
        <td style={{padding:'6px 6px',textAlign:'right',fontSize:9}}>${fmt(d.promedioEgresos)}</td>
      </tr>
    )

    // Saldo final
    rows.push(
      <tr key="sf" style={{background:'#f0fdf4',fontWeight:700}}>
        <td style={{padding:'6px 10px',fontSize:10,position:'sticky',left:0,background:'#f0fdf4',fontWeight:700}}>SALDO FINAL</td>
        {d.periodos.map(p=>{const v=d.saldoFinalPorPeriodo[p]||0
          return (
            <td key={p} style={{padding:'6px 6px',textAlign:'right',color:v<0?RJ:VD,fontWeight:700,fontSize:9}}>
              {v!==0?fmtS(v,true):'—'}
            </td>
          )
        })}
        <td colSpan={3}></td>
      </tr>
    )

    return rows
  }

  return (
    <div>
      {/* Encabezado */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:4}}>
        <div style={{fontWeight:700,fontSize:15}}>📊 Balance Anual</div>
        {datos && (
          <div style={{display:'flex',gap:8}}>
            <Btn small color={GR} onClick={exportarPDFBalance}>🖨️ PDF / Imprimir</Btn>
            <Btn small color={VD} onClick={exportarExcelBalance}>📊 Excel</Btn>
          </div>
        )}
      </div>
      <div style={{fontSize:12,color:GR,marginBottom:16}}>Rendición de cuentas entre períodos seleccionados</div>
      <Msg data={msg} />

      {/* Selector de rango */}
      <Card style={{marginBottom:16}}>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr auto',gap:12,alignItems:'flex-end'}}>
          <div>
            <div style={{fontSize:12,color:GR,marginBottom:4,fontWeight:500}}>Período desde</div>
            <input type="month" value={periodoDesde} onChange={e=>setPeriodoDesde(e.target.value)}
              style={{width:'100%',padding:'8px 11px',border:'1px solid #d1d5db',borderRadius:7,fontSize:13,boxSizing:'border-box'}} />
          </div>
          <div>
            <div style={{fontSize:12,color:GR,marginBottom:4,fontWeight:500}}>Período hasta</div>
            <input type="month" value={periodoHasta} onChange={e=>setPeriodoHasta(e.target.value)}
              style={{width:'100%',padding:'8px 11px',border:'1px solid #d1d5db',borderRadius:7,fontSize:13,boxSizing:'border-box'}} />
          </div>
          <Btn onClick={generar} disabled={cargando}>
            {cargando ? '⏳ Calculando...' : '🔄 Generar balance'}
          </Btn>
        </div>
      </Card>

      {cargando && <div style={{textAlign:'center',padding:32,color:GR}}>⏳ Cargando datos del período...</div>}

      {datos && !cargando && (
        <>
          {/* KPIs principales */}
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:10,marginBottom:16}}>
            {[
              {l:'Total ingresos',  v:'$'+fmt(datos.totalIngresos),  c:VD},
              {l:'Total egresos',   v:'$'+fmt(datos.totalAnual),      c:RJ},
              {l:'Resultado neto',  v:(datos.resultadoNeto>=0?'+':'')+fmtS(Math.abs(datos.resultadoNeto)), c:datos.resultadoNeto>=0?VD:RJ},
              {l:'Meses saldo +',   v:datos.mesesPositivo+' / '+datos.periodos.length, c:AZ},
            ].map((k,i)=>(
              <Card key={i} style={{textAlign:'center',padding:'12px 10px'}}>
                <div style={{fontSize:10,color:GR,textTransform:'uppercase',fontWeight:600,marginBottom:4}}>{k.l}</div>
                <div style={{fontSize:16,fontWeight:800,color:k.c}}>{k.v}</div>
              </Card>
            ))}
          </div>

          {/* Selector de vista */}
          <div style={{display:'flex',gap:8,marginBottom:12}}>
            {[['tabla','📋 Rendición de cuentas'],['analisis','📈 Análisis ejecutivo']].map(([v,l])=>(
              <button key={v} onClick={()=>setVista(v)} style={{
                padding:'6px 16px',borderRadius:6,border:'1px solid '+(vista===v?AZ:'#d1d5db'),
                background:vista===v?AZ:'#fff',color:vista===v?'#fff':GR,
                fontWeight:600,fontSize:12,cursor:'pointer'
              }}>{l}</button>
            ))}
          </div>

          {/* VISTA: TABLA RENDICIÓN */}
          {vista==='tabla' && (
            <Card style={{padding:0,overflowX:'auto',marginBottom:16}}>
              <table style={{width:'100%',borderCollapse:'collapse',fontSize:10,minWidth:datos.periodos.length*75+380}}>
                <thead>
                  <tr style={{background:AZ,color:'#fff'}}>
                    <th style={{padding:'6px 10px',textAlign:'left',fontWeight:700,fontSize:9,minWidth:190,position:'sticky',left:0,background:AZ}}>
                      Categoría / Concepto
                    </th>
                    {datos.periodos.map(p=>(
                      <th key={p} style={{padding:'6px 6px',textAlign:'right',fontSize:8,minWidth:70,whiteSpace:'nowrap'}}>{perLabel(p)}</th>
                    ))}
                    <th style={{padding:'6px 6px',textAlign:'right',fontSize:9,minWidth:90,background:'#0f2d7a'}}>TOTAL</th>
                    <th style={{padding:'6px 6px',textAlign:'right',fontSize:8,minWidth:44,background:'#0f2d7a'}}>%</th>
                    <th style={{padding:'6px 6px',textAlign:'right',fontSize:8,minWidth:80,background:'#0f2d7a'}}>PROM.</th>
                  </tr>
                </thead>
                <tbody>{buildTablaRows(datos)}</tbody>
              </table>
            </Card>
          )}

          {/* VISTA: ANÁLISIS EJECUTIVO */}
          {vista==='analisis' && (
            <div>
              {/* Hallazgos en texto */}
              <Card style={{marginBottom:16,background:'#f8fafc',border:'1px solid #e2e8f0'}}>
                <div style={{fontWeight:700,fontSize:13,marginBottom:12,color:AZ}}>🧠 Hallazgos del período</div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,fontSize:12,color:GR}}>
                  {[
                    `El período cierra con un resultado neto de ${datos.resultadoNeto>=0?'superávit':'déficit'} de $${fmt(Math.abs(datos.resultadoNeto))} (${datos.totalIngresos>0?(Math.abs(datos.resultadoNeto)/datos.totalIngresos*100).toFixed(1):'0'}% de los ingresos).`,
                    `${datos.mesMayorIngreso?.mes||'—'} fue el mes de mayor ingreso ($${fmt(datos.mesMayorIngreso?.ingresos||0)}).`,
                    `${datos.mesMayorEgreso?.mes||'—'} registró el mayor egreso ($${fmt(datos.mesMayorEgreso?.egresos||0)}).`,
                    `El saldo final tocó su mínimo en ${datos.saldoMinimo?.mes||'—'} ($${fmt(datos.saldoMinimo?.saldo||0)}) y su máximo en ${datos.saldoMaximo?.mes||'—'} ($${fmt(datos.saldoMaximo?.saldo||0)}).`,
                    `Las 3 categorías más grandes concentran ${datos.topCats.length>=3?((datos.topCats.slice(0,3).reduce((a,c)=>a+parseFloat(c.pct||0),0)).toFixed(1)):'—'}% del gasto: ${datos.topCats.slice(0,3).map(c=>c.label).join(', ')}.`,
                    `La mejor diferencia mensual fue ${datos.mesMejorDif?.mes||'—'} ($${fmt(datos.mesMejorDif?.diferencia||0)}) y la peor fue ${datos.mesPeorDif?.mes||'—'} ($${fmt(datos.mesPeorDif?.diferencia||0)}).`,
                    `Hubo ${datos.mesesPositivo} mes${datos.mesesPositivo!==1?'es':''} con saldo final positivo y ${datos.periodos.length-datos.mesesPositivo} con saldo negativo.`,
                    `Mayor concentración de gasto: ${datos.topCats[0]?.label||'—'} ($${fmt(datos.topCats[0]?.total||0)}, ${datos.topCats[0]?.pct||0}%).`,
                  ].map((t,i)=>(
                    <div key={i} style={{display:'flex',gap:6,alignItems:'flex-start',padding:'6px 8px',background:'#fff',borderRadius:6,border:'1px solid #e5e7eb'}}>
                      <span style={{color:AZ,flexShrink:0,marginTop:1}}>•</span>
                      <span style={{lineHeight:1.5}}>{t}</span>
                    </div>
                  ))}
                </div>
              </Card>

              {/* Tablas analíticas en 3 columnas */}
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:16}}>

                {/* Resumen egresos por categoría */}
                <Card style={{padding:0,overflow:'hidden'}}>
                  <div style={{background:AZ,color:'#fff',padding:'8px 12px',fontWeight:700,fontSize:11}}>
                    Top categorías de egresos
                  </div>
                  <table style={{width:'100%',borderCollapse:'collapse'}}>
                    <thead>
                      <tr style={{background:'#f8fafc'}}>
                        <th style={{padding:'6px 10px',textAlign:'left',fontSize:9,fontWeight:600,color:GR}}>Categoría</th>
                        <th style={{padding:'6px 8px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>Total</th>
                        <th style={{padding:'6px 8px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>%</th>
                      </tr>
                    </thead>
                    <tbody>
                      {datos.topCats.map((c,i)=>(
                        <tr key={i} style={{borderBottom:'1px solid #f3f4f6'}}>
                          <td style={{padding:'5px 10px',fontSize:10}}>{c.label}</td>
                          <td style={{padding:'5px 8px',textAlign:'right',fontSize:10,fontWeight:600}}>${fmt(c.total)}</td>
                          <td style={{padding:'5px 8px',textAlign:'right',fontSize:10,color:'#4338ca'}}>{c.pct}%</td>
                        </tr>
                      ))}
                      <tr style={{background:'#f0f4ff',fontWeight:700}}>
                        <td style={{padding:'6px 10px',fontSize:10}}>TOTAL</td>
                        <td style={{padding:'6px 8px',textAlign:'right',fontSize:10}}>${fmt(datos.totalAnual)}</td>
                        <td style={{padding:'6px 8px',textAlign:'right',fontSize:10}}>100%</td>
                      </tr>
                    </tbody>
                  </table>
                </Card>

                {/* Evolución mensual ingresos vs egresos */}
                <Card style={{padding:0,overflow:'hidden'}}>
                  <div style={{background:AZ,color:'#fff',padding:'8px 12px',fontWeight:700,fontSize:11}}>
                    Ingresos vs Egresos por mes
                  </div>
                  <div style={{overflowY:'auto',maxHeight:320}}>
                    <table style={{width:'100%',borderCollapse:'collapse'}}>
                      <thead>
                        <tr style={{background:'#f8fafc'}}>
                          <th style={{padding:'6px 8px',textAlign:'left',fontSize:9,fontWeight:600,color:GR}}>Mes</th>
                          <th style={{padding:'6px 6px',textAlign:'right',fontSize:9,fontWeight:600,color:VD}}>Ingresos</th>
                          <th style={{padding:'6px 6px',textAlign:'right',fontSize:9,fontWeight:600,color:RJ}}>Egresos</th>
                          <th style={{padding:'6px 6px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>Dif.</th>
                        </tr>
                      </thead>
                      <tbody>
                        {datos.evolucion.map((e,i)=>(
                          <tr key={i} style={{borderBottom:'1px solid #f3f4f6'}}>
                            <td style={{padding:'4px 8px',fontSize:10}}>{e.mes}</td>
                            <td style={{padding:'4px 6px',textAlign:'right',fontSize:9,color:VD}}>${fmt(e.ingresos)}</td>
                            <td style={{padding:'4px 6px',textAlign:'right',fontSize:9,color:RJ}}>${fmt(e.egresos)}</td>
                            <td style={{padding:'4px 6px',textAlign:'right',fontSize:9,color:e.diferencia>=0?VD:RJ,fontWeight:600}}>
                              {e.diferencia>=0?'+':''}{fmtS(e.diferencia)}
                            </td>
                          </tr>
                        ))}
                        <tr style={{background:'#f0f4ff',fontWeight:700}}>
                          <td style={{padding:'5px 8px',fontSize:10}}>TOTAL</td>
                          <td style={{padding:'5px 6px',textAlign:'right',fontSize:10,color:VD}}>${fmt(datos.totalIngresos)}</td>
                          <td style={{padding:'5px 6px',textAlign:'right',fontSize:10,color:RJ}}>${fmt(datos.totalAnual)}</td>
                          <td style={{padding:'5px 6px',textAlign:'right',fontSize:10,color:datos.resultadoNeto>=0?VD:RJ,fontWeight:700}}>
                            {datos.resultadoNeto>=0?'+':''}{fmtS(datos.resultadoNeto)}
                          </td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                </Card>

                {/* Evolución del saldo final */}
                <Card style={{padding:0,overflow:'hidden'}}>
                  <div style={{background:AZ,color:'#fff',padding:'8px 12px',fontWeight:700,fontSize:11}}>
                    Evolución del saldo final
                  </div>
                  <div style={{overflowY:'auto',maxHeight:320}}>
                    <table style={{width:'100%',borderCollapse:'collapse'}}>
                      <thead>
                        <tr style={{background:'#f8fafc'}}>
                          <th style={{padding:'6px 10px',textAlign:'left',fontSize:9,fontWeight:600,color:GR}}>Mes</th>
                          <th style={{padding:'6px 10px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>Saldo final</th>
                        </tr>
                      </thead>
                      <tbody>
                        {datos.evolucion.map((e,i)=>(
                          <tr key={i} style={{borderBottom:'1px solid #f3f4f6',background:e.saldo<0?'#fff5f5':'#fff'}}>
                            <td style={{padding:'5px 10px',fontSize:10}}>{e.mes}</td>
                            <td style={{padding:'5px 10px',textAlign:'right',fontSize:10,fontWeight:700,color:e.saldo<0?RJ:VD}}>
                              {e.saldo!==0?(e.saldo>0?'+':'')+fmtS(e.saldo):'—'}
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </Card>
              </div>

              {/* Detalle del bloque mayor */}
              {datos.detalleTopCat.length > 0 && (
                <Card style={{padding:0,overflow:'hidden',marginBottom:16}}>
                  <div style={{background:'#0f2d7a',color:'#fff',padding:'8px 14px',fontWeight:700,fontSize:11}}>
                    Detalle de {datos.topCatLabel} — mayor concentración de gasto
                  </div>
                  <table style={{width:'100%',borderCollapse:'collapse'}}>
                    <thead>
                      <tr style={{background:'#f8fafc'}}>
                        <th style={{padding:'7px 14px',textAlign:'left',fontSize:9,fontWeight:600,color:GR}}>Concepto</th>
                        <th style={{padding:'7px 12px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>Total anual</th>
                        <th style={{padding:'7px 12px',textAlign:'right',fontSize:9,fontWeight:600,color:GR}}>% del total</th>
                      </tr>
                    </thead>
                    <tbody>
                      {datos.detalleTopCat.map((d,i)=>(
                        <tr key={i} style={{borderBottom:'1px solid #f3f4f6'}}>
                          <td style={{padding:'6px 14px',fontSize:11}}>{d.concepto}</td>
                          <td style={{padding:'6px 12px',textAlign:'right',fontSize:11,fontWeight:600}}>${fmt(d.total)}</td>
                          <td style={{padding:'6px 12px',textAlign:'right',fontSize:11,color:'#4338ca'}}>{d.pct}%</td>
                        </tr>
                      ))}
                      <tr style={{background:'#e0e7ff',fontWeight:700}}>
                        <td style={{padding:'7px 14px',fontSize:11}}>TOTAL {datos.topCatLabel}</td>
                        <td style={{padding:'7px 12px',textAlign:'right',fontSize:11}}>${fmt(datos.topCatTotal)}</td>
                        <td style={{padding:'7px 12px',textAlign:'right',fontSize:11}}>100%</td>
                      </tr>
                    </tbody>
                  </table>
                </Card>
              )}

              {/* ── GRÁFICOS SVG NATIVOS ── función separada, sin IIFE ── */}
              {GraficosBalance(datos)}


              {/* Indicadores clave — 6 KPIs en grilla */}
              <Card style={{background:'#f8fafc',border:'1px solid #e2e8f0'}}>
                <div style={{fontWeight:700,fontSize:13,marginBottom:12,color:AZ}}>📊 Indicadores clave</div>
                <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:10}}>
                  {[
                    {l:'Total Ingresos Anual',  v:'$'+fmt(datos.totalIngresos),  c:VD},
                    {l:'Total Egresos Anual',   v:'$'+fmt(datos.totalAnual),      c:RJ},
                    {l:'Resultado Neto',        v:(datos.resultadoNeto>=0?'+':'')+fmtS(datos.resultadoNeto), c:datos.resultadoNeto>=0?VD:RJ},
                    {l:'Prom. Mensual Ingresos',v:'$'+fmt(datos.promedioIngresos), c:AZ},
                    {l:'Prom. Mensual Egresos', v:'$'+fmt(datos.promedioEgresos),  c:AZ},
                    {l:'Saldo Final',           v:fmtS(datos.saldoFinalPorPeriodo[datos.periodos[datos.periodos.length-1]]||0), c:((datos.saldoFinalPorPeriodo[datos.periodos[datos.periodos.length-1]]||0)>=0?VD:RJ)},
                  ].map((k,i)=>(
                    <div key={i} style={{textAlign:'center',padding:'10px 8px',background:'#fff',borderRadius:8,border:'1px solid #e5e7eb'}}>
                      <div style={{fontSize:10,color:GR,textTransform:'uppercase',fontWeight:600,marginBottom:4,lineHeight:1.3}}>{k.l}</div>
                      <div style={{fontSize:15,fontWeight:800,color:k.c}}>{k.v}</div>
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          )}
        </>
      )}
    </div>
  )
}



// ESTADO FINANCIERO GENERAL
// ══════════════════════════════════════════════════════════════════════════════
function EstadoFinanciero({ session, consorcioId, consorcioActivo }) {
  const [datos, setDatos]       = useState(null)
  const [cargando, setCargando] = useState(true)
  const [desde, setDesde]       = useState(() => {
    const d = new Date(); d.setMonth(d.getMonth()-3); return d.toISOString().split('T')[0]
  })
  const [hasta, setHasta]       = useState(new Date().toISOString().split('T')[0])

  async function cargar() {
    setCargando(true)
    const [
      { data: detalles },
      { data: cobranzas },
      { data: gastos },
      { data: pagosProv },
      { data: movUnidad },
      { data: compPend },
      { data: expensasCerradas },
    ] = await Promise.all([
      supabase.from('con_expensas_detalle').select('monto,saldo_anterior,interes_mora,pagos_periodo,estado')
        .eq('consorcio_id', consorcioId),
      supabase.from('con_cobranzas').select('monto,fecha,medio_pago')
        .eq('consorcio_id', consorcioId).in('estado',['vigente','acreditado','cobrado'])
        .gte('fecha', desde).lte('fecha', hasta),
      supabase.from('con_gastos').select('monto,categoria,fecha')
        .eq('consorcio_id', consorcioId)
        .gte('fecha', desde).lte('fecha', hasta),
      supabase.from('con_pagos_proveedor').select('monto,fecha')
        .eq('consorcio_id', consorcioId)
        .gte('fecha', desde).lte('fecha', hasta),
      supabase.from('con_movimientos_unidad').select('monto,tipo')
        .eq('consorcio_id', consorcioId).eq('estado','vigente'),
      supabase.from('con_comprobantes_proveedor').select('saldo_pendiente')
        .eq('consorcio_id', consorcioId).in('estado',['pendiente','pagado_parcial']),
      // Últimas expensas cerradas para mostrar saldos reales migrados
      supabase.from('con_expensas').select('periodo,saldo_caja_final,total_cobrado,total_gastos,total_expensa')
        .eq('consorcio_id', consorcioId).in('estado',['cerrado','cerrada'])
        .order('periodo', { ascending: false }).limit(13),
    ])

    // Deudores — saldo pendiente según la última expensa abierta
    // Se toma de con_expensas_detalle filtrado a la expensa abierta actual
    // Si no hay expensa abierta, se toma la última cerrada
    // Fórmula por UF: MAX(0, saldo_anterior + monto + interes - pagos)
    // Deudores: usar el estado del detalle como fuente de verdad
    // 'pagada' = sin deuda | 'parcial' = debe parte | 'pendiente' = debe todo
    const deudores = (detalles||[]).reduce((a,d) => {
      if (d.estado === 'pagada') return a  // Sin deuda
      if (d.estado === 'pendiente') return a + (parseFloat(d.monto)||0) + (parseFloat(d.interes_mora)||0)
      // parcial: debe la diferencia
      const pagado = parseFloat(d.pagos_periodo)||0
      const cargo  = (parseFloat(d.monto)||0) + (parseFloat(d.interes_mora)||0)
      return a + Math.max(0, cargo - pagado)
    }, 0)

    // Acreedores (facturas pendientes de pagar a proveedores)
    const acreedores = (compPend||[]).reduce((a,c) => a + (parseFloat(c.saldo_pendiente)||0), 0)

    // Ingresos del período (cobranzas operativas registradas)
    const ingresos = (cobranzas||[]).reduce((a,c) => a + (parseFloat(c.monto)||0), 0)

    // Egresos del período
    // NOTA: con_gastos ya incluye todos los gastos del consorcio (honorarios, servicios, etc.)
    // con_pagos_proveedor son pagos efectivos a proveedores — pueden solaparse con gastos
    // Para evitar doble conteo, el egreso del período = solo gastos del consorcio
    const egresosGastos   = (gastos||[]).reduce((a,g) => a + (parseFloat(g.monto)||0), 0)
    const egresosPagProv  = (pagosProv||[]).reduce((a,p) => a + (parseFloat(p.monto)||0), 0)
    // Egresos = gastos del consorcio (la fuente más confiable para el período)
    const egresos = egresosGastos

    // Resultado del período = Ingresos cobrados - Gastos ejecutados
    const resultado = ingresos - egresos

    // Ingresos por medio de pago
    const porMedio = {}
    for (const c of (cobranzas||[])) {
      const m = c.medio_pago || 'otros'
      porMedio[m] = (porMedio[m]||0) + (parseFloat(c.monto)||0)
    }

    // Última expensa cerrada con saldo real (datos migrados del PDF)
    const ultimaExpensa = (expensasCerradas||[])[0] || null
    const saldoCajaUltimo = ultimaExpensa ? parseFloat(ultimaExpensa.saldo_caja_final)||0 : null
    const cobradoUltimo   = ultimaExpensa ? parseFloat(ultimaExpensa.total_cobrado)||0   : null
    const gastosUltimo    = ultimaExpensa ? parseFloat(ultimaExpensa.total_gastos)||0    : null

    setDatos({ deudores, acreedores, ingresos, egresos, egresosGastos,
      egresosPagProv, resultado, porMedio,
      expensasCerradas: expensasCerradas||[],
      ultimaExpensa, saldoCajaUltimo, cobradoUltimo, gastosUltimo })
    setCargando(false)
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId, desde, hasta])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2 })
  const MEDIOS_LABEL = {
    transferencia:'Transferencia', efectivo:'Efectivo',
    cheque_propio:'Cheque propio', cheque_tercero:'Cheque de tercero', otros:'Otros'
  }

  async function exportarEFPDF() {
    if (!datos) return
    exportarPDF({
      titulo: 'Estado Financiero',
      subtitulo: (consorcioActivo?.nombre||'') + '  |  Período: ' + desde + ' al ' + hasta,
      logoB64: LOGO_ADM_B64,
      columnas: [{key:'concepto',label:'Concepto'},{key:'importe',label:'Importe'}],
      filas: [
        {concepto:'Deudores (a cobrar)', importe:'$'+(Number(datos.deudores)||0).toLocaleString('es-AR',{minimumFractionDigits:2})},
        {concepto:'Acreedores (a pagar)', importe:'$'+(Number(datos.acreedores)||0).toLocaleString('es-AR',{minimumFractionDigits:2})},
        {concepto:'─── INGRESOS DEL PERÍODO ───', importe:''},
        {concepto:'  Cobrado en período', importe:'$'+(Number(datos.ingresos)||0).toLocaleString('es-AR',{minimumFractionDigits:2})},
        {concepto:'─── EGRESOS DEL PERÍODO ───', importe:''},
        {concepto:'  Gastos del consorcio', importe:'$'+(Number(datos.egresosGastos)||0).toLocaleString('es-AR',{minimumFractionDigits:2})},
        {concepto:'  TOTAL EGRESOS', importe:'$'+(Number(datos.egresos)||0).toLocaleString('es-AR',{minimumFractionDigits:2})},
        {concepto:'RESULTADO NETO', importe:(datos.resultado>=0?'+':'')+('$'+(Number(datos.resultado)||0).toLocaleString('es-AR',{minimumFractionDigits:2}))},
      ],
    })
  }

  async function exportarEFExcel() {
    if (!datos) return
    if (!window.XLSX) await new Promise((res,rej)=>{const s=document.createElement('script');s.src='https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js';s.onload=res;s.onerror=rej;document.head.appendChild(s)})
    const XLSX = window.XLSX
    const fmt = n => Number(n)||0
    const rows = [
      ['Estado Financiero — ' + (consorcioActivo?.nombre||'')],
      ['Período: ' + desde + ' al ' + hasta],
      [],
      ['Concepto','Importe'],
      ['Deudores (a cobrar)', fmt(datos.deudores)],
      ['Acreedores (a pagar)', fmt(datos.acreedores)],
      [],['INGRESOS'],
      ['Cobrado en período', fmt(datos.ingresos)],
      [],['EGRESOS'],
      ['Gastos del consorcio', fmt(datos.egresosGastos)],
      ['Total egresos', fmt(datos.egresos)],
      [],
      ['RESULTADO NETO', fmt(datos.resultado)],
      [],
      ['HISTORIAL LIQUIDACIONES','','',''],
      ['Período','Total gastos','Total cobrado','Saldo final'],
      ...(datos.expensasCerradas||[]).map(e=>[e.periodo,fmt(e.total_gastos),fmt(e.total_cobrado),fmt(e.saldo_caja_final)]),
    ]
    XLSX.utils.book_append_sheet(XLSX.utils.book_new(), XLSX.utils.aoa_to_sheet(rows), 'Estado Financiero')
    const wb = XLSX.utils.book_new()
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(rows), 'Estado Financiero')
    XLSX.writeFile(wb, `EstadoFinanciero_${consorcioActivo?.id||'cons'}_${hasta}.xlsx`)
  }

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>🏦 Estado financiero</div>
        {datos && (
          <div style={{ display:'flex', gap:8 }}>
            <Btn small color={GR} onClick={exportarEFPDF}>🖨️ PDF</Btn>
            <Btn small color={VD} onClick={exportarEFExcel}>📊 Excel</Btn>
          </div>
        )}
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Posición financiera general de {consorcioActivo?.nombre}
      </div>

      {/* Filtro período */}
      <Card style={{ marginBottom:16 }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Desde</div>
            <input type="date" value={desde} onChange={e=>setDesde(e.target.value)}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Hasta</div>
            <input type="date" value={hasta} onChange={e=>setHasta(e.target.value)}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
          </div>
        </div>
      </Card>

      {cargando ? (
        <div style={{ textAlign:'center', padding:32, color:GR }}>⏳ Calculando...</div>
      ) : datos && (
        <>
          {/* Posición patrimonial */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:16 }}>
            <div style={{ background:'#eff6ff', borderRadius:10, padding:'20px', border:'1px solid #bfdbfe' }}>
              <div style={{ fontSize:12, fontWeight:600, color:AZ, textTransform:'uppercase', marginBottom:8 }}>
                📥 Deudores (a cobrar)
              </div>
              <div style={{ fontSize:28, fontWeight:800, color:AZ }}>{fmt(datos.deudores)}</div>
              <div style={{ fontSize:11, color:GR, marginTop:4 }}>
                Expensas pendientes de cobro a propietarios
              </div>
            </div>
            <div style={{ background:'#fff1f2', borderRadius:10, padding:'20px', border:'1px solid #fecdd3' }}>
              <div style={{ fontSize:12, fontWeight:600, color:RJ, textTransform:'uppercase', marginBottom:8 }}>
                📤 Acreedores (a pagar)
              </div>
              <div style={{ fontSize:28, fontWeight:800, color:RJ }}>{fmt(datos.acreedores)}</div>
              <div style={{ fontSize:11, color:GR, marginTop:4 }}>
                Facturas de proveedores pendientes de pago
              </div>
            </div>
          </div>

          {/* Resultado del período */}
          <Card style={{ marginBottom:16, background: datos.resultado>=0?'#f0fdf4':'#fff1f2',
            border:`1.5px solid ${datos.resultado>=0?'#86efac':'#fca5a5'}` }}>
            <div style={{ fontWeight:600, fontSize:13, color: datos.resultado>=0?VD:RJ, marginBottom:14 }}>
              Resultado del período seleccionado
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12 }}>
              {[
                { l:'Ingresos (cobrado)', v:fmt(datos.ingresos), c:VD },
                { l:'Egresos (pagado)',   v:fmt(datos.egresos),  c:RJ },
                { l:'Resultado neto',     v:`${datos.resultado>=0?'+':''}${fmt(datos.resultado)}`, c:datos.resultado>=0?VD:RJ },
              ].map((k,i) => (
                <div key={i} style={{ textAlign:'center', padding:'12px', background:'#fff',
                  borderRadius:8, boxShadow:'0 1px 4px #0001' }}>
                  <div style={{ fontSize:11, color:GR, fontWeight:600, textTransform:'uppercase', marginBottom:6 }}>{k.l}</div>
                  <div style={{ fontSize:20, fontWeight:800, color:k.c }}>{k.v}</div>
                </div>
              ))}
            </div>
          </Card>

          {/* Detalle egresos */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:16 }}>
            <Card>
              <div style={{ fontWeight:600, fontSize:13, color:AZ, marginBottom:10 }}>Detalle egresos</div>
              <div style={{ display:'flex', justifyContent:'space-between',
                padding:'8px 0', borderBottom:'1px solid #f3f4f6' }}>
                <span style={{ fontSize:13 }}>Gastos del consorcio</span>
                <span style={{ fontWeight:700, color:RJ }}>{fmt(datos.egresosGastos)}</span>
              </div>
              {datos.egresosPagProv > 0 && (
                <div style={{ display:'flex', justifyContent:'space-between',
                  padding:'4px 0', borderBottom:'1px solid #f3f4f6' }}>
                  <span style={{ fontSize:11, color:GR, fontStyle:'italic' }}>
                    Pagos a proveedores (informativo)
                  </span>
                  <span style={{ fontSize:11, color:GR }}>{fmt(datos.egresosPagProv)}</span>
                </div>
              )}
              <div style={{ display:'flex', justifyContent:'space-between', padding:'8px 0',
                borderTop:'2px solid #1A3FA0', marginTop:4 }}>
                <span style={{ fontWeight:700, fontSize:13 }}>Total</span>
                <span style={{ fontWeight:800, color:RJ }}>{fmt(datos.egresos)}</span>
              </div>
            </Card>

            <Card>
              <div style={{ fontWeight:600, fontSize:13, color:AZ, marginBottom:10 }}>Ingresos por medio</div>
              {Object.entries(datos.porMedio).length === 0 ? (
                <div style={{ color:GR, fontSize:12, padding:'8px 0' }}>Sin cobranzas en el período</div>
              ) : Object.entries(datos.porMedio).map(([m,v],i) => (
                <div key={i} style={{ display:'flex', justifyContent:'space-between',
                  padding:'8px 0', borderBottom:'1px solid #f3f4f6' }}>
                  <span style={{ fontSize:13 }}>{MEDIOS_LABEL[m]||m}</span>
                  <span style={{ fontWeight:700, color:VD }}>{fmt(v)}</span>
                </div>
              ))}
            </Card>
          </div>

          {/* Historial de liquidaciones cerradas (datos migrados de PDFs) */}
          {(datos.expensasCerradas||[]).length > 0 && (
            <Card style={{ marginBottom:16 }}>
              <div style={{ fontWeight:600, fontSize:13, color:AZ, marginBottom:10 }}>
                📋 Historial de liquidaciones cerradas
              </div>
              <div style={{ fontSize:11, color:GR, marginBottom:10 }}>
                Saldos finales reales según liquidaciones Abril 2026 (datos migrados de PDFs)
              </div>
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                  <thead>
                    <tr style={{ background:'#f3f4f6' }}>
                      <th style={{ padding:'6px 10px', textAlign:'left', fontWeight:600 }}>Período</th>
                      <th style={{ padding:'6px 10px', textAlign:'right', fontWeight:600 }}>Total gastos</th>
                      <th style={{ padding:'6px 10px', textAlign:'right', fontWeight:600 }}>Total cobrado</th>
                      <th style={{ padding:'6px 10px', textAlign:'right', fontWeight:600 }}>Saldo final</th>
                    </tr>
                  </thead>
                  <tbody>
                    {(datos.expensasCerradas||[]).map((e,i) => {
                      const sf = parseFloat(e.saldo_caja_final)||0
                      return (
                        <tr key={i} style={{ borderBottom:'1px solid #f3f4f6' }}>
                          <td style={{ padding:'6px 10px', fontWeight:600 }}>{e.periodo}</td>
                          <td style={{ padding:'6px 10px', textAlign:'right', color:RJ }}>
                            {e.total_gastos > 0 ? fmt(e.total_gastos) : '—'}
                          </td>
                          <td style={{ padding:'6px 10px', textAlign:'right', color:VD }}>
                            {e.total_cobrado > 0 ? fmt(e.total_cobrado) : '—'}
                          </td>
                          <td style={{ padding:'6px 10px', textAlign:'right',
                            fontWeight:800, color: sf >= 0 ? VD : RJ }}>
                            {sf !== 0 ? (sf > 0 ? '+' : '') + fmt(sf) : '—'}
                          </td>
                        </tr>
                      )
                    })}
                  </tbody>
                </table>
              </div>
              {datos.ultimaExpensa && datos.saldoCajaUltimo !== null && (
                <div style={{ marginTop:10, padding:'10px 12px', borderRadius:8,
                  background: datos.saldoCajaUltimo >= 0 ? '#f0fdf4' : '#fff1f2',
                  border: '1px solid ' + (datos.saldoCajaUltimo >= 0 ? '#86efac' : '#fca5a5') }}>
                  <span style={{ fontSize:12, fontWeight:600,
                    color: datos.saldoCajaUltimo >= 0 ? VD : RJ }}>
                    💰 Saldo arrastrado a Mayo 2026: {datos.saldoCajaUltimo > 0 ? '+' : ''}{fmt(datos.saldoCajaUltimo)}
                  </span>
                  <span style={{ fontSize:11, color:GR, marginLeft:8 }}>
                    (saldo final Abril 2026 según liquidación)
                  </span>
                </div>
              )}
            </Card>
          )}
        </>
      )}
    </div>
  )
}


// ══════════════════════════════════════════════════════════════════════════════
// SUELDOS — Gestión de empleados y liquidación de sueldos
// Carga manual + lectura IA de recibo PDF
// Imputación automática a con_gastos (Rubro 2: SUELDOS Y CARGAS SOCIALES)
// Referencia: CCT 589/10 FATERYH · Punta Médanos como ejemplo
// ══════════════════════════════════════════════════════════════════════════════
function Sueldos({ session, consorcioId, consorcioActivo, expensas }) {
  const [tab, setTab]           = useState('liquidar')
  const [empleados, setEmpleados] = useState([])
  const [sueldos, setSueldos]   = useState([])
  const [expSel, setExpSel]     = useState('')
  const [msg, setMsg]           = useState(null)
  const [procesando, setProcesando] = useState(false)

  // ── Estado formulario empleado ──────────────────────────────────────
  const [formEmp, setFormEmp]   = useState(null)

  // ── Estado liquidación ──────────────────────────────────────────────
  const [filas, setFilas]       = useState([])   // array de liquidaciones del período
  const [fateryh, setFateryh]   = useState('')   // monto total FATERYH
  const [vep931, setVep931]     = useState('')   // monto total VEP 931
  const [filaTipo, setFilaTipo] = useState('mensual')

  // ── Estado IA ───────────────────────────────────────────────────────
  const [leyendoIA, setLeyendoIA] = useState(false)
  const [archivoIA, setArchivoIA] = useState(null)
  // input de archivo — se accede por ID directo sin useRef

  const hoy = new Date().toISOString().split('T')[0]
  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2 })
  // parseMto: soporta tanto formato argentino "1.234,56" como numérico "1234.56"
  // Los inputs type=number del browser envían punto decimal estándar (no formato argentino)
  const parseMto = s => {
    const str = String(s || '0').trim()
    if (!str || str === '') return 0
    // Si tiene coma → formato argentino: quitar puntos de miles, coma → punto decimal
    if (str.includes(',')) return parseFloat(str.replace(/\./g, '').replace(',', '.')) || 0
    // Si solo tiene punto → formato numérico estándar (input type=number)
    return parseFloat(str) || 0
  }

  const COLUMNAS = [
    { v:'GENERAL',   l:'General' },
    { v:'LOCALES',   l:'Locales' },
    { v:'DEPTOS',    l:'Deptos' },
    { v:'COCHERAS',  l:'Cocheras' },
    { v:'FDO_OBRAS', l:'Fdo. Obras' },
  ]
  const TIPOS_LIQ = [
    { v:'mensual',    l:'Sueldo mensual' },
    { v:'final',      l:'Liquidación final (alta/baja)' },
    { v:'reemplazo',  l:'Reemplazo / guardia' },
    { v:'adicional',  l:'Pago adicional' },
  ]
  const CATEGORIAS_EMP = [
    { v:'encargado_permanente', l:'Encargado permanente' },
    { v:'encargado_suplente',   l:'Encargado suplente' },
    { v:'auxiliar',             l:'Auxiliar' },
    { v:'otro',                 l:'Otro' },
  ]

  const periodoLabel = p => {
    if (!p) return '—'
    const [y,m] = p.split('-')
    const meses=['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
    return m ? `${meses[parseInt(m)-1]} ${y}` : p
  }

  // ── Cargar datos ────────────────────────────────────────────────────
  async function cargarEmpleados() {
    const { data } = await supabase.from('con_empleados').select('*')
      .eq('admin_id', session.user.id).eq('consorcio_id', consorcioId)
      .order('apellido_nombre')
    setEmpleados(data || [])
  }
  async function cargarSueldos() {
    const { data } = await supabase.from('con_sueldos').select('*')
      .eq('admin_id', session.user.id).eq('consorcio_id', consorcioId)
      .order('periodo', { ascending:false }).order('apellido_nombre')
    setSueldos(data || [])
  }
  useEffect(() => {
    if (consorcioId) { cargarEmpleados(); cargarSueldos() }
  }, [consorcioId])

  // ── Inicializar filas del período a liquidar ─────────────────────────
  useEffect(() => {
    if (tab === 'liquidar' && empleados.length > 0) {
      setFilas(empleados.filter(e => e.activo).map(e => ({
        empleado_id:         e.id,
        apellido_nombre:     e.apellido_nombre,
        categoria:           e.categoria,
        tipo_liquidacion:    'mensual',
        es_liquidacion_final: false,
        sueldo_basico:       '',
        adicionales:         '',
        aportes_empleado:    '',
        sueldo_neto:         '',
        columna:             'GENERAL',
        incluir:             true,
      })))
    }
  }, [tab, empleados.length, consorcioId])

  // ── Agregar fila manual (sin empleado registrado) ───────────────────
  function agregarFilaManual() {
    setFilas(prev => [...prev, {
      empleado_id:         null,
      apellido_nombre:     '',
      categoria:           '',
      tipo_liquidacion:    'mensual',
      es_liquidacion_final: false,
      sueldo_basico:       '',
      adicionales:         '',
      aportes_empleado:    '',
      sueldo_neto:         '',
      columna:             'GENERAL',
      incluir:             true,
      _manual:             true,
    }])
  }
  function actualizarFila(idx, campo, valor) {
    setFilas(prev => prev.map((f, i) => {
      if (i !== idx) return f
      const upd = { ...f, [campo]: valor }
      // Calcular neto automático si se cambia básico/adicionales/aportes
      if (['sueldo_basico','adicionales','aportes_empleado'].includes(campo)) {
        const bas = parseMto(campo==='sueldo_basico'?valor:upd.sueldo_basico)
        const adi = parseMto(campo==='adicionales'?valor:upd.adicionales)
        const apo = parseMto(campo==='aportes_empleado'?valor:upd.aportes_empleado)
        upd.sueldo_neto = String((bas + adi - apo || 0).toFixed(2))
      }
      return upd
    }))
  }

  // ── Lectura IA de recibo PDF (via Edge Function — evita CORS) ───────────
  async function leerReciboConIA(file, tipoDoc = 'recibo_sueldo') {
    if (!file) return
    setLeyendoIA(true); setMsg(null)
    try {
      // Convertir PDF a base64
      const b64 = await new Promise((res, rej) => {
        const r = new FileReader()
        r.onload = () => res(r.result.split(',')[1])
        r.onerror = rej
        r.readAsDataURL(file)
      })

      // Llamar a la Edge Function (servidor Supabase) — sin problema de CORS
      const { data: { session: sess } } = await supabase.auth.getSession()
      const response = await fetch(`${SUPA_URL}/functions/v1/leer-recibo-sueldo`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${sess?.access_token}`,
          'apikey': process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
        },
        body: JSON.stringify({
          base64:        b64,
          nombre_archivo: file.name,
          tipo:          tipoDoc,  // 'recibo_sueldo' | 'fateryh' | 'vep931'
        })
      })

      const result = await response.json()
      if (!response.ok || result.error) {
        throw new Error(result.error || `Error del servidor: ${response.status}`)
      }

      const parsed = result.datos || {}

      // Si leyó FATERYH → completar campo fateryh directamente
      if (tipoDoc === 'fateryh') {
        if (parsed.total_a_pagar) setFateryh(String(parsed.total_a_pagar))
        setMsg({ tipo:'ok', texto:`✓ FATERYH leído: Total ${parsed.total_a_pagar ? '$' + Number(parsed.total_a_pagar).toLocaleString('es-AR') : '—'} · Período ${parsed.periodo || '—'} · ${parsed.cantidad_trabajadores || '?'} trabajadores` })
        setLeyendoIA(false)
        return
      }

      // Si leyó VEP 931 → completar campo vep931 directamente
      if (tipoDoc === 'vep931') {
        if (parsed.total_a_pagar) setVep931(String(parsed.total_a_pagar))
        setMsg({ tipo:'ok', texto:`✓ VEP F.931 leído: Total ${parsed.total_a_pagar ? '$' + Number(parsed.total_a_pagar).toLocaleString('es-AR') : '—'} · Período ${parsed.periodo || '—'} · ${parsed.cantidad_empleados || '?'} empleados` })
        setLeyendoIA(false)
        return
      }

      // Recibo de sueldo — crear nueva fila
      const nuevaFila = {
        empleado_id:          null,
        apellido_nombre:      parsed.apellido_nombre || '',
        categoria:            '',
        tipo_liquidacion:     parsed.tipo_liquidacion || 'mensual',
        es_liquidacion_final: parsed.es_liquidacion_final || false,
        sueldo_basico:        parsed.sueldo_basico || '',
        adicionales:          parsed.adicionales || '',
        aportes_empleado:     parsed.aportes_empleado || '',
        sueldo_neto:          parsed.sueldo_neto || '',
        columna:              parsed.columna || 'GENERAL',
        notas:                parsed.notas || '',
        recibo_pdf_nombre:    file.name,
        incluir:              true,
        _ia:                  true,
      }

      // Avisar si el período del recibo difiere del seleccionado
      if (parsed.periodo && expSel) {
        const expPer = expensas.find(e => e.id === expSel)?.periodo
        if (expPer && parsed.periodo !== expPer) {
          nuevaFila.notas = (nuevaFila.notas ? nuevaFila.notas + ' | ' : '') +
            `⚠ Período recibo: ${parsed.periodo}`
        }
      }

      // Buscar empleado coincidente por apellido
      const primerApellido = (parsed.apellido_nombre || '').split(' ')[0]?.toUpperCase()
      if (primerApellido && primerApellido.length > 2) {
        const match = empleados.find(e =>
          e.apellido_nombre.toUpperCase().includes(primerApellido)
        )
        if (match) nuevaFila.empleado_id = match.id
      }

      setFilas(prev => [...prev, nuevaFila])
      setMsg({ tipo:'ok', texto:`✓ IA extrajo datos de "${file.name}" — Verificar y ajustar antes de imputar` })
    } catch(e) {
      setMsg({ tipo:'error', texto:'Error al leer PDF con IA: ' + e.message })
    }
    setLeyendoIA(false)
  }

  // ── Imputar sueldos a con_gastos ─────────────────────────────────────
  async function imputarSueldos() {
    if (!expSel) return setMsg({ tipo:'warn', texto:'Seleccioná el período de expensas primero' })
    const filasActivas = filas.filter(f => f.incluir && parseMto(f.sueldo_neto) > 0)
    if (filasActivas.length === 0) return setMsg({ tipo:'warn', texto:'No hay filas con sueldo neto mayor a cero' })
    setProcesando(true); setMsg(null)
    const exp = expensas.find(e => e.id === expSel)
    const periodo = exp?.periodo || ''
    let ok = 0, errores = []

    for (const fila of filasActivas) {
      const neto = parseMto(fila.sueldo_neto)
      const apellido = fila.apellido_nombre.trim()
      const esLiqFinal = fila.es_liquidacion_final || fila.tipo_liquidacion === 'final'
      const tipoDesc = fila.tipo_liquidacion === 'reemplazo'
        ? 'Reemplazo' + (fila.notas ? ' ' + fila.notas : '')
        : esLiqFinal ? 'Sueldo neto' : 'Sueldo neto'
      const concepto = esLiqFinal
        ? `Sueldos, ${apellido}, ${tipoDesc} - ${periodo} Liquidación final`
        : fila.tipo_liquidacion === 'reemplazo'
          ? `Sueldos, ${apellido}, ${tipoDesc} - ${periodo}`
          : `Sueldos, ${apellido}, Sueldo neto - ${periodo}`

      // La columna de prorrateo se incorpora en las notas del gasto
      // (con_gastos no tiene campos de prorrateo — usa concepto + notas)
      const colLabel = { GENERAL:'General', LOCALES:'Locales', DEPTOS:'Deptos',
        COCHERAS:'Cocheras', FDO_OBRAS:'Fdo. Obras' }[fila.columna] || fila.columna

      const idSueldo = `GAS-SLD-${consorcioId}-${Date.now()}-${ok}`
      const { error } = await supabase.from('con_gastos').insert([{
        id:          idSueldo,
        admin_id:    session.user.id,
        consorcio_id: consorcioId,
        expensa_id:  expSel,
        categoria:   'sueldos',
        concepto,
        monto:       neto,
        fecha:       hoy,
        notas:       [fila.notas, `Col: ${colLabel}`].filter(Boolean).join(' | ') || null,
      }])

      if (!error) {
        // Guardar en con_sueldos para historial
        const sueldoId = `SLD-${consorcioId}-${Date.now()}-${ok}`
        await supabase.from('con_sueldos').insert([{
          id: sueldoId,
          admin_id:    session.user.id,
          consorcio_id: consorcioId,
          expensa_id:  expSel,
          empleado_id: fila.empleado_id,
          periodo,
          fecha_pago:  hoy,
          apellido_nombre: apellido,
          categoria:   fila.categoria || null,
          es_liquidacion_final: esLiqFinal,
          tipo_liquidacion: fila.tipo_liquidacion,
          sueldo_basico:   parseMto(fila.sueldo_basico),
          adicionales:     parseMto(fila.adicionales),
          aportes_empleado: parseMto(fila.aportes_empleado),
          sueldo_neto:     neto,
          columna:         fila.columna,
          imputado:        true,
          gasto_id_sueldo: idSueldo,
          recibo_pdf_nombre: fila.recibo_pdf_nombre || null,
          notas:           fila.notas || null,
        }])
        ok++
      } else {
        errores.push(`${apellido}: ${error.message}`)
      }
    }

    // FATERYH
    const montoFateryh = parseMto(fateryh)
    let fateryh_ok = false
    if (montoFateryh > 0) {
      const idFat = `GAS-FAT-${consorcioId}-${Date.now()}`
      const { error: ef } = await supabase.from('con_gastos').insert([{
        id: idFat, admin_id: session.user.id, consorcio_id: consorcioId, expensa_id: expSel,
        categoria: 'fateryh', concepto: 'F.A.T.E.R.Y.H.',
        monto: montoFateryh, fecha: hoy,
      }])
      if (!ef) { ok++; fateryh_ok = true }
      else errores.push(`FATERYH: ${ef.message}`)
    }

    // VEP 931
    const montoVep = parseMto(vep931)
    let vep_ok = false
    if (montoVep > 0) {
      const idVep = `GAS-VEP-${consorcioId}-${Date.now()}`
      const { error: ev } = await supabase.from('con_gastos').insert([{
        id: idVep, admin_id: session.user.id, consorcio_id: consorcioId, expensa_id: expSel,
        categoria: 'vep_931', concepto: 'VEP F.931 — Cargas sociales AFIP',
        monto: montoVep, fecha: hoy,
        notas: 'Aportes + contribuciones seguridad social y obra social',
      }])
      if (!ev) { ok++; vep_ok = true }
      else errores.push(`VEP 931: ${ev.message}`)
    }

    if (errores.length === 0) {
      setMsg({ tipo:'ok', texto:`✓ ${ok} gastos imputados correctamente en Rubro 2 — Expensas ${periodoLabel(periodo)}` })
      cargarSueldos()
    } else {
      setMsg({ tipo:'warn', texto:`${ok} imputados · Errores: ${errores.join(' | ')}` })
    }
    setProcesando(false)
  }

  // ── Guardar empleado ─────────────────────────────────────────────────
  async function guardarEmpleado() {
    if (!formEmp?.apellido_nombre) return setMsg({ tipo:'warn', texto:'El nombre es requerido' })
    const payload = {
      ...formEmp,
      admin_id:     session.user.id,
      consorcio_id: consorcioId,
      id:           formEmp.id || `EMP-${consorcioId}-${Date.now()}`,
      updated_at:   new Date().toISOString(),
    }
    const { error } = await supabase.from('con_empleados').upsert([payload], { onConflict:'id' })
    if (error) return setMsg({ tipo:'error', texto: error.message })
    setMsg({ tipo:'ok', texto:'✓ Empleado guardado' })
    setFormEmp(null)
    cargarEmpleados()
  }

  // ── RENDER ───────────────────────────────────────────────────────────
  const totalNeto   = filas.filter(f=>f.incluir).reduce((a,f)=>a+parseMto(f.sueldo_neto),0)
  const totalRubro2 = totalNeto + parseMto(fateryh) + parseMto(vep931)
  const expActual   = expensas.find(e => e.id === expSel)

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>💼 Sueldos y cargas sociales</div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Rubro 2 — CCT 589/10 FATERYH · Liquidación de empleados del consorcio
      </div>

      {/* Tabs */}
      <div style={{ display:'flex', gap:0, marginBottom:20, borderBottom:'2px solid #e5e7eb' }}>
        {[
          { id:'liquidar',   l:'📝 Liquidar período' },
          { id:'historial',  l:'📋 Historial' },
          { id:'empleados',  l:'👷 Empleados' },
        ].map(t => (
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{ padding:'8px 16px', border:'none',
              borderBottom:tab===t.id?`2px solid ${AZ}`:'2px solid transparent',
              background:'transparent', color:tab===t.id?AZ:GR,
              fontWeight:tab===t.id?700:400, fontSize:13, cursor:'pointer', marginBottom:-2 }}>
            {t.l}
          </button>
        ))}
      </div>

      <Msg data={msg} />

      {/* ── TAB LIQUIDAR ── */}
      {tab === 'liquidar' && (
        <div>
          {/* Selector período */}
          <Card style={{ marginBottom:16 }}>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, alignItems:'end' }}>
              <Sel label="Período de expensas" value={expSel} onChange={setExpSel}
                opts={[{ v:'', l:'— Seleccioná el período —' },
                  ...expensas.map(e => ({ v:e.id, l:`${periodoLabel(e.periodo)} ${e.estado==='abierta'?'✓':'🔒'} ${e.tipo||''}` }))
                ]} />
              <div style={{ padding:'10px 14px', background:'#eff6ff', borderRadius:8, fontSize:12 }}>
                <div style={{ fontWeight:600, color:AZ, marginBottom:2 }}>💡 Flujo de trabajo</div>
                <div style={{ color:'#374151', lineHeight:1.6 }}>
                  1. Cargar sueldos manualmente o con PDF (IA)<br/>
                  2. Completar FATERYH y VEP 931<br/>
                  3. Imputar → se generan gastos en Rubro 2
                </div>
              </div>
            </div>
          </Card>

          {/* Botones de carga */}
          <div style={{ display:'flex', gap:8, marginBottom:14, flexWrap:'wrap' }}>
            <button type="button" onClick={agregarFilaManual} style={{ padding:"6px 14px", background:AZ, color:"#fff", border:"none", borderRadius:7, fontSize:12.5, fontWeight:600, cursor:"pointer" }}>+ Agregar sueldo manual</button>
            <div style={{ display:'flex', gap:6, flexWrap:'wrap' }}>
              {/* Input oculto compartido — el tipo se guarda en el atributo data */}
              <input
                type="file" accept=".pdf,application/pdf"
                onChange={e => {
                  const tipo = e.target.dataset.tipo || 'recibo_sueldo'
                  if (e.target.files[0]) leerReciboConIA(e.target.files[0], tipo)
                  e.target.value = ''
                }}
                style={{ display:'none' }} id="ia-recibo-upload" />
              <button type="button" disabled={leyendoIA}
                onClick={() => { document.getElementById('ia-recibo-upload').dataset.tipo='recibo_sueldo'; document.getElementById('ia-recibo-upload').click() }}
                style={{ padding:'6px 12px', background:'#7c3aed', color:'#fff', border:'none',
                  borderRadius:7, fontSize:12, fontWeight:600, cursor:'pointer', opacity:leyendoIA?0.6:1 }}>
                {leyendoIA ? '⏳ Leyendo...' : '🤖 Recibo sueldo (IA)'}
              </button>
              <button type="button" disabled={leyendoIA}
                onClick={() => { document.getElementById('ia-recibo-upload').dataset.tipo='fateryh'; document.getElementById('ia-recibo-upload').click() }}
                style={{ padding:'6px 12px', background:'#5b21b6', color:'#fff', border:'none',
                  borderRadius:7, fontSize:12, fontWeight:600, cursor:'pointer', opacity:leyendoIA?0.6:1 }}>
                {leyendoIA ? '⏳ Leyendo...' : '🤖 Boleta FATERYH (IA)'}
              </button>
              <button type="button" disabled={leyendoIA}
                onClick={() => { document.getElementById('ia-recibo-upload').dataset.tipo='vep931'; document.getElementById('ia-recibo-upload').click() }}
                style={{ padding:'6px 12px', background:'#0369a1', color:'#fff', border:'none',
                  borderRadius:7, fontSize:12, fontWeight:600, cursor:'pointer', opacity:leyendoIA?0.6:1 }}>
                {leyendoIA ? '⏳ Leyendo...' : '🤖 VEP F.931 (IA)'}
              </button>
            </div>
          </div>

          {/* Tabla de sueldos */}
          {filas.length > 0 && (
            <Card style={{ marginBottom:14, padding:0, overflow:'hidden' }}>
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                  <thead>
                    <tr style={{ background:'#f8fafc', borderBottom:'1.5px solid #e5e7eb' }}>
                      <th style={{ padding:'8px 10px', width:30, textAlign:'center' }}>✓</th>
                      <th style={{ padding:'8px 10px', textAlign:'left', fontWeight:600, color:'#374151', minWidth:160 }}>Empleado</th>
                      <th style={{ padding:'8px 10px', textAlign:'left', fontWeight:600, color:'#374151', minWidth:110 }}>Tipo</th>
                      <th style={{ padding:'8px 10px', textAlign:'right', fontWeight:600, color:'#374151', minWidth:100 }}>Básico</th>
                      <th style={{ padding:'8px 10px', textAlign:'right', fontWeight:600, color:'#374151', minWidth:90 }}>Adicionales</th>
                      <th style={{ padding:'8px 10px', textAlign:'right', fontWeight:600, color:'#374151', minWidth:90 }}>Aportes emp.</th>
                      <th style={{ padding:'8px 10px', textAlign:'right', fontWeight:700, color:AZ, minWidth:105 }}>Neto a imputar</th>
                      <th style={{ padding:'8px 10px', textAlign:'left', fontWeight:600, color:'#374151', minWidth:100 }}>Columna</th>
                      <th style={{ padding:'8px 10px', textAlign:'left', fontWeight:600, color:'#374151', minWidth:80 }}>Notas</th>
                      <th style={{ padding:'8px 10px', width:30 }}></th>
                    </tr>
                  </thead>
                  <tbody>
                    {filas.map((f, i) => (
                      <tr key={i} style={{ borderBottom:'1px solid #f1f5f9',
                        background: f._ia ? '#faf5ff' : f._manual ? '#f0fdf4' : '#fff',
                        opacity: f.incluir ? 1 : 0.45 }}>
                        <td style={{ padding:'6px 10px', textAlign:'center' }}>
                          <input type="checkbox" checked={!!f.incluir}
                            onChange={e => actualizarFila(i,'incluir',e.target.checked)} />
                        </td>
                        <td style={{ padding:'6px 10px' }}>
                          {f._manual || f._ia ? (
                            <input value={f.apellido_nombre}
                              onChange={e => actualizarFila(i,'apellido_nombre',e.target.value)}
                              placeholder="APELLIDO Nombre"
                              style={{ width:'100%', padding:'4px 7px', border:'1px solid #d1d5db',
                                borderRadius:5, fontSize:11.5, boxSizing:'border-box' }} />
                          ) : (
                            <div>
                              <div style={{ fontWeight:600, fontSize:12 }}>{f.apellido_nombre}</div>
                              {f._ia && <span style={{ fontSize:10, color:'#7c3aed', fontWeight:600 }}>IA 🤖</span>}
                            </div>
                          )}
                          {f.es_liquidacion_final && (
                            <div style={{ fontSize:10, color:RJ, fontWeight:600 }}>Liquidación final</div>
                          )}
                        </td>
                        <td style={{ padding:'6px 10px' }}>
                          <select value={f.tipo_liquidacion}
                            onChange={e => {
                              actualizarFila(i,'tipo_liquidacion',e.target.value)
                              if (e.target.value==='final') actualizarFila(i,'es_liquidacion_final',true)
                              else actualizarFila(i,'es_liquidacion_final',false)
                            }}
                            style={{ width:'100%', padding:'4px 5px', border:'1px solid #d1d5db',
                              borderRadius:5, fontSize:11, background:'#fff' }}>
                            {TIPOS_LIQ.map(t => <option key={t.v} value={t.v}>{t.l}</option>)}
                          </select>
                        </td>
                        {['sueldo_basico','adicionales','aportes_empleado'].map(campo => (
                          <td key={campo} style={{ padding:'6px 8px', textAlign:'right' }}>
                            <input type="number" value={f[campo]}
                              onChange={e => actualizarFila(i, campo, e.target.value)}
                              placeholder="0"
                              style={{ width:'92px', padding:'4px 6px', border:'1px solid #d1d5db',
                                borderRadius:5, fontSize:11.5, textAlign:'right', boxSizing:'border-box' }} />
                          </td>
                        ))}
                        <td style={{ padding:'6px 10px', textAlign:'right' }}>
                          <input type="number" value={f.sueldo_neto}
                            onChange={e => actualizarFila(i,'sueldo_neto',e.target.value)}
                            style={{ width:'105px', padding:'4px 7px', border:`1.5px solid ${AZ}`,
                              borderRadius:5, fontSize:12.5, fontWeight:700, textAlign:'right',
                              color:AZ, boxSizing:'border-box' }} />
                        </td>
                        <td style={{ padding:'6px 8px' }}>
                          <select value={f.columna}
                            onChange={e => actualizarFila(i,'columna',e.target.value)}
                            style={{ padding:'4px 5px', border:'1px solid #d1d5db',
                              borderRadius:5, fontSize:11, background:'#fff', width:'100%' }}>
                            {COLUMNAS.map(c => <option key={c.v} value={c.v}>{c.l}</option>)}
                          </select>
                        </td>
                        <td style={{ padding:'6px 8px' }}>
                          <input value={f.notas||''} onChange={e => actualizarFila(i,'notas',e.target.value)}
                            placeholder="opcional"
                            style={{ width:'100%', padding:'4px 6px', border:'1px solid #d1d5db',
                              borderRadius:5, fontSize:11, boxSizing:'border-box' }} />
                        </td>
                        <td style={{ padding:'6px 8px', textAlign:'center' }}>
                          <button onClick={() => setFilas(prev => prev.filter((_,j)=>j!==i))}
                            style={{ background:'none', border:'none', cursor:'pointer',
                              color:RJ, fontSize:14, fontWeight:700 }}>✕</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr style={{ background:'#f0f4ff', borderTop:'1.5px solid #1A3FA0' }}>
                      <td colSpan={6} style={{ padding:'8px 10px', fontWeight:700, color:AZ, fontSize:12 }}>
                        Total sueldos netos
                      </td>
                      <td style={{ padding:'8px 10px', textAlign:'right', fontWeight:800, color:AZ, fontSize:13 }}>
                        {fmt(totalNeto)}
                      </td>
                      <td colSpan={3} />
                    </tr>
                  </tfoot>
                </table>
              </div>
            </Card>
          )}

          {/* FATERYH + VEP 931 */}
          <Card style={{ marginBottom:14 }}>
            <div style={{ fontWeight:600, color:'#374151', fontSize:13, marginBottom:12 }}>
              Cargas adicionales del Rubro 2
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
              <div>
                <div style={{ fontSize:12, fontWeight:600, color:GR, marginBottom:4 }}>
                  F.A.T.E.R.Y.H. — Boleta sindical
                </div>
                <input type="number" value={fateryh}
                  onChange={e => setFateryh(e.target.value)}
                  placeholder="0.00"
                  style={{ width:'100%', padding:'9px 11px', border:'1px solid #d1d5db',
                    borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
                <div style={{ fontSize:10.5, color:GR, marginTop:3 }}>
                  Total boleta FATERYH (FMVDD + CPF + Aporte sindical + ART 27bis)
                </div>
              </div>
              <div>
                <div style={{ fontSize:12, fontWeight:600, color:GR, marginBottom:4 }}>
                  VEP F.931 — Cargas sociales ARCA/AFIP
                </div>
                <input type="number" value={vep931}
                  onChange={e => setVep931(e.target.value)}
                  placeholder="0.00"
                  style={{ width:'100%', padding:'9px 11px', border:'1px solid #d1d5db',
                    borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
                <div style={{ fontSize:10.5, color:GR, marginTop:3 }}>
                  Total VEP 931 (SS + OS + ART + SCVO)
                </div>
              </div>
            </div>
          </Card>

          {/* Resumen y botón imputar */}
          <Card style={{ background:'#f0f4ff', border:'1px solid #bfdbfe', marginBottom:14 }}>
            <div style={{ fontWeight:700, fontSize:13, color:AZ, marginBottom:10 }}>
              Resumen Rubro 2 — Sueldos y Cargas Sociales
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:12, marginBottom:14 }}>
              {[
                { l:'Sueldos netos', v:totalNeto, c:'#374151' },
                { l:'F.A.T.E.R.Y.H.', v:parseMto(fateryh), c:'#5b21b6' },
                { l:'VEP F.931', v:parseMto(vep931), c:'#0369a1' },
              ].map(({l,v,c}) => (
                <div key={l} style={{ textAlign:'center', background:'#fff', borderRadius:8, padding:'10px 12px' }}>
                  <div style={{ fontSize:11, color:GR, marginBottom:3 }}>{l}</div>
                  <div style={{ fontSize:16, fontWeight:700, color:c }}>{fmt(v)}</div>
                </div>
              ))}
            </div>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center',
              padding:'10px 14px', background:'#1A3FA0', borderRadius:8, marginBottom:14 }}>
              <span style={{ color:'#fff', fontWeight:700, fontSize:13 }}>TOTAL RUBRO 2</span>
              <span style={{ color:'#fff', fontWeight:800, fontSize:18 }}>{fmt(totalRubro2)}</span>
            </div>
            <div style={{ fontSize:11.5, color:'#374151', marginBottom:12, lineHeight:1.7 }}>
              <strong>Gastos que se generarán en Rubro 2:</strong><br/>
              {filas.filter(f=>f.incluir&&parseMto(f.sueldo_neto)>0).map((f,i) => (
                <div key={i} style={{ fontSize:11, color:GR, paddingLeft:8 }}>
                  • {f.es_liquidacion_final||f.tipo_liquidacion==='final'
                    ? `Sueldos, ${f.apellido_nombre}, Sueldo neto - ${expActual?.periodo||'?'} Liquidación final`
                    : f.tipo_liquidacion==='reemplazo'
                      ? `Sueldos, ${f.apellido_nombre}, Reemplazo${f.notas?' '+f.notas:''} - ${expActual?.periodo||'?'}`
                      : `Sueldos, ${f.apellido_nombre}, Sueldo neto - ${expActual?.periodo||'?'}`
                  } → {COLUMNAS.find(c=>c.v===f.columna)?.l} {fmt(parseMto(f.sueldo_neto))}
                </div>
              ))}
              {parseMto(fateryh)>0 && <div style={{ fontSize:11, color:GR, paddingLeft:8 }}>• F.A.T.E.R.Y.H. → General {fmt(parseMto(fateryh))}</div>}
              {parseMto(vep931)>0 && <div style={{ fontSize:11, color:GR, paddingLeft:8 }}>• VEP F.931 — Cargas sociales AFIP → General {fmt(parseMto(vep931))}</div>}
            </div>
            <Btn onClick={imputarSueldos} disabled={procesando||!expSel}
              style={{ opacity: (procesando||!expSel)?0.5:1 }}>
              {procesando ? '⏳ Imputando...' : '💸 Imputar en planilla de gastos'}
            </Btn>
            {!expSel && (
              <div style={{ fontSize:11.5, color:AM, marginTop:6 }}>⚠ Seleccioná el período primero</div>
            )}
          </Card>
        </div>
      )}

      {/* ── TAB HISTORIAL ── */}
      {tab === 'historial' && (
        <Card>
          <div style={{ fontWeight:600, fontSize:13, marginBottom:12 }}>
            Historial de liquidaciones de sueldos ({sueldos.length})
          </div>
          {sueldos.length === 0 ? (
            <div style={{ color:GR, fontSize:13, padding:'16px 0' }}>Sin liquidaciones registradas</div>
          ) : (
            <div style={{ overflowX:'auto' }}>
              <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                <thead>
                  <tr style={{ background:'#f3f4f6' }}>
                    {['Período','Empleado','Tipo','Sueldo neto','FATERYH','Columna','Imputado'].map((h,i) => (
                      <th key={i} style={{ padding:'7px 10px', textAlign:i>=2?'right':'left',
                        fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb',
                        whiteSpace:'nowrap' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {sueldos.map(s => (
                    <tr key={s.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                      <td style={{ padding:'7px 10px' }}>{periodoLabel(s.periodo)}</td>
                      <td style={{ padding:'7px 10px', fontWeight:600 }}>
                        {s.apellido_nombre}
                        {s.es_liquidacion_final && <span style={{ fontSize:10, color:RJ, marginLeft:4 }}>Liq. Final</span>}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right', textTransform:'capitalize' }}>
                        {s.tipo_liquidacion}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:600, color:AZ }}>
                        {fmt(s.sueldo_neto)}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right', color:'#5b21b6' }}>
                        {s.fateryh_monto > 0 ? fmt(s.fateryh_monto) : '—'}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right', fontSize:11 }}>
                        {COLUMNAS.find(c=>c.v===s.columna)?.l || s.columna}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right' }}>
                        {s.imputado
                          ? <span style={{ color:VD, fontSize:11, fontWeight:600 }}>✓ Imputado</span>
                          : <span style={{ color:AM, fontSize:11 }}>Pendiente</span>
                        }
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </Card>
      )}

      {/* ── TAB EMPLEADOS ── */}
      {tab === 'empleados' && (
        <div>
          {formEmp ? (
            <Card>
              <div style={{ fontWeight:600, color:AZ, fontSize:13, marginBottom:14 }}>
                {formEmp.id ? '✏ Editar empleado' : '+ Nuevo empleado'}
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:12 }}>
                <div style={{ gridColumn:'span 2' }}>
                  <Input label="Apellido y Nombre" value={formEmp.apellido_nombre||''}
                    onChange={v=>setFormEmp(x=>({...x,apellido_nombre:v}))}
                    placeholder="APELLIDO Nombre" required />
                </div>
                <div>
                  <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Categoría</div>
                  <select value={formEmp.categoria||''}
                    onChange={e=>setFormEmp(x=>({...x,categoria:e.target.value}))}
                    style={{ width:'100%', padding:'8px 10px', border:'1px solid #d1d5db',
                      borderRadius:7, fontSize:13, background:'#fff' }}>
                    <option value="">— Categoría —</option>
                    {CATEGORIAS_EMP.map(c => <option key={c.v} value={c.v}>{c.l}</option>)}
                  </select>
                </div>
                <Input label="CUIL" value={formEmp.cuil||''} onChange={v=>setFormEmp(x=>({...x,cuil:v}))}
                  placeholder="20-12345678-9" />
                <Input label="Fecha ingreso" value={formEmp.fecha_ingreso||''}
                  onChange={v=>setFormEmp(x=>({...x,fecha_ingreso:v}))} type="date" />
                <div>
                  <label style={{ display:'flex', alignItems:'center', gap:8, fontSize:13, marginTop:8 }}>
                    <input type="checkbox" checked={!!formEmp.activo}
                      onChange={e=>setFormEmp(x=>({...x,activo:e.target.checked}))} />
                    <span>Activo</span>
                  </label>
                </div>
                <Input label="Banco" value={formEmp.banco||''} onChange={v=>setFormEmp(x=>({...x,banco:v}))}
                  placeholder="Banco Macro" />
                <Input label="CBU" value={formEmp.cbu||''} onChange={v=>setFormEmp(x=>({...x,cbu:v}))}
                  placeholder="22 dígitos" />
                <div style={{ gridColumn:'span 2' }}>
                  <Input label="Notas" value={formEmp.notas||''} onChange={v=>setFormEmp(x=>({...x,notas:v}))}
                    placeholder="Observaciones" />
                </div>
              </div>
              <div style={{ display:'flex', gap:8 }}>
                <Btn onClick={guardarEmpleado}>💾 Guardar</Btn>
                <BtnSec onClick={()=>setFormEmp(null)}>Cancelar</BtnSec>
              </div>
            </Card>
          ) : (
            <>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
                <div style={{ fontWeight:600, fontSize:13 }}>Empleados del consorcio ({empleados.length})</div>
                <Btn small onClick={()=>setFormEmp({ activo:true })}>+ Agregar empleado</Btn>
              </div>
              {empleados.length === 0 ? (
                <Card>
                  <div style={{ textAlign:'center', padding:'24px 0', color:GR }}>
                    <div style={{ fontSize:28, marginBottom:8 }}>👷</div>
                    <div style={{ fontWeight:600, marginBottom:6 }}>Sin empleados registrados</div>
                    <div style={{ fontSize:12 }}>
                      Registrá los empleados para que aparezcan automáticamente al liquidar.<br/>
                      También podés cargar sueldos manualmente o con PDF sin registro previo.
                    </div>
                  </div>
                </Card>
              ) : (
                <Card style={{ padding:0, overflow:'hidden' }}>
                  <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12.5 }}>
                    <thead>
                      <tr style={{ background:'#f8fafc', borderBottom:'1.5px solid #e5e7eb' }}>
                        {['Empleado','CUIL','Categoría','Ingreso','Banco','Estado',''].map((h,i)=>(
                          <th key={i} style={{ padding:'8px 12px', textAlign:'left', fontWeight:600,
                            color:'#374151', fontSize:11.5 }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {empleados.map(e => (
                        <tr key={e.id} style={{ borderBottom:'1px solid #f3f4f6',
                          opacity: e.activo ? 1 : 0.55 }}>
                          <td style={{ padding:'8px 12px', fontWeight:600 }}>{e.apellido_nombre}</td>
                          <td style={{ padding:'8px 12px', color:GR, fontSize:11 }}>{e.cuil||'—'}</td>
                          <td style={{ padding:'8px 12px', fontSize:11 }}>
                            {CATEGORIAS_EMP.find(c=>c.v===e.categoria)?.l||e.categoria||'—'}
                          </td>
                          <td style={{ padding:'8px 12px', color:GR, fontSize:11 }}>
                            {e.fecha_ingreso ? new Date(e.fecha_ingreso+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                          </td>
                          <td style={{ padding:'8px 12px', color:GR, fontSize:11 }}>{e.banco||'—'}</td>
                          <td style={{ padding:'8px 12px' }}>
                            <Badge text={e.activo?'Activo':'Inactivo'}
                              color={e.activo?VD:'#9ca3af'}
                              bg={e.activo?'#dcfce7':'#f3f4f6'} />
                          </td>
                          <td style={{ padding:'8px 10px', textAlign:'right' }}>
                            <BtnSec small onClick={()=>setFormEmp({...e})}>✏ Editar</BtnSec>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </Card>
              )}
            </>
          )}
        </div>
      )}
    </div>
  )
}


// ══════════════════════════════════════════════════════════════════════════════
// ANULAR COBRANZAS
// ══════════════════════════════════════════════════════════════════════════════
function AnularCobranzas({ session, consorcioId, unidades, copropietarios, expensas }) {
  const [cobranzas, setCobranzas] = useState([])
  const [filtroExp, setFiltroExp] = useState('')
  const [filtroUF, setFiltroUF]   = useState('')
  const [msg, setMsg]             = useState(null)
  const [form, setForm]           = useState(null)

  async function cargar() {
    const q = supabase.from('con_cobranzas').select('*')
      .eq('consorcio_id', consorcioId)
      .order('fecha', { ascending:false }).limit(200)
    if (filtroExp) q.eq('expensa_id', filtroExp)
    if (filtroUF)  q.eq('unidad_id', filtroUF)
    const { data } = await q
    setCobranzas(data || [])
  }

  async function anular(c) {
    if (!form?.motivo?.trim()) return setMsg({ tipo:'warn', texto:'Ingresá el motivo de anulación' })
    const { error } = await supabase.from('con_cobranzas')
      .update({
        estado: 'anulada',
        anulado_motivo: form.motivo,
        anulado_fecha: new Date().toISOString().split('T')[0],
      })
      .eq('id', c.id)

    if (error) {
      setMsg({ tipo:'error', texto: error.message })
    } else {
      // Revertir el pago en el detalle de expensa
      if (c.expensa_id && c.unidad_id) {
        const { data: det } = await supabase.from('con_expensas_detalle')
          .select('pagos_periodo').eq('expensa_id', c.expensa_id).eq('unidad_id', c.unidad_id).single()
        if (det) {
          const nuevoPago = Math.max(0, (parseFloat(det.pagos_periodo)||0) - (parseFloat(c.monto)||0))
          await supabase.from('con_expensas_detalle')
            .update({ pagos_periodo: nuevoPago,
              estado: nuevoPago > 0 ? 'pendiente' : 'pendiente' })
            .eq('expensa_id', c.expensa_id).eq('unidad_id', c.unidad_id)
        }
      }
      setMsg({ tipo:'ok', texto:'✓ Cobranza anulada y saldo revertido' })
      setForm(null)
      cargar()
    }
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId, filtroExp, filtroUF])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR')
  const fmtD = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'
  const periodoLabel = p => {
    if (!p) return '—'
    const exp = expensas.find(e=>e.id===p)
    if (!exp) return p
    const [y,m] = (exp.periodo||'').split('-')
    const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
    return m ? `${meses[parseInt(m)-1]} ${y}` : exp.periodo
  }

  const vigentes = cobranzas.filter(c=>c.estado==='vigente')
  const anuladas = cobranzas.filter(c=>c.estado==='anulada')

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>↩️ Anular cobranzas</div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Anule cobranzas registradas por error. El saldo se revierte automáticamente.
      </div>
      <Msg data={msg} />

      {/* Alerta */}
      <Card style={{ marginBottom:16, background:'#fff8f0', border:'1px solid #fed7aa' }}>
        <div style={{ fontSize:12, color:'#92400e' }}>
          ⚠️ La anulación revierte el pago en la cuenta corriente de la unidad.
          Use esta función solo para corregir registros cargados por error.
          Requiere motivo obligatorio para auditoría.
        </div>
      </Card>

      {/* Filtros */}
      <Card style={{ marginBottom:12 }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <Sel label="Filtrar por período" value={filtroExp} onChange={setFiltroExp}
            opts={[{v:'',l:'Todos los períodos'},
              ...expensas.map(e => {
                const [y,m2] = (e.periodo||'').split('-')
                const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
                return { v:e.id, l:m2?`${meses[parseInt(m2)-1]} ${y}`:e.periodo }
              })
            ]} />
          <Sel label="Filtrar por unidad" value={filtroUF} onChange={setFiltroUF}
            opts={[{v:'',l:'Todas las unidades'},
              ...unidades.map(u => ({ v:u.id, l:`UF ${u.numero}` }))
            ]} />
        </div>
      </Card>

      {/* Modal anulación */}
      {form && (
        <Card style={{ marginBottom:16, border:'1.5px solid #fca5a5', background:'#fff8f8' }}>
          <div style={{ fontWeight:700, color:RJ, fontSize:13, marginBottom:10 }}>
            Anular cobranza — UF {unidades.find(u=>u.id===form.c.unidad_id)?.numero} — {fmt(form.c.monto)}
          </div>
          <div style={{ marginBottom:12 }}>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Motivo de anulación *</div>
            <input value={form.motivo||''} placeholder="Ej: Error en el monto, pago duplicado..."
              onChange={e=>setForm(f=>({...f,motivo:e.target.value}))}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #fca5a5',
                borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <Btn onClick={()=>anular(form.c)} style={{ background:RJ, color:'#fff' }}>↩️ Confirmar anulación</Btn>
            <BtnSec onClick={()=>{ setForm(null); setMsg(null) }}>Cancelar</BtnSec>
          </div>
        </Card>
      )}

      {/* Tabla vigentes */}
      <Card style={{ marginBottom:12 }}>
        <div style={{ fontWeight:600, fontSize:13, marginBottom:10 }}>
          Cobranzas vigentes ({vigentes.length})
        </div>
        {vigentes.length === 0 ? (
          <div style={{ color:GR, fontSize:13, padding:'8px 0' }}>Sin cobranzas vigentes en el filtro seleccionado</div>
        ) : (
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
              <thead>
                <tr style={{ background:'#f3f4f6' }}>
                  {['Fecha','UF','Período','Monto','Medio','Recibo',''].map((h,i) => (
                    <th key={i} style={{ padding:'7px 10px', textAlign:i===3?'right':'left',
                      fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {vigentes.map(c => {
                  const uf = unidades.find(u=>u.id===c.unidad_id)
                  return (
                    <tr key={c.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                      <td style={{ padding:'7px 10px', color:GR, fontSize:11 }}>{fmtD(c.fecha)}</td>
                      <td style={{ padding:'7px 10px', fontWeight:600 }}>UF {uf?.numero||'?'}</td>
                      <td style={{ padding:'7px 10px', color:GR }}>{periodoLabel(c.expensa_id)}</td>
                      <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700, color:VD }}>{fmt(c.monto)}</td>
                      <td style={{ padding:'7px 10px', color:GR, textTransform:'capitalize' }}>
                        {c.medio_pago?.replace('_',' ')||'—'}
                      </td>
                      <td style={{ padding:'7px 10px', color:GR, fontSize:11 }}>{c.recibo_numero||'—'}</td>
                      <td style={{ padding:'7px 10px' }}>
                        <Btn small onClick={()=>setForm({c, motivo:''})}
                          style={{ background:'#fee2e2', color:RJ }}>↩️ Anular</Btn>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      {/* Anuladas */}
      {anuladas.length > 0 && (
        <Card>
          <div style={{ fontWeight:600, fontSize:13, marginBottom:10, color:GR }}>
            Anuladas ({anuladas.length})
          </div>
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:11 }}>
              <thead>
                <tr style={{ background:'#f9fafb' }}>
                  {['Fecha','UF','Monto','Motivo','Fecha anulación'].map((h,i) => (
                    <th key={i} style={{ padding:'6px 10px', textAlign:'left',
                      fontWeight:600, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {anuladas.map(c => {
                  const uf = unidades.find(u=>u.id===c.unidad_id)
                  return (
                    <tr key={c.id} style={{ borderBottom:'1px solid #f3f4f6', opacity:0.6 }}>
                      <td style={{ padding:'6px 10px' }}>{fmtD(c.fecha)}</td>
                      <td style={{ padding:'6px 10px' }}>UF {uf?.numero||'?'}</td>
                      <td style={{ padding:'6px 10px', color:GR }}>{fmt(c.monto)}</td>
                      <td style={{ padding:'6px 10px', color:GR }}>{c.anulado_motivo||'—'}</td>
                      <td style={{ padding:'6px 10px', color:GR }}>{fmtD(c.anulado_fecha)}</td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  )
}

// ── FormComp fuera del componente: evita re-mount en cada keystroke ─────────
function FormComp({ form, setForm, guardar, guardando, proveedores, expensas,
  extraerFacturaConIA, extrayendoIA, archivoFactura }) {
  const TIPOS = [
    {v:'factura',l:'Factura'},{v:'remito',l:'Remito'},{v:'ticket',l:'Ticket'},
    {v:'nota_debito',l:'Nota de débito'},{v:'nota_credito',l:'Nota de crédito'}
  ]
  return (
    <Card style={{ marginBottom:16, border:`1.5px solid ${form.id?AM:AZ}` }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:10 }}>
        <div style={{ fontWeight:700, color:form.id?AM:AZ, fontSize:13 }}>
          {form.id ? '✏ Editar comprobante' : '🧾 Nuevo comprobante'}
        </div>
      </div>

      {/* IA solo en alta nueva */}
      {!form.id && (
        <div style={{ background:'#f0f9ff', border:'1px solid #bae6fd', borderRadius:8, padding:'10px 14px', marginBottom:14 }}>
          <div style={{ fontSize:12, fontWeight:600, color:'#0369a1', marginBottom:6 }}>🤖 Extracción automática con IA (opcional)</div>
          <div style={{ display:'flex', gap:10, alignItems:'center' }}>
            <input type="file" accept=".pdf,image/*"
              onChange={e => e.target.files[0] && extraerFacturaConIA(e.target.files[0])}
              style={{ fontSize:12, flex:1 }} disabled={extrayendoIA} />
            {extrayendoIA && <span style={{ fontSize:12, color:'#0369a1', whiteSpace:'nowrap' }}>⏳ Analizando...</span>}
            {archivoFactura && !extrayendoIA && <span style={{ fontSize:11, color:VD, whiteSpace:'nowrap' }}>✓ {archivoFactura.name.slice(0,20)}</span>}
          </div>
          <div style={{ fontSize:10, color:'#6b7280', marginTop:4 }}>Suba la factura y la IA completará los campos automáticamente.</div>
        </div>
      )}

      <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr 1fr', gap:12, marginBottom:12 }}>
        <Sel label="Proveedor *" value={form.proveedor_id||''} onChange={v=>setForm(f=>({...f,proveedor_id:v}))}
          opts={[{v:'',l:'— Seleccione —'},...proveedores.map(p=>({v:p.id,l:p.razon_social}))]} />
        <Sel label="Tipo" value={form.tipo||'factura'} onChange={v=>setForm(f=>({...f,tipo:v}))} opts={TIPOS} />
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>N° comprobante</div>
          <input value={form.numero||''} placeholder="0001-00012345"
            onChange={e=>setForm(f=>({...f,numero:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
        </div>
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr 1fr', gap:12, marginBottom:12 }}>
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Concepto *</div>
          <input value={form.concepto||''} placeholder="Descripción del servicio/producto"
            onChange={e=>setForm(f=>({...f,concepto:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
        </div>
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Fecha *</div>
          <input type="date" value={form.fecha||''} onChange={e=>setForm(f=>({...f,fecha:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
        </div>
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Vencimiento</div>
          <input type="date" value={form.fecha_vencimiento||''} onChange={e=>setForm(f=>({...f,fecha_vencimiento:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
        </div>
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:12, marginBottom:12 }}>
        {[
          { k:'monto_neto', l:'Monto neto' },
          { k:'iva', l:'IVA' },
          { k:'otros_impuestos', l:'Otros imp.' },
          { k:'monto_total', l:'Total *' },
        ].map(f2 => (
          <div key={f2.k}>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>{f2.l}</div>
            <input type="number" min="0" step="0.01" value={form[f2.k]||''}
              onChange={e => {
                const val = e.target.value
                setForm(f => {
                  const upd = {...f, [f2.k]: val}
                  if (f2.k !== 'monto_total') {
                    upd.monto_total = (
                      (parseFloat(upd.monto_neto)||0) +
                      (parseFloat(upd.iva)||0) +
                      (parseFloat(upd.otros_impuestos)||0)
                    ).toFixed(2)
                  }
                  return upd
                })
              }}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7,
                fontSize:13, boxSizing:'border-box',
                fontWeight: f2.k==='monto_total'?700:400,
                background: f2.k==='monto_total'?'#f0f4ff':'#fff' }} />
          </div>
        ))}
      </div>
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Período asociado</div>
          <select value={form.expensa_id||''} onChange={e=>setForm(f=>({...f,expensa_id:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, background:'#fff' }}>
            <option value="">Sin período</option>
            {expensas.map(e=><option key={e.id} value={e.id}>{e.periodo}</option>)}
          </select>
        </div>
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Notas</div>
          <input value={form.notas||''} placeholder="Opcional"
            onChange={e=>setForm(f=>({...f,notas:e.target.value}))}
            style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
        </div>
      </div>
      <div style={{ display:'flex', gap:8 }}>
        <Btn onClick={guardar} disabled={guardando}>{guardando?'⏳':form.id?'💾 Actualizar':'✓ Guardar'}</Btn>
        <BtnSec onClick={()=>{setForm(null);setMsg(null)}}>Cancelar</BtnSec>
      </div>
    </Card>
  )
}

// ── FormPago fuera del componente: evita re-mount en cada keystroke ─────────
function FormPago({ formPago, setFormPago, pagarComprobante, proveedores }) {
  const MEDIOS_PAGO = [
    {v:'transferencia',l:'Transferencia'},{v:'cheque_propio',l:'Cheque propio'},
    {v:'cheque_tercero',l:'Cheque de tercero'},{v:'efectivo',l:'Efectivo'},{v:'otro',l:'Otro'}
  ]
  const hoy = new Date().toISOString().split('T')[0]
    const comp = formPago.comp
    const prov = proveedores.find(p=>p.id===comp.proveedor_id)
    return (
      <Card style={{ marginBottom:16, border:'2px solid #86efac', background:'#f0fdf4' }}>
        <div style={{ fontWeight:700, color:VD, fontSize:13, marginBottom:4 }}>💸 Registrar pago</div>
        <div style={{ fontSize:12, color:GR, marginBottom:12 }}>
          {prov?.razon_social} — {comp.tipo} {comp.numero||''} — {comp.concepto} — Saldo: <strong style={{ color:RJ }}>{fmt(comp.saldo_pendiente)}</strong>
        </div>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10, marginBottom:10 }}>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Monto a pagar *</div>
            <input type="number" min="0" step="0.01" value={formPago.monto||''}
              onChange={e=>setFormPago(f=>({...f,monto:e.target.value}))}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #86efac', borderRadius:7, fontSize:14, fontWeight:700, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Fecha *</div>
            <input type="date" value={formPago.fecha||hoy} onChange={e=>setFormPago(f=>({...f,fecha:e.target.value}))}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Medio de pago</div>
            <select value={formPago.medio_pago||'transferencia'} onChange={e=>setFormPago(f=>({...f,medio_pago:e.target.value}))}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, background:'#fff' }}>
              {MEDIOS_PAGO.map(m=><option key={m.v} value={m.v}>{m.l}</option>)}
            </select>
          </div>
        </div>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:10, marginBottom:12 }}>
          <div>
            <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Ret. IIBB $</div>
            <input type="number" min="0" step="0.01" value={formPago.retencion_iibb||''}
              onChange={e=>setFormPago(f=>({...f,retencion_iibb:e.target.value}))}
              style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Ret. Ganancias $</div>
            <input type="number" min="0" step="0.01" value={formPago.retencion_ganancias||''}
              onChange={e=>setFormPago(f=>({...f,retencion_ganancias:e.target.value}))}
              style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:11, color:GR, marginBottom:3 }}>N° Orden de pago</div>
            <input value={formPago.nro_orden_pago||''} onChange={e=>setFormPago(f=>({...f,nro_orden_pago:e.target.value}))}
              style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
          </div>
          <div>
            <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Referencia</div>
            <input value={formPago.referencia||''} onChange={e=>setFormPago(f=>({...f,referencia:e.target.value}))}
              style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
          </div>
        </div>
        {formPago.monto && (formPago.retencion_iibb||formPago.retencion_ganancias||formPago.retencion_iva) && (
          <div style={{ fontSize:13, fontWeight:700, color:VD, marginBottom:10 }}>
            Neto a transferir: {fmt((parseFloat(formPago.monto)||0)-(parseFloat(formPago.retencion_iibb)||0)-(parseFloat(formPago.retencion_ganancias)||0)-(parseFloat(formPago.retencion_iva)||0))}
          </div>
        )}
        <div style={{ display:'flex', gap:8 }}>
          <Btn color={VD} onClick={pagarComprobante}>✓ Confirmar pago</Btn>
          <BtnSec onClick={()=>setFormPago(null)}>Cancelar</BtnSec>
        </div>
      </Card>
    )
}

function Comprobantes({ session, consorcioId, proveedores, expensas }) {
  const [comprobantes, setComprobantes] = useState([])
  const [form, setForm]   = useState(null)
  const [formPago, setFormPago] = useState(null) // pago rápido inline
  const [filtro, setFiltro] = useState('')
  const [msg, setMsg]     = useState(null)
  const [guardando, setGuardando] = useState(false)
  const [extrayendoIA, setExtrayendoIA] = useState(false)
  const [archivoFactura, setArchivoFactura] = useState(null)
  const [filtroEstado, setFiltroEstado] = useState('')
  const [busquedaComp, setBusquedaComp] = useState('')
  const hoy = new Date().toISOString().split('T')[0]

  // ── Extraer datos de factura PDF con IA ───────────────────────────────────
  async function extraerFacturaConIA(file) {
    if (!file) return
    setArchivoFactura(file)
    setExtrayendoIA(true)
    setMsg({ tipo:'info', texto:'🤖 Analizando factura con IA...' })
    try {
      const base64 = await new Promise((res, rej) => {
        const r = new FileReader()
        r.onload = () => res(r.result.split(',')[1])
        r.onerror = () => rej(new Error('Error leyendo archivo'))
        r.readAsDataURL(file)
      })
      const { data: { session: sess } } = await supabase.auth.getSession()
      const response = await fetch(`${SUPA_URL}/functions/v1/extraer-factura-ia`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${sess?.access_token}`,
          'apikey': process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
        },
        body: JSON.stringify({ base64, filename: file.name })
      })
      if (!response.ok) {
        const err = await response.json().catch(() => ({}))
        throw new Error(err.error || `Error ${response.status}`)
      }
      const result = await response.json()
      if (!result.ok) throw new Error(result.error || 'Error desconocido')
      const d = result.datos
      let provId = ''
      if (d.proveedor_nombre) {
        const nombreLower = d.proveedor_nombre.toLowerCase()
        const match = proveedores.find(p =>
          p.razon_social?.toLowerCase().includes(nombreLower) ||
          nombreLower.includes(p.razon_social?.toLowerCase())
        )
        if (match) provId = match.id
      }
      const tipoMap = { 'A':'factura', 'B':'factura', 'C':'factura',
        'FACTURA':'factura', 'REMITO':'remito', 'TICKET':'ticket',
        'NOTA DE DEBITO':'nota_debito', 'NOTA DE CREDITO':'nota_credito' }
      const tipoDetectado = tipoMap[(d.tipo || '').toUpperCase()] || 'factura'
      setForm(f => ({
        ...(f || {}),
        proveedor_id:     provId || f?.proveedor_id || '',
        tipo:             tipoDetectado,
        numero:           d.numero || f?.numero || '',
        fecha:            d.fecha || f?.fecha || hoy,
        fecha_vencimiento: d.fecha_vencimiento || f?.fecha_vencimiento || '',
        concepto:         d.concepto || f?.concepto || '',
        monto_neto:       d.monto_neto != null ? String(d.monto_neto) : f?.monto_neto || '',
        iva:              d.iva != null ? String(d.iva) : f?.iva || '',
        otros_impuestos:  d.otros_impuestos != null ? String(d.otros_impuestos) : f?.otros_impuestos || '',
        monto_total:      d.monto_total != null ? String(d.monto_total) : f?.monto_total || '',
        notas:            d.notas || f?.notas || '',
      }))
      const avisoProveedor = provId ? '' : (d.proveedor_nombre ? ` — Proveedor "${d.proveedor_nombre}" no encontrado, seleccionarlo manualmente.` : '')
      setMsg({ tipo:'ok', texto:`✓ Datos extraídos de la factura${avisoProveedor}` })
    } catch(e) {
      setMsg({ tipo:'error', texto: 'Error IA: ' + e.message })
    }
    setExtrayendoIA(false)
  }

  async function cargar() {
    const q = supabase.from('con_comprobantes_proveedor').select('*')
      .eq('consorcio_id', consorcioId).order('fecha', { ascending:false }).limit(200)
    if (filtro) q.eq('proveedor_id', filtro)
    const { data } = await q
    setComprobantes(data || [])
  }

  async function guardar() {
    if (!form?.proveedor_id) return setMsg({ tipo:'warn', texto:'Seleccioná un proveedor' })
    if (!form?.concepto?.trim()) return setMsg({ tipo:'warn', texto:'Ingresá el concepto' })
    if (!form?.monto_total || parseFloat(form.monto_total) <= 0) return setMsg({ tipo:'warn', texto:'Ingresá el monto' })
    if (!form?.fecha) return setMsg({ tipo:'warn', texto:'Ingresá la fecha' })
    setGuardando(true)
    const total = parseFloat(form.monto_total)
    const esEdicion = !!form.id
    if (esEdicion) {
      // Edición: actualizar campos editables (no el saldo ni estado si ya tiene pagos)
      const { error } = await supabase.from('con_comprobantes_proveedor').update({
        proveedor_id: form.proveedor_id,
        expensa_id: form.expensa_id || null,
        tipo: form.tipo || 'factura',
        numero: form.numero || null,
        fecha: form.fecha,
        fecha_vencimiento: form.fecha_vencimiento || null,
        concepto: form.concepto.trim(),
        monto_neto: parseFloat(form.monto_neto||0),
        iva: parseFloat(form.iva||0),
        otros_impuestos: parseFloat(form.otros_impuestos||0),
        monto_total: total,
        notas: form.notas || null,
      }).eq('id', form.id)
      if (error) setMsg({ tipo:'error', texto: error.message })
      else { setMsg({ tipo:'ok', texto:'✓ Comprobante actualizado' }); setForm(null); cargar() }
    } else {
      // Alta nueva
      const { error } = await supabase.from('con_comprobantes_proveedor').insert([{
        id: `COMP-${Date.now()}`,
        admin_id: session.user.id,
        consorcio_id: consorcioId,
        proveedor_id: form.proveedor_id,
        expensa_id: form.expensa_id || null,
        tipo: form.tipo || 'factura',
        numero: form.numero || null,
        fecha: form.fecha,
        fecha_vencimiento: form.fecha_vencimiento || null,
        concepto: form.concepto.trim(),
        monto_neto: parseFloat(form.monto_neto||0),
        iva: parseFloat(form.iva||0),
        otros_impuestos: parseFloat(form.otros_impuestos||0),
        monto_total: total,
        saldo_pendiente: total,
        estado: 'pendiente',
        notas: form.notas || null,
      }])
      if (error) setMsg({ tipo:'error', texto: error.message })
      else {
        setMsg({ tipo:'ok', texto:'✓ Comprobante registrado' })
        setForm(null)
        // Si el usuario quiere pagar en el momento, no hace nada más
        cargar()
      }
    }
    setGuardando(false)
  }

  // Pago rápido directo desde el comprobante
  async function pagarComprobante() {
    if (!formPago?.monto || parseFloat(formPago.monto)<=0) return setMsg({ tipo:'warn', texto:'Ingresá el monto a pagar' })
    if (!formPago?.fecha) return setMsg({ tipo:'warn', texto:'Ingresá la fecha' })
    const comp = formPago.comp
    const monto = parseFloat(formPago.monto)
    const retIIBB = parseFloat(formPago.retencion_iibb)||0
    const retGan  = parseFloat(formPago.retencion_ganancias)||0
    const retIVA  = parseFloat(formPago.retencion_iva)||0
    const neto    = monto - retIIBB - retGan - retIVA

    // Registrar pago
    const { error } = await supabase.from('con_pagos_proveedor').insert([{
      id: `PAG-${Date.now()}`,
      admin_id: session.user.id,
      consorcio_id: consorcioId,
      proveedor_id: comp.proveedor_id,
      comprobante_id: comp.id,
      fecha: formPago.fecha,
      monto,
      retencion_iibb: retIIBB||null,
      retencion_ganancias: retGan||null,
      retencion_iva: retIVA||null,
      monto_neto_pagado: neto,
      nro_orden_pago: formPago.nro_orden_pago||null,
      medio_pago: formPago.medio_pago||'transferencia',
      referencia: formPago.referencia||null,
      notas: formPago.notas||null,
    }])
    if (error) return setMsg({ tipo:'error', texto: error.message })

    // Actualizar saldo del comprobante
    const nuevoSaldo = Math.max(0, (parseFloat(comp.saldo_pendiente)||0) - monto)
    const nuevoEstado = nuevoSaldo <= 0 ? 'pagado' : 'pagado_parcial'
    await supabase.from('con_comprobantes_proveedor')
      .update({ saldo_pendiente: nuevoSaldo, estado: nuevoEstado })
      .eq('id', comp.id)

    setFormPago(null)
    setMsg({ tipo:'ok', texto:`✓ Pago de ${fmt(monto)} registrado — Saldo restante: ${fmt(nuevoSaldo)}` })
    cargar()
  }

  async function anular(id) {
    if (!confirm('¿Anular este comprobante?')) return
    await supabase.from('con_comprobantes_proveedor').update({ estado:'anulado' }).eq('id', id)
    cargar()
  }

  async function eliminar(id) {
    if (!confirm('¿Eliminar definitivamente este comprobante? Esta acción no se puede deshacer.')) return
    await supabase.from('con_comprobantes_proveedor').delete().eq('id', id)
    cargar()
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId, filtro])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR')
  const fmtD = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'

  const totalPendiente = comprobantes.filter(c=>c.estado==='pendiente'||c.estado==='pagado_parcial')
    .reduce((a,c) => a + (parseFloat(c.saldo_pendiente)||0), 0)

  const compsFiltrados = comprobantes.filter(c => {
    const prov = proveedores.find(p=>p.id===c.proveedor_id)
    const q = busquedaComp.toLowerCase()
    return (!filtro || c.proveedor_id === filtro)
      && (!filtroEstado || c.estado === filtroEstado)
      && (!q || c.concepto?.toLowerCase().includes(q) || c.numero?.toLowerCase().includes(q)
           || prov?.razon_social?.toLowerCase().includes(q))
  })

  const fmtD2 = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'
  function handlePDFComp(){
    exportarPDF({titulo:'Comprobantes de Proveedores',logoB64:LOGO_ADM_B64,
      columnas:[{key:'fecha',label:'Fecha',nowrap:true},{key:'vto',label:'Vto.',nowrap:true},
        {key:'prov',label:'Proveedor'},{key:'tipo',label:'Tipo'},{key:'nro',label:'N°'},
        {key:'concepto',label:'Concepto'},{key:'total',label:'Total',align:'right'},
        {key:'saldo',label:'Saldo',align:'right'},{key:'estado',label:'Estado'}],
      filas:compsFiltrados.map(c=>{
        const prov=proveedores.find(p=>p.id===c.proveedor_id)
        return {fecha:fmtD2(c.fecha),vto:fmtD2(c.fecha_vencimiento),prov:prov?.razon_social||'',
          tipo:c.tipo,nro:c.numero||'',concepto:c.concepto,
          total:'$'+Number(c.monto_total||0).toLocaleString('es-AR'),
          saldo:c.estado==='pagado'?'✓':'$'+Number(c.saldo_pendiente||0).toLocaleString('es-AR'),
          estado:c.estado}
      }),
      totales:{fecha:'',vto:'',prov:'TOTAL',tipo:'',nro:'',concepto:'',
        total:'$'+compsFiltrados.reduce((a,c)=>a+parseFloat(c.monto_total||0),0).toLocaleString('es-AR'),
        saldo:'$'+compsFiltrados.filter(c=>c.estado!=='pagado'&&c.estado!=='anulado').reduce((a,c)=>a+parseFloat(c.saldo_pendiente||0),0).toLocaleString('es-AR'),
        estado:''}
    })
  }
  function handleExcelComp(){
    exportarExcel({titulo:'Comprobantes-Proveedores',
      columnas:[{key:'fecha',label:'Fecha'},{key:'prov',label:'Proveedor'},{key:'tipo',label:'Tipo'},
        {key:'nro',label:'N° Comp.'},{key:'concepto',label:'Concepto'},{key:'total',label:'Monto Total'},
        {key:'saldo',label:'Saldo Pendiente'},{key:'estado',label:'Estado'},{key:'vto',label:'Vencimiento'}],
      filas:compsFiltrados.map(c=>{
        const prov=proveedores.find(p=>p.id===c.proveedor_id)
        return {fecha:c.fecha,prov:prov?.razon_social||'',tipo:c.tipo,nro:c.numero||'',
          concepto:c.concepto,total:c.monto_total,saldo:c.saldo_pendiente,estado:c.estado,vto:c.fecha_vencimiento||''}
      })
    })
  }

  const TIPOS = [
    {v:'factura',l:'Factura'},{v:'remito',l:'Remito'},{v:'ticket',l:'Ticket'},
    {v:'nota_debito',l:'Nota de débito'},{v:'nota_credito',l:'Nota de crédito'}
  ]
  const ESTADOS_COLOR = {
    pendiente:    { c:AM,  bg:'#fef9c3', t:'Pendiente' },
    pagado_parcial:{ c:'#7c3aed', bg:'#ede9fe', t:'Pago parcial' },
    pagado:       { c:VD,  bg:'#dcfce7', t:'Pagado' },
    anulado:      { c:GR,  bg:'#f3f4f6', t:'Anulado' },
  }
  const MEDIOS_PAGO = [
    {v:'transferencia',l:'Transferencia'},{v:'cheque_propio',l:'Cheque propio'},
    {v:'cheque_tercero',l:'Cheque de tercero'},{v:'efectivo',l:'Efectivo'},{v:'otro',l:'Otro'}
  ]



  // ── Tab sueldos: gastos de con_gastos de categoría sueldos/fateryh/vep_931 ──
  const [tabComp, setTabComp]         = useState('proveedores')
  const [gastosSueldos, setGastosSueldos] = useState([])
  const [cargandoSueldos, setCargandoSueldos] = useState(false)

  async function cargarGastosSueldos() {
    setCargandoSueldos(true)
    const { data } = await supabase.from('con_gastos').select('*')
      .eq('admin_id', session.user.id).eq('consorcio_id', consorcioId)
      .in('categoria', ['sueldos','fateryh','vep_931','cargas_sociales'])
      .order('fecha', { ascending:false }).limit(200)
    setGastosSueldos(data || [])
    setCargandoSueldos(false)
  }

  useEffect(() => {
    if (consorcioId && tabComp === 'sueldos') cargarGastosSueldos()
  }, [consorcioId, tabComp])

  async function anularGasto(id) {
    if (!confirm('¿Eliminar este gasto de sueldo/CCSS? Se borrará de la planilla de gastos de la expensa.')) return
    const { error } = await supabase.from('con_gastos').delete().eq('id', id)
    if (error) setMsg({ tipo:'error', texto: error.message })
    else { setMsg({ tipo:'ok', texto:'✓ Gasto eliminado de la planilla' }); cargarGastosSueldos() }
  }

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>🧾 Comprobantes</div>
        {tabComp === 'proveedores' && (
          <Btn onClick={() => { setForm({ tipo:'factura', fecha:hoy }); setFormPago(null) }}>+ Nuevo comprobante</Btn>
        )}
      </div>

      {/* Tabs */}
      <div style={{ display:'flex', gap:0, marginBottom:16, borderBottom:'2px solid #e5e7eb' }}>
        {[
          { id:'proveedores', l:'🧾 Proveedores' },
          { id:'sueldos',     l:'💼 Sueldos y CCSS' },
        ].map(t => (
          <button key={t.id} type="button" onClick={()=>setTabComp(t.id)}
            style={{ padding:'8px 18px', border:'none',
              borderBottom:tabComp===t.id?`2px solid ${AZ}`:'2px solid transparent',
              background:'transparent', color:tabComp===t.id?AZ:GR,
              fontWeight:tabComp===t.id?700:400, fontSize:13, cursor:'pointer', marginBottom:-2 }}>
            {t.l}
          </button>
        ))}
      </div>

      <Msg data={msg} />

      {/* ── TAB SUELDOS Y CCSS ── */}
      {tabComp === 'sueldos' && (
        <div>
          <div style={{ fontSize:12, color:GR, marginBottom:12 }}>
            Gastos de Rubro 2 — Sueldos, FATERYH y VEP F.931 imputados en las expensas
          </div>
          <div style={{ display:'flex', gap:8, marginBottom:12 }}>
            <Btn small onClick={cargarGastosSueldos}>↺ Actualizar</Btn>
          </div>
          {cargandoSueldos ? (
            <div style={{ textAlign:'center', padding:32, color:GR }}>⏳ Cargando...</div>
          ) : gastosSueldos.length === 0 ? (
            <Card>
              <div style={{ textAlign:'center', padding:'24px 0', color:GR }}>
                <div style={{ fontSize:28, marginBottom:8 }}>💼</div>
                Sin gastos de sueldos o CCSS registrados en expensas
              </div>
            </Card>
          ) : (
            <Card style={{ padding:0, overflow:'hidden' }}>
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                  <thead>
                    <tr style={{ background:'#f8fafc', borderBottom:'1.5px solid #e5e7eb' }}>
                      {['Fecha','Expensa','Concepto','Categoría','Monto','Notas',''].map((h,i) => (
                        <th key={i} style={{ padding:'8px 12px', textAlign:i===4?'right':'left',
                          fontWeight:600, color:'#374151', fontSize:11.5, whiteSpace:'nowrap' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {gastosSueldos.map(g => {
                      const exp = expensas.find(e => e.id === g.expensa_id)
                      const catLabel = g.categoria === 'sueldos' ? '💼 Sueldo' :
                        g.categoria === 'fateryh' ? '🟣 FATERYH' :
                        g.categoria === 'vep_931' ? '🔵 VEP F.931' : g.categoria
                      const catColor = g.categoria === 'sueldos' ? AZ :
                        g.categoria === 'fateryh' ? '#5b21b6' :
                        g.categoria === 'vep_931' ? '#0369a1' : GR
                      return (
                        <tr key={g.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                          <td style={{ padding:'8px 12px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>
                            {g.fecha ? new Date(g.fecha+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                          </td>
                          <td style={{ padding:'8px 12px', fontSize:11, color:GR }}>
                            {exp ? (() => {
                              const [y,m] = (exp.periodo||'').split('-')
                              const ms=['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
                              return m ? `${ms[parseInt(m)-1]} ${y}` : exp.periodo
                            })() : '—'}
                          </td>
                          <td style={{ padding:'8px 12px', fontWeight:500, maxWidth:260 }}>
                            {g.concepto}
                          </td>
                          <td style={{ padding:'8px 12px' }}>
                            <span style={{ fontSize:11, padding:'2px 8px', borderRadius:6, fontWeight:600,
                              background: g.categoria==='sueldos'?'#eff6ff':g.categoria==='fateryh'?'#f5f3ff':'#eff6ff',
                              color: catColor }}>
                              {catLabel}
                            </span>
                          </td>
                          <td style={{ padding:'8px 12px', textAlign:'right', fontWeight:700, color:AZ }}>
                            ${(Number(g.monto)||0).toLocaleString('es-AR',{minimumFractionDigits:2})}
                          </td>
                          <td style={{ padding:'8px 12px', fontSize:11, color:GR, maxWidth:160,
                            overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>
                            {g.notas||'—'}
                          </td>
                          <td style={{ padding:'8px 10px', textAlign:'right' }}>
                            <button type="button"
                              onClick={() => anularGasto(g.id)}
                              title="Eliminar este gasto de la planilla de expensas"
                              style={{ padding:'4px 10px', background:'#fff', color:RJ,
                                border:`1px solid ${RJ}`, borderRadius:6, fontSize:11,
                                fontWeight:600, cursor:'pointer' }}>
                              🗑 Anular
                            </button>
                          </td>
                        </tr>
                      )
                    })}
                  </tbody>
                  <tfoot>
                    <tr style={{ background:'#f0f4ff', borderTop:'2px solid #1A3FA0' }}>
                      <td colSpan={4} style={{ padding:'8px 12px', fontWeight:700, color:AZ }}>Total Rubro 2</td>
                      <td style={{ padding:'8px 12px', textAlign:'right', fontWeight:800, fontSize:14, color:AZ }}>
                        ${gastosSueldos.reduce((a,g)=>a+(Number(g.monto)||0),0)
                          .toLocaleString('es-AR',{minimumFractionDigits:2})}
                      </td>
                      <td colSpan={2} />
                    </tr>
                  </tfoot>
                </table>
              </div>
            </Card>
          )}
        </div>
      )}

      {/* ── TAB PROVEEDORES (contenido original) ── */}
      {tabComp === 'proveedores' && (
        <div>

      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Facturas, remitos y notas de proveedores con seguimiento de saldo
      </div>

      {/* KPI pendiente */}
      {totalPendiente > 0 && !form && !formPago && (
        <div style={{ background:'#fff8f0', border:'1px solid #fed7aa', borderRadius:8, padding:'10px 16px', marginBottom:14, fontSize:13 }}>
          ⚠️ Saldo total pendiente de pago: <strong style={{ color:RJ }}>{fmt(totalPendiente)}</strong>
        </div>
      )}

      <Msg data={msg} />

      {form && (
        <FormComp
          form={form} setForm={setForm}
          guardar={guardar} guardando={guardando}
          proveedores={proveedores} expensas={expensas}
          extraerFacturaConIA={extraerFacturaConIA}
          extrayendoIA={extrayendoIA} archivoFactura={archivoFactura}
        />
      )}
      {formPago && (
        <FormPago
          formPago={formPago} setFormPago={setFormPago}
          pagarComprobante={pagarComprobante}
          proveedores={proveedores}
        />
      )}

      {/* Filtros */}
      <Card style={{ marginBottom:12 }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10, marginBottom:8 }}>
          <Sel label="Filtrar por proveedor" value={filtro} onChange={setFiltro}
            opts={[{v:'',l:'Todos los proveedores'},...proveedores.map(p=>({v:p.id,l:p.razon_social}))]} />
          <Sel label="Estado" value={filtroEstado} onChange={setFiltroEstado}
            opts={[{v:'',l:'Todos los estados'},{v:'pendiente',l:'Pendiente'},{v:'pagado_parcial',l:'Pago parcial'},{v:'pagado',l:'Pagado'},{v:'anulado',l:'Anulado'}]} />
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Buscar</div>
            <div style={{ position:'relative' }}>
              <span style={{ position:'absolute', left:9, top:'50%', transform:'translateY(-50%)', color:GR, fontSize:13 }}>🔍</span>
              <input value={busquedaComp} onChange={e=>setBusquedaComp(e.target.value)} placeholder="Concepto, N° comprobante..."
                style={{ width:'100%', paddingLeft:30, padding:'7px 10px 7px 30px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
          </div>
        </div>
        <div style={{ display:'flex', gap:8, alignItems:'center' }}>
          <Btn small color={GR} onClick={handlePDFComp}>🖨️ PDF</Btn>
          <Btn small color={VD} onClick={handleExcelComp}>📊 Excel</Btn>
          {(filtro||filtroEstado||busquedaComp) && (
            <Btn small onClick={()=>{setFiltro('');setFiltroEstado('');setBusquedaComp('')}} style={{ background:'#fee2e2', color:RJ }}>✕ Limpiar filtros</Btn>
          )}
          <span style={{ fontSize:11, color:GR, marginLeft:4 }}>
            {compsFiltrados.length} comprobante{compsFiltrados.length!==1?'s':''}
            {totalPendiente > 0 && <span style={{ color:RJ, marginLeft:8 }}>· Saldo pendiente: {fmt(totalPendiente)}</span>}
          </span>
        </div>
      </Card>

      {/* Tabla */}
      <Card>
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead>
              <tr style={{ background:'#f3f4f6' }}>
                {['Fecha','Vto.','Proveedor','Tipo','N°','Concepto','Total','Saldo','Estado','Acciones'].map((h,i) => (
                  <th key={i} style={{ padding:'7px 10px', textAlign:i>=6&&i<=7?'right':'left',
                    fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb', whiteSpace:'nowrap' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {compsFiltrados.length === 0 ? (
                <tr><td colSpan={10} style={{ padding:24, textAlign:'center', color:GR }}>Sin comprobantes{(filtro||filtroEstado||busquedaComp)?' que coincidan con los filtros':' registrados'}</td></tr>
              ) : compsFiltrados.map(c => {
                const prov = proveedores.find(p=>p.id===c.proveedor_id)
                const est  = ESTADOS_COLOR[c.estado] || ESTADOS_COLOR.pendiente
                const vencido = c.fecha_vencimiento && c.fecha_vencimiento < hoy && c.estado !== 'pagado' && c.estado !== 'anulado'
                return (
                  <tr key={c.id} style={{ borderBottom:'1px solid #f3f4f6', opacity:c.estado==='anulado'?0.45:1,
                    background: formPago?.comp?.id===c.id ? '#f0fdf4' : 'transparent' }}>
                    <td style={{ padding:'7px 10px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>{fmtD(c.fecha)}</td>
                    <td style={{ padding:'7px 10px', whiteSpace:'nowrap', fontSize:11,
                      color:vencido?RJ:GR, fontWeight:vencido?700:400 }}>
                      {c.fecha_vencimiento ? fmtD(c.fecha_vencimiento) : '—'}
                      {vencido && <span style={{ fontSize:9, display:'block' }}>⚠ VENCIDO</span>}
                    </td>
                    <td style={{ padding:'7px 10px', fontWeight:600, maxWidth:130 }}>{prov?.razon_social||'—'}</td>
                    <td style={{ padding:'7px 10px', textTransform:'capitalize', color:GR }}>{c.tipo}</td>
                    <td style={{ padding:'7px 10px', fontSize:11, color:GR }}>{c.numero||'—'}</td>
                    <td style={{ padding:'7px 10px', maxWidth:150 }}>{c.concepto}</td>
                    <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:600 }}>{fmt(c.monto_total)}</td>
                    <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700,
                      color: parseFloat(c.saldo_pendiente)>0 ? RJ : VD }}>
                      {c.estado==='pagado' ? '✓ Pagado' : fmt(c.saldo_pendiente)}
                    </td>
                    <td style={{ padding:'7px 10px' }}>
                      <Badge text={est.t} color={est.c} bg={est.bg} />
                    </td>
                    <td style={{ padding:'7px 10px' }}>
                      <div style={{ display:'flex', gap:4, flexWrap:'wrap' }}>
                        {/* Pagar aquí */}
                        {(c.estado==='pendiente'||c.estado==='pagado_parcial') && (
                          <Btn small color={VD} title="Registrar pago" onClick={()=>{
                            setFormPago({ comp:c, monto:c.saldo_pendiente, fecha:hoy, medio_pago:'transferencia' })
                            setForm(null)
                            setTimeout(()=>document.querySelector('[data-formPago]')?.scrollIntoView({behavior:'smooth'}),100)
                          }}>💸 Pagar</Btn>
                        )}
                        {/* Editar */}
                        {c.estado !== 'anulado' && (
                          <Btn small title="Editar" onClick={()=>{ setForm({...c}); setFormPago(null) }}
                            style={{ background:'#f3f4f6', color:'#374151' }}>✏</Btn>
                        )}
                        {/* Anular */}
                        {c.estado !== 'anulado' && c.estado !== 'pagado' && (
                          <Btn small title="Anular" onClick={()=>anular(c.id)} style={{ background:'#fff3cd', color:AM }}>⊘</Btn>
                        )}
                        {/* Eliminar */}
                        <Btn small title="Eliminar" onClick={()=>eliminar(c.id)} style={{ background:'#fee2e2', color:RJ }}>✕</Btn>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </Card>
        </div>
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// PAGOS A PROVEEDORES
// ══════════════════════════════════════════════════════════════════════════════
function PagosProveedor({ session, consorcioId, proveedores }) {
  const [pagos, setPagos]         = useState([])
  const [compPendientes, setCompPendientes] = useState([])
  const [form, setForm]           = useState(null)
  const [filtro, setFiltro]       = useState('')
  const [msg, setMsg]             = useState(null)
  const [guardando, setGuardando] = useState(false)
  const hoy = new Date().toISOString().split('T')[0]

  async function cargar() {
    const [{ data: p }, { data: cp }] = await Promise.all([
      supabase.from('con_pagos_proveedor').select('*')
        .eq('consorcio_id', consorcioId).order('fecha', { ascending:false }).limit(200),
      supabase.from('con_comprobantes_proveedor').select('*')
        .eq('consorcio_id', consorcioId)
        .in('estado', ['pendiente','pagado_parcial'])
        .order('fecha_vencimiento', { ascending:true })
    ])
    setPagos(p||[])
    setCompPendientes(cp||[])
  }

  async function guardar() {
    if (!form?.proveedor_id) return setMsg({ tipo:'warn', texto:'Seleccioná un proveedor' })
    if (!form?.monto || parseFloat(form.monto)<=0) return setMsg({ tipo:'warn', texto:'Ingresá el monto' })
    if (!form?.fecha) return setMsg({ tipo:'warn', texto:'Ingresá la fecha' })
    setGuardando(true)
    const monto=parseFloat(form.monto)
    const retIIBB=parseFloat(form.retencion_iibb)||0
    const retGan=parseFloat(form.retencion_ganancias)||0
    const retIVA=parseFloat(form.retencion_iva)||0
    const neto=monto-retIIBB-retGan-retIVA
    if (form.id) {
      // Edición
      await supabase.from('con_pagos_proveedor').update({
        proveedor_id: form.proveedor_id, comprobante_id: form.comprobante_id||null,
        fecha: form.fecha, monto, retencion_iibb: retIIBB||null,
        retencion_ganancias: retGan||null, retencion_iva: retIVA||null,
        monto_neto_pagado: neto, nro_orden_pago: form.nro_orden_pago||null,
        medio_pago: form.medio_pago||'transferencia',
        referencia: form.referencia||null, notas: form.notas||null,
      }).eq('id', form.id)
      setMsg({ tipo:'ok', texto:'✓ Pago actualizado' })
    } else {
      const { error } = await supabase.from('con_pagos_proveedor').insert([{
        id: `PAG-${Date.now()}`,
        admin_id: session.user.id, consorcio_id: consorcioId,
        proveedor_id: form.proveedor_id, comprobante_id: form.comprobante_id || null,
        fecha: form.fecha, monto,
        retencion_iibb: retIIBB||null, retencion_ganancias: retGan||null,
        retencion_iva: retIVA||null, monto_neto_pagado: neto,
        nro_orden_pago: form.nro_orden_pago||null,
        medio_pago: form.medio_pago || 'transferencia',
        numero_cheque: form.numero_cheque || null,
        banco: form.banco || null, referencia: form.referencia || null,
        notas: form.notas || null,
      }])
      if (error) { setMsg({ tipo:'error', texto: error.message }); setGuardando(false); return }
      setMsg({ tipo:'ok', texto:'✓ Pago registrado' })
    }
    setForm(null); cargar()
    setGuardando(false)
  }

  async function eliminarPago(p) {
    if (!confirm(`¿Eliminar este pago de ${fmt(p.monto)}?\nSi estaba asociado a un comprobante, el saldo no se actualiza automáticamente.`)) return
    await supabase.from('con_pagos_proveedor').delete().eq('id', p.id)
    cargar()
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR')
  const fmtD = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'

  const MEDIOS = [
    {v:'transferencia',l:'Transferencia'},{v:'cheque_propio',l:'Cheque propio'},
    {v:'cheque_tercero',l:'Cheque de tercero'},{v:'efectivo',l:'Efectivo'},{v:'otro',l:'Otro'}
  ]

  const compsFiltro = compPendientes.filter(c =>
    !form?.proveedor_id || c.proveedor_id === form.proveedor_id
  )

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>💸 Pagos a proveedores</div>
        <Btn onClick={()=>setForm({ medio_pago:'transferencia', fecha:hoy })}>+ Registrar pago</Btn>
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Registre pagos de facturas y comprobantes pendientes
      </div>
      <Msg data={msg} />

      {/* Pendientes de pago */}
      {compPendientes.length > 0 && !form && (
        <Card style={{ marginBottom:16, background:'#fff8f0', border:'1px solid #fed7aa' }}>
          <div style={{ fontWeight:600, color:AM, fontSize:13, marginBottom:10 }}>
            ⚠️ {compPendientes.length} comprobante{compPendientes.length>1?'s':''} pendiente{compPendientes.length>1?'s':''} de pago
          </div>
          <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
            {compPendientes.slice(0,5).map(c => {
              const prov = proveedores.find(p=>p.id===c.proveedor_id)
              const vencido = c.fecha_vencimiento && c.fecha_vencimiento < hoy
              return (
                <div key={c.id} style={{ display:'flex', justifyContent:'space-between',
                  alignItems:'center', padding:'8px 10px', background:'#fff',
                  borderRadius:8, border: vencido?'1px solid #fca5a5':'1px solid #e5e7eb' }}>
                  <div>
                    <span style={{ fontWeight:600, fontSize:13 }}>{prov?.razon_social}</span>
                    <span style={{ fontSize:11, color:GR, marginLeft:8 }}>{c.concepto}</span>
                    {vencido && <span style={{ fontSize:10, color:RJ, marginLeft:8, fontWeight:600 }}>VENCIDO</span>}
                  </div>
                  <div style={{ display:'flex', gap:8, alignItems:'center' }}>
                    <span style={{ fontWeight:700, color:RJ }}>{fmt(c.saldo_pendiente)}</span>
                    <Btn small color={VD} onClick={()=>setForm({
                      medio_pago:'transferencia', fecha:hoy,
                      proveedor_id:c.proveedor_id, comprobante_id:c.id,
                      monto: c.saldo_pendiente
                    })}>Pagar</Btn>
                  </div>
                </div>
              )
            })}
          </div>
        </Card>
      )}

      {/* Formulario */}
      {form && (
        <Card style={{ marginBottom:16, border:'1.5px solid #86efac' }}>
          <div style={{ fontWeight:700, color:VD, fontSize:13, marginBottom:14 }}>{form.id?'✏ Editar pago':'💸 Registrar pago'}</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12, marginBottom:12 }}>
            <Sel label="Proveedor *" value={form.proveedor_id||''} onChange={v=>setForm(f=>({...f,proveedor_id:v,comprobante_id:''}))}
              opts={[{v:'',l:'— Seleccione —'},...proveedores.map(p=>({v:p.id,l:p.razon_social}))]} />
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Comprobante (opcional)</div>
              <select value={form.comprobante_id||''} onChange={e=>setForm(f=>({...f,comprobante_id:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, background:'#fff' }}>
                <option value="">Sin comprobante</option>
                {compsFiltro.map(c=>(
                  <option key={c.id} value={c.id}>{c.tipo} {c.numero||''} — ${Number(c.saldo_pendiente).toLocaleString('es-AR')}</option>
                ))}
              </select>
            </div>
            <Sel label="Medio de pago" value={form.medio_pago||'transferencia'} onChange={v=>setForm(f=>({...f,medio_pago:v}))} opts={MEDIOS} />
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12, marginBottom:12 }}>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Monto bruto *</div>
              <input type="number" min="0" step="0.01" value={form.monto||''}
                onChange={e=>setForm(f=>({...f,monto:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, fontWeight:700, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Fecha *</div>
              <input type="date" value={form.fecha||''} onChange={e=>setForm(f=>({...f,fecha:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Referencia / N° cheque</div>
              <input value={form.referencia||''} placeholder="Nro. operación, cheque, etc."
                onChange={e=>setForm(f=>({...f,referencia:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
          </div>
          {/* Retenciones */}
          <div style={{ background:'#f0fdf4', border:'1px solid #86efac', borderRadius:8, padding:'12px 14px', marginBottom:12 }}>
            <div style={{ fontSize:12, fontWeight:600, color:VD, marginBottom:10 }}>Retenciones impositivas (opcional)</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:10 }}>
              <div>
                <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Ret. IIBB $</div>
                <input type="number" min="0" step="0.01" value={form.retencion_iibb||''} onChange={e=>setForm(f=>({...f,retencion_iibb:e.target.value}))}
                  style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
              </div>
              <div>
                <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Ret. Ganancias $</div>
                <input type="number" min="0" step="0.01" value={form.retencion_ganancias||''} onChange={e=>setForm(f=>({...f,retencion_ganancias:e.target.value}))}
                  style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
              </div>
              <div>
                <div style={{ fontSize:11, color:GR, marginBottom:3 }}>Ret. IVA $</div>
                <input type="number" min="0" step="0.01" value={form.retencion_iva||''} onChange={e=>setForm(f=>({...f,retencion_iva:e.target.value}))}
                  style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
              </div>
              <div>
                <div style={{ fontSize:11, color:GR, marginBottom:3 }}>N° Orden de pago</div>
                <input value={form.nro_orden_pago||''} onChange={e=>setForm(f=>({...f,nro_orden_pago:e.target.value}))}
                  style={{ width:'100%', padding:'7px 9px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12, boxSizing:'border-box' }} />
              </div>
            </div>
            {(form.monto && (form.retencion_iibb||form.retencion_ganancias||form.retencion_iva)) && (
              <div style={{ marginTop:10, fontSize:13, fontWeight:700, color:VD }}>
                Neto a pagar: {fmt((parseFloat(form.monto)||0)-(parseFloat(form.retencion_iibb)||0)-(parseFloat(form.retencion_ganancias)||0)-(parseFloat(form.retencion_iva)||0))}
              </div>
            )}
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <Btn onClick={guardar} disabled={guardando} style={{ background:VD, color:'#fff' }}>{guardando?'⏳':'✓ Registrar pago'}</Btn>
            <BtnSec onClick={()=>{setForm(null);setMsg(null)}}>Cancelar</BtnSec>
          </div>
        </Card>
      )}

      {/* Historial */}
      <Card>
        <div style={{ fontWeight:600, fontSize:13, marginBottom:12 }}>Historial de pagos</div>
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead>
              <tr style={{ background:'#f3f4f6' }}>
                {['Fecha','Proveedor','Concepto/Comp.','Medio','Monto','Acciones'].map((h,i) => (
                  <th key={i} style={{ padding:'7px 10px', textAlign:i===4?'right':'left',
                    fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {pagos.length === 0 ? (
                <tr><td colSpan={5} style={{ padding:24, textAlign:'center', color:GR }}>Sin pagos registrados</td></tr>
              ) : pagos.map(p => {
                const prov = proveedores.find(pr=>pr.id===p.proveedor_id)
                const comp = compPendientes.find(c=>c.id===p.comprobante_id)
                return (
                  <tr key={p.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                    <td style={{ padding:'7px 10px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>{fmtD(p.fecha)}</td>
                    <td style={{ padding:'7px 10px', fontWeight:600 }}>{prov?.razon_social||'—'}</td>
                    <td style={{ padding:'7px 10px', color:GR, fontSize:11 }}>
                      {comp ? `${comp.tipo} ${comp.numero||''}` : p.referencia||'—'}
                    </td>
                    <td style={{ padding:'7px 10px', textTransform:'capitalize', color:GR }}>{p.medio_pago?.replace('_',' ')}</td>
                    <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700, color:VD }}>{fmt(p.monto)}</td>
                    <td style={{ padding:'7px 10px' }}>
                      <div style={{ display:'flex', gap:4 }}>
                        <Btn small onClick={()=>setForm({...p})} style={{ background:'#f3f4f6', color:'#374151' }} title="Editar">✏</Btn>
                        <Btn small onClick={()=>eliminarPago(p)} style={{ background:'#fee2e2', color:RJ }} title="Eliminar">✕</Btn>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </Card>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// CUENTA CORRIENTE POR PROVEEDOR
// ══════════════════════════════════════════════════════════════════════════════
function CtaProveedor({ session, consorcioId, proveedores }) {
  const [provSel, setProvSel] = useState('')
  const [comps, setComps]     = useState([])
  const [pagos, setPagos]     = useState([])
  const [cargando, setCargando] = useState(false)

  async function cargar(pid) {
    if (!pid) return
    setCargando(true)
    const [{ data:c }, { data:p }] = await Promise.all([
      supabase.from('con_comprobantes_proveedor').select('*')
        .eq('proveedor_id', pid).eq('consorcio_id', consorcioId)
        .order('fecha', { ascending:true }),
      supabase.from('con_pagos_proveedor').select('*')
        .eq('proveedor_id', pid).eq('consorcio_id', consorcioId)
        .order('fecha', { ascending:true }),
    ])
    setComps(c||[])
    setPagos(p||[])
    setCargando(false)
  }

  useEffect(() => { if (provSel) cargar(provSel) }, [provSel])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2 })
  const fmtD = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'
  const [fDesde, setFDesde] = useState('')
  const [fHasta, setFHasta] = useState('')

  const totalDeuda    = comps.filter(c=>c.estado!=='anulado').reduce((a,c)=>a+(parseFloat(c.monto_total)||0),0)
  const totalPagado   = pagos.reduce((a,p)=>a+(parseFloat(p.monto)||0),0)
  const saldoAdeudado = Math.max(0, totalDeuda - totalPagado)
  const prov = proveedores.find(p=>p.id===provSel)

  // Construir movimientos combinados con filtro por fechas
  const movs = [
    ...comps.filter(c=>c.estado!=='anulado').map(c=>({ fecha:c.fecha, tipo:'debito', concepto:`${c.tipo} ${c.numero||''} — ${c.concepto}`, monto:parseFloat(c.monto_total)||0 })),
    ...pagos.map(p=>({ fecha:p.fecha, tipo:'credito', concepto:`Pago — ${p.medio_pago?.replace('_',' ')||''}${p.referencia?' ('+p.referencia+')':''}`, monto:parseFloat(p.monto)||0 })),
  ].sort((a,b)=>(a.fecha||'').localeCompare(b.fecha||''))
   .filter(m=>(!fDesde||m.fecha>=fDesde)&&(!fHasta||m.fecha<=fHasta))

  let acc = 0
  const conSaldo = movs.map(m => {
    if (m.tipo==='debito')  acc += m.monto
    if (m.tipo==='credito') acc -= m.monto
    return { ...m, saldo_acum: acc }
  })

  function handlePDFCta(){
    exportarPDF({titulo:`Cuenta Corriente — ${prov?.razon_social||'Proveedor'}`,logoB64:LOGO_ADM_B64,
      columnas:[{key:'fecha',label:'Fecha',nowrap:true},{key:'concepto',label:'Concepto'},
        {key:'debito',label:'Débito',align:'right'},{key:'credito',label:'Crédito',align:'right'},{key:'saldo',label:'Saldo',align:'right'}],
      filas:conSaldo.map(m=>({fecha:fmtD(m.fecha),concepto:m.concepto,
        debito:m.tipo==='debito'?fmt(m.monto):'',credito:m.tipo==='credito'?fmt(m.monto):'',
        saldo:fmt(Math.abs(m.saldo_acum))+(m.saldo_acum<0?' CR':'')})),
      totales:{fecha:'',concepto:'Saldo adeudado',debito:fmt(totalDeuda),credito:fmt(totalPagado),saldo:fmt(saldoAdeudado)}
    })
  }
  function handleExcelCta(){
    exportarExcel({titulo:`Cta-Cte-${prov?.razon_social||'Proveedor'}`,
      columnas:[{key:'fecha',label:'Fecha'},{key:'concepto',label:'Concepto'},{key:'tipo',label:'Tipo'},
        {key:'debito',label:'Débito'},{key:'credito',label:'Crédito'},{key:'saldo',label:'Saldo Acum.'}],
      filas:conSaldo.map(m=>({fecha:m.fecha,concepto:m.concepto,tipo:m.tipo==='debito'?'Débito':'Crédito',
        debito:m.tipo==='debito'?m.monto:'',credito:m.tipo==='credito'?m.monto:'',saldo:m.saldo_acum}))
    })
  }

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>📊 Cuenta corriente proveedor</div>
      <div style={{ fontSize:12, color:GR, marginBottom:12 }}>Comprobantes, pagos y saldo adeudado por proveedor</div>

      <Card style={{ marginBottom:12 }}>
        <Sel label="Proveedor" value={provSel} onChange={v=>{setProvSel(v);setFDesde('');setFHasta('')}}
          opts={[{v:'',l:'— Seleccione proveedor —'},...proveedores.map(p=>({v:p.id,l:p.razon_social}))]} />
      </Card>

      {provSel && (
        <>
          {/* Info proveedor + KPIs */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12, marginBottom:12 }}>
            <div style={{ background: saldoAdeudado>0?'#fee2e2':'#dcfce7', borderRadius:10, padding:'14px 18px', textAlign:'center' }}>
              <div style={{ fontSize:11, fontWeight:600, color:saldoAdeudado>0?RJ:VD, textTransform:'uppercase', marginBottom:4 }}>Saldo adeudado</div>
              <div style={{ fontSize:22, fontWeight:800, color:saldoAdeudado>0?RJ:VD }}>
                {saldoAdeudado>0 ? fmt(saldoAdeudado) : '✓ Sin deuda'}
              </div>
            </div>
            <div style={{ background:'#fff', borderRadius:10, padding:'14px 18px', textAlign:'center', boxShadow:'0 1px 6px #0001' }}>
              <div style={{ fontSize:11, fontWeight:600, color:GR, textTransform:'uppercase', marginBottom:4 }}>Total facturado</div>
              <div style={{ fontSize:20, fontWeight:700, color:RJ }}>{fmt(totalDeuda)}</div>
            </div>
            <div style={{ background:'#fff', borderRadius:10, padding:'14px 18px', textAlign:'center', boxShadow:'0 1px 6px #0001' }}>
              <div style={{ fontSize:11, fontWeight:600, color:GR, textTransform:'uppercase', marginBottom:4 }}>Total pagado</div>
              <div style={{ fontSize:20, fontWeight:700, color:VD }}>{fmt(totalPagado)}</div>
            </div>
          </div>

          {/* Filtros CtaProveedor */}
          <div style={{ display:'flex', gap:8, marginBottom:10, flexWrap:'wrap', alignItems:'center' }}>
            <div style={{ fontSize:12, color:GR, display:'flex', gap:6, alignItems:'center' }}>
              <span>Desde</span>
              <input type="date" value={fDesde} onChange={e=>setFDesde(e.target.value)} style={{ padding:'6px 8px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12 }} />
              <span>hasta</span>
              <input type="date" value={fHasta} onChange={e=>setFHasta(e.target.value)} style={{ padding:'6px 8px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12 }} />
              {(fDesde||fHasta) && <Btn small onClick={()=>{setFDesde('');setFHasta('')}} style={{ background:'#fee2e2', color:RJ }}>✕</Btn>}
            </div>
            <Btn small color={GR} onClick={handlePDFCta}>🖨️ PDF</Btn>
            <Btn small color={VD} onClick={handleExcelCta}>📊 Excel</Btn>
          </div>

          <Card>
            {cargando ? (
              <div style={{ textAlign:'center', padding:24, color:GR }}>⏳ Cargando...</div>
            ) : conSaldo.length===0 ? (
              <div style={{ textAlign:'center', padding:24, color:GR }}>Sin movimientos para este proveedor{(fDesde||fHasta)?' en el rango seleccionado':''}</div>
            ) : (
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                  <thead>
                    <tr style={{ background:'#f3f4f6' }}>
                      {['Fecha','Concepto','Débito','Crédito','Saldo'].map((h,i)=>(
                        <th key={i} style={{ padding:'7px 10px', textAlign:i>=2?'right':'left',
                          fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {conSaldo.map((m,i)=>(
                      <tr key={i} style={{ borderBottom:'1px solid #f3f4f6' }}>
                        <td style={{ padding:'7px 10px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>{fmtD(m.fecha)}</td>
                        <td style={{ padding:'7px 10px' }}>{m.concepto}</td>
                        <td style={{ padding:'7px 10px', textAlign:'right', color:RJ, fontWeight:600 }}>{m.tipo==='debito'?fmt(m.monto):''}</td>
                        <td style={{ padding:'7px 10px', textAlign:'right', color:VD, fontWeight:600 }}>{m.tipo==='credito'?fmt(m.monto):''}</td>
                        <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700, color:m.saldo_acum>0?RJ:VD }}>
                          {fmt(Math.abs(m.saldo_acum))}{m.saldo_acum<0&&<span style={{fontSize:9,marginLeft:2}}>CR</span>}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr style={{ background:'#f0f4ff', borderTop:'2px solid #1A3FA0' }}>
                      <td colSpan={2} style={{ padding:'8px 10px', fontWeight:700, color:AZ }}>Saldo final</td>
                      <td colSpan={3} style={{ padding:'8px 10px', textAlign:'right', fontWeight:800, fontSize:15, color:saldoAdeudado>0?RJ:VD }}>
                        {saldoAdeudado>0 ? `Debe ${fmt(saldoAdeudado)}` : 'Sin deuda'}
                      </td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </Card>
        </>
      )}
    </div>
  )
}

function CtaCorriente({ session, consorcioId, unidades, copropietarios }) {
  const [ufSel, setUfSel]       = useState('')
  const [movs, setMovs]         = useState([])
  const [cargando, setCargando] = useState(false)
  const [saldo, setSaldo]       = useState(0)
  const [fDesde, setFDesde]     = useState('')
  const [fHasta, setFHasta]     = useState('')

  // ── v56: CC calculada en el servidor por get-cuenta-corriente ─────────
  // Elimina toda la lógica financiera del cliente. El servidor determina
  // automáticamente el modelo (normal/historico/mixto) según modelo_cc
  // del consorcio y devuelve las líneas ya ordenadas con saldo acumulado.
  const [modeloCC, setModeloCC] = useState('')

  async function cargarMovimientos(uid) {
    if (!uid) return
    setCargando(true)
    try {
      const { data: { session: sess } } = await supabase.auth.getSession()
      const res = await fetch(`${SUPA_URL}/functions/v1/get-cuenta-corriente`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${sess?.access_token}`,
          'apikey': process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
        },
        body: JSON.stringify({ unidad_id: uid })
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || 'Error calculando cuenta corriente')
      setMovs(data.lineas || [])
      setSaldo(data.saldo_total || 0)
      setModeloCC(data.modelo || '')
    } catch (err) {
      console.error('[CtaCorriente] Error:', err)
      setMovs([])
      setSaldo(0)
    } finally {
      setCargando(false)
    }
  }

  useEffect(() => { if (ufSel) cargarMovimientos(ufSel) }, [ufSel])

  const uf  = unidades.find(u => u.id === ufSel)
  const cp  = copropietarios.find(c => c.id === uf?.propietario_id)
  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2, maximumFractionDigits:2 })
  const fmtD = d => d ? new Date(d+'T00:00:00').toLocaleDateString('es-AR') : '—'

  // Movimientos filtrados por rango de fechas
  const movsFiltrados = movs.filter(m =>
    (!fDesde || (m.fecha||'') >= fDesde) && (!fHasta || (m.fecha||'') <= fHasta)
  )
  // Recalcular saldo acumulado sobre los filtrados
  let accF = 0
  const movsConSaldoFiltrado = movsFiltrados.map(m => {
    if (m.tipo === 'debito')  accF += m.monto
    if (m.tipo === 'credito') accF -= m.monto
    return { ...m, saldo_acum: accF }
  })
  const totalDebitosFil  = movsFiltrados.filter(m=>m.tipo==='debito').reduce((a,m)=>a+m.monto,0)
  const totalCreditosFil = movsFiltrados.filter(m=>m.tipo==='credito').reduce((a,m)=>a+m.monto,0)

  function handlePDFCtaCorriente() {
    exportarPDF({
      titulo: `Cuenta Corriente UF — ${uf?.numero||''} — ${cp?.apellido_nombre||''}`,
      subtitulo: (fDesde||fHasta) ? `Período: ${fDesde?fmtD(fDesde):'inicio'} al ${fHasta?fmtD(fHasta):'hoy'}` : 'Historial completo',
      consorcioNombre: '',
      logoB64: LOGO_ADM_B64,
      columnas: [
        { key:'fecha',    label:'Fecha',   nowrap:true },
        { key:'concepto', label:'Concepto' },
        { key:'debito',   label:'Débito',  align:'right' },
        { key:'credito',  label:'Crédito', align:'right' },
        { key:'saldo',    label:'Saldo',   align:'right' },
      ],
      filas: movsConSaldoFiltrado.map(m => ({
        fecha:   fmtD(m.fecha),
        concepto: m.concepto + (m.nro ? ` — N° ${m.nro}` : ''),
        debito:  m.tipo==='debito'  ? fmt(m.monto) : '',
        credito: m.tipo==='credito' ? fmt(m.monto) : '',
        saldo:   fmt(Math.abs(m.saldo_acum)) + (m.saldo_acum < 0 ? ' CR' : ''),
      })),
      totales: {
        fecha:'', concepto:'Saldo final',
        debito: fmt(totalDebitosFil), credito: fmt(totalCreditosFil),
        saldo: accF > 0 ? `Debe ${fmt(accF)}` : `A favor ${fmt(Math.abs(accF))}`,
      }
    })
  }

  function handleExcelCtaCorriente() {
    exportarExcel({
      titulo: `CtaCte-UF-${uf?.numero||''}`,
      columnas: [
        { key:'fecha',    label:'Fecha' },
        { key:'concepto', label:'Concepto' },
        { key:'tipo',     label:'Tipo' },
        { key:'debito',   label:'Débito' },
        { key:'credito',  label:'Crédito' },
        { key:'saldo',    label:'Saldo Acum.' },
      ],
      filas: movsConSaldoFiltrado.map(m => ({
        fecha:   m.fecha,
        concepto: m.concepto + (m.nro ? ` — N° ${m.nro}` : ''),
        tipo:    m.tipo === 'debito' ? 'Débito' : 'Crédito',
        debito:  m.tipo==='debito'  ? m.monto : '',
        credito: m.tipo==='credito' ? m.monto : '',
        saldo:   m.saldo_acum,
      }))
    })
  }

  return (
    <div>
      <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>📋 Cuenta corriente por unidad</div>
        {modeloCC && (
          <span style={{
            fontSize:10, fontWeight:700, padding:'2px 8px', borderRadius:12,
            background: modeloCC==='historico' ? '#dbeafe' : modeloCC==='mixto' ? '#fef3c7' : '#dcfce7',
            color:       modeloCC==='historico' ? '#1d4ed8' : modeloCC==='mixto' ? '#92400e' : '#166534',
            textTransform:'uppercase', letterSpacing:'0.05em'
          }}>
            {modeloCC==='historico' ? '📂 Histórico' : modeloCC==='mixto' ? '⚡ Mixto' : '✓ Normal'}
          </span>
        )}
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Historial completo de débitos, créditos y saldo por unidad funcional
      </div>

      <Card style={{ marginBottom:16 }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, alignItems:'end' }}>
          <Sel label="Unidad funcional" value={ufSel} onChange={v=>{setUfSel(v);setFDesde('');setFHasta('')}}
            opts={[{ v:'', l:'— Seleccione UF —' },
              ...unidades.map(u => {
                const cp2 = copropietarios.find(c => c.id === u.propietario_id)
                return { v: u.id, l: `${u.numero} — ${cp2?.apellido_nombre||'Sin propietario'}` }
              })
            ]} />
          {uf && (
            <div style={{ padding:'10px 14px', background:'#f0f4ff', borderRadius:8, fontSize:13 }}>
              <strong>{cp?.apellido_nombre||'—'}</strong>
              <div style={{ fontSize:11, color:GR }}>
                {uf.tipo} {uf.piso ? `· Piso ${uf.piso}` : ''}
                {uf.porcentaje_fiscal ? ` · Coef: ${Number(uf.porcentaje_fiscal).toFixed(4)}%` : ''}
              </div>
            </div>
          )}
        </div>
      </Card>

      {ufSel && (
        <>
          {/* KPI saldo */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12, marginBottom:12 }}>
            <div style={{ background: accF > 0 ? '#fee2e2' : '#dcfce7', borderRadius:10,
              padding:'14px 18px', textAlign:'center' }}>
              <div style={{ fontSize:11, color: accF > 0 ? RJ : VD, fontWeight:600,
                textTransform:'uppercase', marginBottom:4 }}>
                Saldo{(fDesde||fHasta)?' (filtrado)':' actual'}
              </div>
              <div style={{ fontSize:22, fontWeight:800, color: accF > 0 ? RJ : VD }}>
                {accF > 0 ? fmt(accF) : '✓ Al día'}
              </div>
            </div>
            <div style={{ background:'#fff', borderRadius:10, padding:'14px 18px',
              textAlign:'center', boxShadow:'0 1px 6px #0001' }}>
              <div style={{ fontSize:11, color:GR, fontWeight:600, textTransform:'uppercase', marginBottom:4 }}>
                Total débitos
              </div>
              <div style={{ fontSize:20, fontWeight:700, color:RJ }}>
                {fmt(totalDebitosFil)}
              </div>
            </div>
            <div style={{ background:'#fff', borderRadius:10, padding:'14px 18px',
              textAlign:'center', boxShadow:'0 1px 6px #0001' }}>
              <div style={{ fontSize:11, color:GR, fontWeight:600, textTransform:'uppercase', marginBottom:4 }}>
                Total créditos
              </div>
              <div style={{ fontSize:20, fontWeight:700, color:VD }}>
                {fmt(totalCreditosFil)}
              </div>
            </div>
          </div>

          {/* Filtros por fecha + exportación */}
          <div style={{ display:'flex', gap:8, marginBottom:12, flexWrap:'wrap', alignItems:'center' }}>
            <div style={{ fontSize:12, color:GR, display:'flex', gap:6, alignItems:'center' }}>
              <span>Desde</span>
              <input type="date" value={fDesde} onChange={e=>setFDesde(e.target.value)}
                style={{ padding:'6px 8px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12 }} />
              <span>hasta</span>
              <input type="date" value={fHasta} onChange={e=>setFHasta(e.target.value)}
                style={{ padding:'6px 8px', border:'1px solid #d1d5db', borderRadius:6, fontSize:12 }} />
              {(fDesde||fHasta) && (
                <Btn small onClick={()=>{setFDesde('');setFHasta('')}} style={{ background:'#fee2e2', color:RJ }}>✕</Btn>
              )}
            </div>
            <Btn small color={GR} onClick={handlePDFCtaCorriente}>🖨️ PDF</Btn>
            <Btn small color={VD} onClick={handleExcelCtaCorriente}>📊 Excel</Btn>
          </div>

          {/* Tabla */}
          <Card>
            {cargando ? (
              <div style={{ textAlign:'center', padding:24, color:GR }}>⏳ Cargando...</div>
            ) : movsConSaldoFiltrado.length === 0 ? (
              <div style={{ textAlign:'center', padding:24, color:GR }}>
                {movs.length === 0 ? 'Sin movimientos registrados' : 'Sin movimientos en el rango seleccionado'}
              </div>
            ) : (
              <div style={{ overflowX:'auto' }}>
                <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
                  <thead>
                    <tr style={{ background:'#f3f4f6' }}>
                      {['Fecha','Concepto','Débito','Crédito','Saldo'].map((h,i) => (
                        <th key={i} style={{ padding:'7px 10px', textAlign: i>=2?'right':'left',
                          fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb',
                          whiteSpace:'nowrap' }}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {movsConSaldoFiltrado.map((m, i) => (
                      <tr key={i} style={{ borderBottom:'1px solid #f3f4f6',
                        background: m.origen==='mora' ? '#fff8f0' : 'transparent' }}>
                        <td style={{ padding:'7px 10px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>
                          {m.fecha ? new Date(m.fecha+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                        </td>
                        <td style={{ padding:'7px 10px' }}>
                          <div style={{ fontWeight: m.origen==='expensa'?600:400 }}>{m.concepto}</div>
                          {m.nro && <div style={{ fontSize:10, color:GR }}>N° {m.nro}</div>}
                        </td>
                        <td style={{ padding:'7px 10px', textAlign:'right', color:RJ, fontWeight:600 }}>
                          {m.tipo==='debito' ? fmt(m.monto) : ''}
                        </td>
                        <td style={{ padding:'7px 10px', textAlign:'right', color:VD, fontWeight:600 }}>
                          {m.tipo==='credito' ? fmt(m.monto) : ''}
                        </td>
                        <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700,
                          color: m.saldo_acum > 0 ? RJ : VD }}>
                          {fmt(Math.abs(m.saldo_acum))}
                          {m.saldo_acum < 0 && <span style={{ fontSize:9, marginLeft:2 }}>CR</span>}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr style={{ background:'#f0f4ff', borderTop:'2px solid #1A3FA0' }}>
                      <td colSpan={2} style={{ padding:'8px 10px', fontWeight:700, color:AZ }}>
                        Saldo final{(fDesde||fHasta)?' (período filtrado)':''}
                      </td>
                      <td colSpan={3} style={{ padding:'8px 10px', textAlign:'right',
                        fontWeight:800, fontSize:15, color: accF > 0 ? RJ : VD }}>
                        {accF > 0 ? `Debe ${fmt(accF)}` : `A favor ${fmt(Math.abs(accF))}`}
                      </td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </Card>
        </>
      )}
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// MOVIMIENTOS POR UNIDAD — Notas de débito y crédito
// ══════════════════════════════════════════════════════════════════════════════
function MovimientosUnidad({ session, consorcioId, unidades, copropietarios, expensas }) {
  const [form, setForm]       = useState(null)
  const [movs, setMovs]       = useState([])
  const [filtroUF, setFiltroUF] = useState('')
  const [msg, setMsg]         = useState(null)
  const [guardando, setGuardando] = useState(false)

  async function cargar() {
    const q = supabase.from('con_movimientos_unidad').select('*')
      .eq('consorcio_id', consorcioId).order('created_at', { ascending: false }).limit(100)
    if (filtroUF) q.eq('unidad_id', filtroUF)
    const { data } = await q
    setMovs(data || [])
  }

  async function guardar() {
    if (!form?.unidad_id)  return setMsg({ tipo:'warn', texto:'Seleccioná una unidad' })
    if (!form?.tipo)        return setMsg({ tipo:'warn', texto:'Seleccioná el tipo' })
    if (!form?.concepto?.trim()) return setMsg({ tipo:'warn', texto:'Ingresá el concepto' })
    if (!form?.monto || parseFloat(form.monto) <= 0) return setMsg({ tipo:'warn', texto:'Ingresá un monto válido' })
    if (!form?.fecha)       return setMsg({ tipo:'warn', texto:'Ingresá la fecha' })

    setGuardando(true)
    const { error } = await supabase.from('con_movimientos_unidad').insert([{
      id: `MOV-${Date.now()}`,
      admin_id: session.user.id,
      consorcio_id: consorcioId,
      unidad_id: form.unidad_id,
      expensa_id: form.expensa_id || null,
      tipo: form.tipo,
      concepto: form.concepto.trim(),
      categoria: form.categoria || 'varios',
      monto: parseFloat(form.monto),
      fecha: form.fecha,
      fecha_vencimiento: form.fecha_vencimiento || null,
      numero_comprobante: form.numero_comprobante || null,
      notas: form.notas || null,
      estado: 'vigente',
    }])

    if (error) {
      setMsg({ tipo:'error', texto: 'Error: ' + error.message })
    } else {
      setMsg({ tipo:'ok', texto: `✓ ${form.tipo === 'debito' ? 'Nota de débito' : 'Nota de crédito'} registrada` })
      setForm(null)
      cargar()
    }
    setGuardando(false)
  }

  async function anular(id) {
    if (!confirm('¿Anular este movimiento?')) return
    await supabase.from('con_movimientos_unidad')
      .update({ estado:'anulado', anulado_por: session.user.id })
      .eq('id', id)
    cargar()
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId, filtroUF])

  const fmt = n => '$' + (Number(n)||0).toLocaleString('es-AR')
  const hoy = new Date().toISOString().split('T')[0]

  const CATEGORIAS = [
    { v:'ajuste_inicial',  l:'Ajuste inicial / saldo anterior' },
    { v:'gasto_directo',   l:'Gasto directo a unidad' },
    { v:'interes',         l:'Quita / ajuste de interés' },
    { v:'convenio_pago',   l:'Convenio de pago' },
    { v:'reintegro',       l:'Reintegro de gasto' },
    { v:'varios',          l:'Varios' },
  ]

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>↕️ Notas de débito / crédito</div>
        <div style={{ display:'flex', gap:8 }}>
          <Btn small color={RJ} onClick={() => setForm({ tipo:'debito',  fecha: hoy })}>+ Débito</Btn>
          <Btn small color={VD} onClick={() => setForm({ tipo:'credito', fecha: hoy })}>+ Crédito</Btn>
        </div>
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Ajustes directos en la cuenta corriente de una unidad funcional
      </div>
      <Msg data={msg} />

      {/* Formulario */}
      {form && (
        <Card style={{ marginBottom:16, border:`1.5px solid ${form.tipo==='debito'?'#fca5a5':'#86efac'}`,
          background: form.tipo==='debito' ? '#fff8f8' : '#f0fdf4' }}>
          <div style={{ fontWeight:700, color: form.tipo==='debito'?RJ:VD, fontSize:13, marginBottom:14 }}>
            {form.tipo === 'debito' ? '📤 Nueva nota de débito' : '📥 Nueva nota de crédito'}
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:12 }}>
            <Sel label="Unidad" value={form.unidad_id||''} onChange={v => setForm(f => ({...f, unidad_id:v}))}
              opts={[{ v:'', l:'— Seleccione UF —' },
                ...unidades.map(u => {
                  const cp2 = copropietarios.find(c => c.id === u.propietario_id)
                  return { v:u.id, l:`${u.numero} — ${cp2?.apellido_nombre||'Sin prop.'}` }
                })
              ]} />
            <Sel label="Categoría" value={form.categoria||'varios'} onChange={v => setForm(f => ({...f, categoria:v}))}
              opts={CATEGORIAS} />
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'2fr 1fr 1fr', gap:12, marginBottom:12 }}>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Concepto *</div>
              <input value={form.concepto||''} onChange={e => setForm(f => ({...f, concepto:e.target.value}))}
                placeholder="Descripción del movimiento"
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Monto *</div>
              <input type="number" min="0" step="0.01" value={form.monto||''}
                onChange={e => setForm(f => ({...f, monto:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Fecha *</div>
              <input type="date" value={form.fecha||''} onChange={e => setForm(f => ({...f, fecha:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
          </div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:12, marginBottom:14 }}>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>N° comprobante</div>
              <input value={form.numero_comprobante||''} placeholder="Opcional"
                onChange={e => setForm(f => ({...f, numero_comprobante:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Vencimiento</div>
              <input type="date" value={form.fecha_vencimiento||''}
                onChange={e => setForm(f => ({...f, fecha_vencimiento:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
            </div>
            <div>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Período asociado</div>
              <select value={form.expensa_id||''} onChange={e => setForm(f => ({...f, expensa_id:e.target.value}))}
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                  borderRadius:7, fontSize:13, background:'#fff' }}>
                <option value="">Sin período</option>
                {expensas.map(e => <option key={e.id} value={e.id}>{e.periodo}</option>)}
              </select>
            </div>
          </div>
          <div style={{ marginBottom:14 }}>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Notas internas</div>
            <input value={form.notas||''} placeholder="Opcional"
              onChange={e => setForm(f => ({...f, notas:e.target.value}))}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db',
                borderRadius:7, fontSize:13, boxSizing:'border-box' }} />
          </div>
          <div style={{ display:'flex', gap:8 }}>
            <Btn onClick={guardar} disabled={guardando}
              style={{ background: form.tipo==='debito'?RJ:VD, color:'#fff' }}>
              {guardando ? '⏳' : '✓ Guardar'}
            </Btn>
            <BtnSec onClick={() => { setForm(null); setMsg(null) }}>Cancelar</BtnSec>
          </div>
        </Card>
      )}

      {/* Filtro */}
      <Card style={{ marginBottom:12 }}>
        <div style={{ display:'flex', gap:12, alignItems:'center' }}>
          <div style={{ flex:1 }}>
            <Sel label="Filtrar por unidad" value={filtroUF} onChange={setFiltroUF}
              opts={[{ v:'', l:'Todas las unidades' },
                ...unidades.map(u => {
                  const cp2 = copropietarios.find(c => c.id === u.propietario_id)
                  return { v:u.id, l:`${u.numero} — ${cp2?.apellido_nombre||''}` }
                })
              ]} />
          </div>
          <div style={{ fontSize:13, color:GR, marginTop:18 }}>
            {movs.filter(m=>m.estado==='vigente').length} movimientos
          </div>
        </div>
      </Card>

      {/* Listado */}
      <Card>
        {movs.length === 0 ? (
          <div style={{ textAlign:'center', padding:24, color:GR }}>Sin movimientos registrados</div>
        ) : (
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
              <thead>
                <tr style={{ background:'#f3f4f6' }}>
                  {['Fecha','Unidad','Tipo','Concepto','Monto','Estado',''].map((h,i) => (
                    <th key={i} style={{ padding:'7px 10px', textAlign: i===4?'right':'left',
                      fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {movs.map(m => {
                  const uf  = unidades.find(u => u.id === m.unidad_id)
                  return (
                    <tr key={m.id} style={{ borderBottom:'1px solid #f3f4f6',
                      opacity: m.estado==='anulado' ? 0.45 : 1,
                      background: m.estado==='anulado' ? '#f9fafb' : 'transparent' }}>
                      <td style={{ padding:'7px 10px', whiteSpace:'nowrap', color:GR, fontSize:11 }}>
                        {m.fecha ? new Date(m.fecha+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                      </td>
                      <td style={{ padding:'7px 10px', fontWeight:600 }}>UF {uf?.numero||'?'}</td>
                      <td style={{ padding:'7px 10px' }}>
                        <Badge text={m.tipo==='debito'?'Débito':'Crédito'}
                          color={m.tipo==='debito'?RJ:VD}
                          bg={m.tipo==='debito'?'#fee2e2':'#dcfce7'} />
                      </td>
                      <td style={{ padding:'7px 10px' }}>
                        <div>{m.concepto}</div>
                        {m.numero_comprobante && <div style={{ fontSize:10, color:GR }}>N° {m.numero_comprobante}</div>}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'right', fontWeight:700,
                        color: m.tipo==='debito'?RJ:VD }}>{fmt(m.monto)}</td>
                      <td style={{ padding:'7px 10px' }}>
                        <Badge text={m.estado==='vigente'?'Vigente':'Anulado'}
                          color={m.estado==='vigente'?VD:GR}
                          bg={m.estado==='vigente'?'#dcfce7':'#f3f4f6'} />
                      </td>
                      <td style={{ padding:'7px 10px' }}>
                        {m.estado === 'vigente' && (
                          <Btn small onClick={() => anular(m.id)}
                            style={{ background:'#fee2e2', color:RJ }}>✕ Anular</Btn>
                        )}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// CONTROL DE PERÍODOS
// ══════════════════════════════════════════════════════════════════════════════
function ControlPeriodos({ session, consorcioId, consorcioActivo, expensas }) {
  const [periodos, setPeriodos]   = useState([])
  const [msg, setMsg]             = useState(null)
  const [procesando, setProcesando] = useState(false)

  async function cargar() {
    const { data } = await supabase.from('con_periodos').select('*')
      .eq('consorcio_id', consorcioId).order('periodo', { ascending: false })
    setPeriodos(data || [])
  }

  async function abrirPeriodo() {
    const hoy = new Date()
    const mes = String(hoy.getMonth()+1).padStart(2,'0')
    const periodo = `${hoy.getFullYear()}-${mes}`

    // Verificar si ya existe
    const existe = periodos.find(p => p.periodo === periodo)
    if (existe) return setMsg({ tipo:'warn', texto:`El período ${periodo} ya existe` })

    setProcesando(true)
    const { error } = await supabase.from('con_periodos').insert([{
      id: `PER-${consorcioId}-${periodo}`,
      admin_id: session.user.id,
      consorcio_id: consorcioId,
      periodo,
      estado: 'abierto',
      fecha_apertura: hoy.toISOString().split('T')[0],
      expensas_generadas: expensas.some(e => e.periodo === periodo),
    }])
    if (error) setMsg({ tipo:'error', texto: error.message })
    else { setMsg({ tipo:'ok', texto: `✓ Período ${periodo} abierto` }); cargar() }
    setProcesando(false)
  }

  async function cerrarPeriodo(p) {
    // Verificar que tenga expensas generadas
    const tieneExpensa = expensas.some(e => e.periodo === p.periodo)
    if (!tieneExpensa) {
      if (!confirm(`El período ${p.periodo} no tiene expensas generadas. ¿Cerrar de todas formas?`)) return
    }
    if (!confirm(`¿Cerrar definitivamente el período ${p.periodo}? No se podrán registrar movimientos en períodos cerrados.`)) return

    setProcesando(true)
    const { error } = await supabase.from('con_periodos')
      .update({ estado:'cerrado', fecha_cierre: new Date().toISOString().split('T')[0] })
      .eq('id', p.id)
    if (error) setMsg({ tipo:'error', texto: error.message })
    else { setMsg({ tipo:'ok', texto: `✓ Período ${p.periodo} cerrado` }); cargar() }
    setProcesando(false)
  }

  async function reabrirPeriodo(p) {
    if (!confirm(`¿Reabrir el período ${p.periodo}?`)) return
    setProcesando(true)
    await supabase.from('con_periodos')
      .update({ estado:'abierto', fecha_cierre: null })
      .eq('id', p.id)
    setMsg({ tipo:'ok', texto: `✓ Período ${p.periodo} reabierto` })
    cargar()
    setProcesando(false)
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId])

  const periodoLabel = periodo => {
    const [y,m] = (periodo||'').split('-')
    const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio',
      'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre']
    return m ? `${meses[parseInt(m)-1]} ${y}` : periodo
  }

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>🔒 Control de períodos</div>
        <Btn onClick={abrirPeriodo} disabled={procesando}>+ Abrir período actual</Btn>
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Gestión del ciclo contable mensual de {consorcioActivo?.nombre}
      </div>
      <Msg data={msg} />

      {/* Info */}
      <Card style={{ marginBottom:16, background:'#eff6ff', border:'1px solid #bae6fd' }}>
        <div style={{ fontSize:13, color:'#1e40af', lineHeight:1.8 }}>
          <strong>Flujo recomendado por período:</strong>
          <div style={{ marginTop:6, display:'grid', gridTemplateColumns:'repeat(5,1fr)', gap:8, fontSize:12 }}>
            {['1. Cargar gastos','2. Generar expensa','3. Calcular mora','4. Registrar cobranzas','5. Cerrar período'].map((s,i) => (
              <div key={i} style={{ background:'#dbeafe', borderRadius:6, padding:'6px 8px',
                textAlign:'center', fontWeight:600, color:'#1e40af' }}>{s}</div>
            ))}
          </div>
        </div>
      </Card>

      {/* Tabla de períodos */}
      {periodos.length === 0 ? (
        <Card>
          <div style={{ textAlign:'center', padding:24, color:GR }}>
            Sin períodos registrados. Haga clic en "Abrir período actual" para comenzar.
          </div>
        </Card>
      ) : (
        <Card>
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
              <thead>
                <tr style={{ background:'#f3f4f6' }}>
                  {['Período','Estado','Apertura','Cierre','Expensas','Acciones'].map((h,i) => (
                    <th key={i} style={{ padding:'8px 12px', textAlign:'left',
                      fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {periodos.map(p => {
                  const tieneExpensa = expensas.some(e => e.periodo === p.periodo)
                  return (
                    <tr key={p.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                      <td style={{ padding:'10px 12px', fontWeight:700 }}>{periodoLabel(p.periodo)}</td>
                      <td style={{ padding:'10px 12px' }}>
                        <Badge text={p.estado==='abierto'?'🔓 Abierto':'🔒 Cerrado'}
                          color={p.estado==='abierto'?VD:'#374151'}
                          bg={p.estado==='abierto'?'#dcfce7':'#f3f4f6'} />
                      </td>
                      <td style={{ padding:'10px 12px', color:GR, fontSize:12 }}>
                        {p.fecha_apertura ? new Date(p.fecha_apertura+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                      </td>
                      <td style={{ padding:'10px 12px', color:GR, fontSize:12 }}>
                        {p.fecha_cierre ? new Date(p.fecha_cierre+'T00:00:00').toLocaleDateString('es-AR') : '—'}
                      </td>
                      <td style={{ padding:'10px 12px' }}>
                        <Badge text={tieneExpensa?'✓ Generadas':'Pendiente'}
                          color={tieneExpensa?VD:AM}
                          bg={tieneExpensa?'#dcfce7':'#fef9c3'} />
                      </td>
                      <td style={{ padding:'10px 12px' }}>
                        {p.estado === 'abierto' ? (
                          <Btn small onClick={() => cerrarPeriodo(p)} disabled={procesando}
                            style={{ background:'#374151', color:'#fff' }}>
                            🔒 Cerrar
                          </Btn>
                        ) : (
                          <Btn small onClick={() => reabrirPeriodo(p)} disabled={procesando}
                            style={{ background:'#f3f4f6', color:'#374151' }}>
                            🔓 Reabrir
                          </Btn>
                        )}
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </Card>
      )}
    </div>
  )
}

function PerfilAdmin({ session }) {
  const [perfil, setPerfil] = useState({ nombre:'', telefono:'', matricula_rpac:'', email:'', direccion:'', horario:'', cuit:'', situacion_fiscal:'Monotributo', firma_url:'', sello_url:'', texto_encabezado_liquidacion:'', texto_pie_liquidacion:'' })
  const [guardando, setGuardando] = useState(false)
  const [cargando, setCargando]   = useState(true)
  const [msg, setMsg]             = useState(null)
  const [tabActiva, setTabActiva] = useState('datos')

  useEffect(() => {
    async function cargar() {
      const { data } = await supabase.from('con_admin_perfil').select('*').eq('admin_id',session.user.id).single()
      if (data) setPerfil({...data, email:data.email||session.user.email||''})
      else setPerfil(p=>({...p, email:session.user.email||''}))
      setCargando(false)
    }
    cargar()
  }, [session])

  async function guardar() {
    setGuardando(true)
    const { error } = await supabase.from('con_admin_perfil').upsert({ admin_id:session.user.id, ...perfil, updated_at:new Date().toISOString() }, { onConflict:'admin_id' })
    if (error) setMsg({ tipo:'error', texto:error.message })
    else setMsg({ tipo:'ok', texto:'✓ Perfil guardado correctamente' })
    setGuardando(false)
  }
  const P = f => setPerfil(p=>({...p,...f}))
  if (cargando) return <div style={{ textAlign:'center', color:GR, padding:40 }}>Cargando...</div>

  const tabs = [
    { id:'datos', label:'Datos personales' },
    { id:'pdf', label:'PDF de liquidación' },
  ]

  return (
    <div style={{ maxWidth:640 }}>
      <div style={{ fontWeight:700, fontSize:16, color:'#111827', marginBottom:16 }}>⚙️ Mi perfil de administrador</div>
      <Msg data={msg} />

      {/* Alerta si el perfil está vacío */}
      {!perfil.nombre && (
        <div style={{ background:'#fff3cd', border:'1px solid #ffc107', borderRadius:8, padding:'10px 14px', marginBottom:14, fontSize:13, color:'#856404' }}>
          ⚠️ <strong>Perfil incompleto.</strong> El nombre y los datos del administrador aparecerán en el PDF de liquidación. Completá el perfil antes de generar liquidaciones.
        </div>
      )}

      {/* Tabs */}
      <div style={{ display:'flex', gap:4, marginBottom:16, borderBottom:'2px solid #e5e7eb' }}>
        {tabs.map(t=>(
          <button key={t.id} onClick={()=>setTabActiva(t.id)}
            style={{ padding:'8px 18px', border:'none', background:'none', cursor:'pointer', fontSize:13, fontWeight:tabActiva===t.id?700:400, color:tabActiva===t.id?AZ:GR, borderBottom:tabActiva===t.id?`2px solid ${AZ}`:'2px solid transparent', marginBottom:-2 }}>
            {t.label}
          </button>
        ))}
      </div>

      {tabActiva === 'datos' && (
        <Card style={{ marginBottom:16 }}>
          <div style={{ fontWeight:600, color:AZ, marginBottom:14, fontSize:13 }}>Datos personales y profesionales</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, marginBottom:16 }}>
            <Input label="Nombre completo" value={perfil.nombre||''} onChange={v=>P({nombre:v})} placeholder="Javier García Pérez" />
            <Input label="Email" value={perfil.email||''} onChange={v=>P({email:v})} />
            <Input label="Teléfono" value={perfil.telefono||''} onChange={v=>P({telefono:v})} placeholder="02267 444034" />
            <Input label="Matrícula RPAC" value={perfil.matricula_rpac||''} onChange={v=>P({matricula_rpac:v})} placeholder="83" />
            <Input label="CUIT" value={perfil.cuit||''} onChange={v=>P({cuit:v})} placeholder="20186006802" />
            <Sel label="Situación fiscal" value={perfil.situacion_fiscal||'Monotributo'} onChange={v=>P({situacion_fiscal:v})} opts={['Monotributo','Responsable Inscripto','Exento']} />
            <div style={{ gridColumn:'span 2' }}><Input label="Dirección de oficina" value={perfil.direccion||''} onChange={v=>P({direccion:v})} placeholder="Lenguado 1313 - Local 3" /></div>
            <div style={{ gridColumn:'span 2' }}><Input label="Horario de atención" value={perfil.horario||''} onChange={v=>P({horario:v})} placeholder="Lunes a Sábados 9:00 a 13:00 hs" /></div>
          </div>
          <Btn onClick={guardar} disabled={guardando}>{guardando?'Guardando...':'💾 Guardar perfil'}</Btn>
        </Card>
      )}

      {tabActiva === 'pdf' && (
        <Card style={{ marginBottom:16 }}>
          <div style={{ fontWeight:600, color:AZ, marginBottom:14, fontSize:13 }}>Configuración del PDF de liquidación</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:14, marginBottom:14 }}>
            <div style={{ gridColumn:'span 2' }}>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Texto de encabezado (aparece arriba, debajo del logo)</div>
              <textarea value={perfil.texto_encabezado_liquidacion||''} onChange={e=>P({texto_encabezado_liquidacion:e.target.value})}
                rows={3} placeholder="Ej: Período de liquidación correspondiente al mes de..."
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, fontFamily:'inherit', resize:'vertical', boxSizing:'border-box' }} />
            </div>
            <div style={{ gridColumn:'span 2' }}>
              <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Texto de pie de página (aparece al final del PDF)</div>
              <textarea value={perfil.texto_pie_liquidacion||''} onChange={e=>P({texto_pie_liquidacion:e.target.value})}
                rows={3} placeholder="Ej: Atención: Los pagos realizados fuera de término..."
                style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, fontFamily:'inherit', resize:'vertical', boxSizing:'border-box' }} />
            </div>
            <div style={{ gridColumn:'span 2' }}>
              <Input label="URL de firma digital (imagen PNG/JPG, fondo transparente)" value={perfil.firma_url||''} onChange={v=>P({firma_url:v})} placeholder="https://..." />
              {perfil.firma_url && <img src={perfil.firma_url} alt="Firma" style={{ marginTop:8, maxHeight:60, maxWidth:200, border:'1px solid #e5e7eb', borderRadius:6 }} onError={e=>e.target.style.display='none'} />}
            </div>
            <div style={{ gridColumn:'span 2' }}>
              <Input label="URL de sello (imagen PNG/JPG, fondo transparente)" value={perfil.sello_url||''} onChange={v=>P({sello_url:v})} placeholder="https://..." />
              {perfil.sello_url && <img src={perfil.sello_url} alt="Sello" style={{ marginTop:8, maxHeight:60, maxWidth:200, border:'1px solid #e5e7eb', borderRadius:6 }} onError={e=>e.target.style.display='none'} />}
            </div>
          </div>
          <div style={{ fontSize:11, color:GR, marginBottom:12, background:'#f9fafb', padding:'8px 12px', borderRadius:6 }}>
            💡 Para subir imágenes de firma/sello puede usar servicios como <a href="https://imgbb.com" target="_blank" rel="noreferrer" style={{ color:AZ }}>ImgBB</a> o Google Drive (compartir como pública) y pegar la URL aquí.
          </div>
          <Btn onClick={guardar} disabled={guardando}>{guardando?'Guardando...':'💾 Guardar configuración PDF'}</Btn>
        </Card>
      )}

      <Card>
        <div style={{ fontSize:13, color:'#6b7280', marginBottom:8, fontWeight:600 }}>Sesión activa</div>
        <div style={{ fontSize:13, color:'#374151', marginBottom:10 }}>{session?.user?.email}</div>
        <Btn color='#991B1B' small onClick={async()=>{ await supabase.auth.signOut() }}>Cerrar sesión</Btn>
      </Card>
    </div>
  )
}

// ══════════════════════════════════════════════════════════════════════════════
// APP PRINCIPAL
// ══════════════════════════════════════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════════════════════
// LISTADO DE CONSORCIOS — búsqueda, PDF y Excel
// ══════════════════════════════════════════════════════════════════════════════
function ListadoConsorcios({ session, consorcios }) {
  const [busqueda, setBusqueda] = useState('')

  const filtrados = consorcios.filter(c => {
    const q = busqueda.toLowerCase()
    return !q || c.nombre?.toLowerCase().includes(q) || c.cuit?.toLowerCase().includes(q)
      || c.direccion?.toLowerCase().includes(q) || c.localidad?.toLowerCase().includes(q)
      || c.banco?.toLowerCase().includes(q) || c.clave_suterh?.toLowerCase().includes(q)
  })

  function handlePDF() {
    // PDF en landscape para tener más espacio horizontal
    const fmtN = n => (Number(n)||0).toLocaleString('es-AR', { minimumFractionDigits:2 })
    const logo = LOGO_ADM_B64 ? `<img src="${LOGO_ADM_B64}" style="height:44px;width:auto;object-fit:contain"/>` : ''

    const filasHTML = filtrados.map((c,i) => {
      const bg = i%2===0 ? '#fff' : '#f4f8fc'
      const dir = [c.direccion, c.localidad].filter(Boolean).join(' — ') || '—'
      return `<tr style="background:${bg};border-bottom:1px solid #e0e8f0">
        <td style="padding:3px 6px;font-size:7.5pt;font-weight:600;color:#1A3FA0">${(c.nombre||'').replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:7pt;white-space:nowrap">${(c.cuit||'—').replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:7pt">${dir.replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:7pt">${(c.banco||'—').replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:6.5pt;font-family:monospace">${(c.cbu||'—')}</td>
        <td style="padding:3px 6px;font-size:7pt;color:#1A3FA0">${(c.alias_cbu||'—').replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:7pt;text-align:center">${(c.nro_cuenta||'—').replace(/</g,'&lt;')}</td>
        <td style="padding:3px 6px;font-size:7pt;text-align:center">${c.clave_suterh||'—'}</td>
        <td style="padding:3px 6px;font-size:7pt;text-align:center;color:${parseFloat(c.interes_mora||0)>0?'#92400e':'#6b7280'};font-weight:${parseFloat(c.interes_mora||0)>0?700:400}">${c.interes_mora ? c.interes_mora+'%' : '—'}</td>
      </tr>`
    }).join('')

    const html = `<!DOCTYPE html>
<html lang="es"><head><meta charset="UTF-8">
<title>Listado de Consorcios</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:Arial,Helvetica,sans-serif;font-size:9pt;color:#111;background:#fff}
  .page{width:297mm;min-height:210mm;padding:9mm 11mm 8mm;position:relative}
  @page{size:A4 landscape;margin:0}
  @media print{body{margin:0}.no-print{display:none!important}*{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}}
  .hdr{display:flex;align-items:center;gap:14px;border-bottom:3px solid #1A3FA0;padding-bottom:7px;margin-bottom:10px}
  table{width:100%;border-collapse:collapse}
  th{background:#2e4057;color:#fff;padding:4px 6px;font-size:7.5pt;text-align:left;white-space:nowrap}
  .footer{position:absolute;bottom:6mm;left:11mm;right:11mm;display:flex;justify-content:space-between;border-top:1px solid #ccc;padding-top:3px;font-size:6pt;color:#888}
  .btn-imp{display:block;margin:12px auto;padding:9px 24px;background:#1A3FA0;color:#fff;border:none;border-radius:6px;font-size:13px;cursor:pointer;font-family:Arial}
</style></head><body>
<button class="btn-imp no-print" onclick="window.print()">🖨️ Imprimir / Guardar PDF</button>
<div class="page">
  <div class="hdr">
    ${logo}
    <div style="flex:1">
      <div style="font-size:14pt;font-weight:800;color:#1A3FA0">Listado de Consorcios</div>
      <div style="font-size:8.5pt;color:#374151">Generado: ${new Date().toLocaleDateString('es-AR')} — Administración de Consorcios Pinamar — R.P.A.C. N° 83</div>
    </div>
    <div style="font-size:22pt;font-weight:800;color:#1A3FA0">${filtrados.length}</div>
    <div style="font-size:8pt;color:#6b7280">consorcio${filtrados.length!==1?'s':''}</div>
  </div>

  <table>
    <thead>
      <tr>
        <th style="min-width:120px">Nombre</th>
        <th style="width:105px">CUIT</th>
        <th style="min-width:100px">Dirección / Localidad</th>
        <th style="width:80px">Banco</th>
        <th style="width:155px">CBU</th>
        <th style="width:90px">Alias</th>
        <th style="width:70px">N° Cuenta</th>
        <th style="width:70px;text-align:center">SUTERH</th>
        <th style="width:52px;text-align:center">Mora %</th>
      </tr>
    </thead>
    <tbody>${filasHTML}</tbody>
    <tfoot>
      <tr style="background:#0d2b3e;color:#fff;font-weight:700">
        <td colspan="9" style="padding:4px 6px;font-size:8pt">
          Total: ${filtrados.length} consorcio${filtrados.length!==1?'s':''} administrado${filtrados.length!==1?'s':''}
        </td>
      </tr>
    </tfoot>
  </table>

  <div class="footer">
    <span>Listado de Consorcios — Administración de Consorcios Pinamar</span>
    <span>R.P.A.C. N°83 | CUIT Administración: 20186006802</span>
    <span>${new Date().toLocaleDateString('es-AR')}</span>
  </div>
</div>
</body></html>`

    const blob = new Blob([html], { type:'text/html;charset=utf-8' })
    const url  = URL.createObjectURL(blob)
    window.open(url, '_blank', 'width=1050,height=750')
    setTimeout(()=>URL.revokeObjectURL(url), 60000)
  }

  function handleExcel() {
    exportarExcel({
      titulo: 'Consorcios',
      columnas: [
        { key:'nombre',   label:'Nombre' },
        { key:'cuit',     label:'CUIT' },
        { key:'direccion',label:'Dirección' },
        { key:'localidad',label:'Localidad' },
        { key:'banco',    label:'Banco' },
        { key:'cbu',      label:'CBU' },
        { key:'alias',    label:'Alias CBU' },
        { key:'nro_cta',  label:'N° Cuenta' },
        { key:'suterh',   label:'Clave SUTERH' },
        { key:'mora',     label:'Interés Mora %' },
      ],
      filas: filtrados.map(c => ({
        nombre: c.nombre||'', cuit: c.cuit||'',
        direccion: c.direccion||'', localidad: c.localidad||'',
        banco: c.banco||'', cbu: c.cbu||'', alias: c.alias_cbu||'',
        nro_cta: c.nro_cuenta||'', suterh: c.clave_suterh||'',
        mora: c.interes_mora||'',
      }))
    })
  }

  return (
    <div>
      <div style={{ fontWeight:700, fontSize:15, marginBottom:4 }}>🏛️ Mis Consorcios</div>
      <div style={{ fontSize:12, color:GR, marginBottom:12 }}>
        {consorcios.length} consorcio{consorcios.length!==1?'s':''} administrado{consorcios.length!==1?'s':''}
      </div>

      <BarraListado
        busqueda={busqueda} onBuscar={setBusqueda}
        onPDF={handlePDF} onExcel={handleExcel}
        placeholder="Buscar por nombre, CUIT, dirección, banco, SUTERH..." />

      {filtrados.length === 0 ? (
        <Card style={{ textAlign:'center', padding:32, color:GR }}>
          <div style={{ fontSize:28, marginBottom:8 }}>🏛️</div>
          <div>No hay consorcios que coincidan con la búsqueda.</div>
        </Card>
      ) : (
        <div style={{ overflowX:'auto' }}>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead>
              <tr style={{ background:'#2e4057' }}>
                {['Nombre','CUIT','Dirección','Banco','CBU','Alias','N° Cuenta','SUTERH','Mora%'].map((h,i) => (
                  <th key={i} style={{ padding:'8px 10px', textAlign:'left', fontSize:11,
                    fontWeight:700, color:'#fff', whiteSpace:'nowrap' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtrados.map((c,i) => (
                <tr key={c.id} style={{ borderBottom:'1px solid #e5e7eb', background: i%2===0?'#fff':'#f4f8fc' }}>
                  <td style={{ padding:'9px 10px', fontWeight:700, color:AZ }}>{c.nombre}</td>
                  <td style={{ padding:'9px 10px', fontSize:11, color:GR, whiteSpace:'nowrap' }}>{c.cuit||'—'}</td>
                  <td style={{ padding:'9px 10px', fontSize:11 }}>
                    {c.direccion && <div>{c.direccion}</div>}
                    {c.localidad && <div style={{ color:GR, fontSize:10 }}>{c.localidad}</div>}
                    {!c.direccion && !c.localidad && '—'}
                  </td>
                  <td style={{ padding:'9px 10px', fontSize:11 }}>{c.banco||'—'}</td>
                  <td style={{ padding:'9px 10px', fontSize:10, fontFamily:'monospace' }}>{c.cbu||'—'}</td>
                  <td style={{ padding:'9px 10px', fontSize:11, color:AZ }}>{c.alias_cbu||'—'}</td>
                  <td style={{ padding:'9px 10px', fontSize:11 }}>{c.nro_cuenta||'—'}</td>
                  <td style={{ padding:'9px 10px', fontSize:11, fontWeight:c.clave_suterh?600:400 }}>
                    {c.clave_suterh||'—'}
                  </td>
                  <td style={{ padding:'9px 10px', fontSize:12, textAlign:'right',
                    fontWeight: parseFloat(c.interes_mora||0) > 0 ? 700 : 400,
                    color: parseFloat(c.interes_mora||0) > 0 ? AM : GR }}>
                    {c.interes_mora ? c.interes_mora + '%' : '—'}
                  </td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr style={{ background:'#f0f4ff', borderTop:'2px solid '+AZ }}>
                <td colSpan={9} style={{ padding:'8px 10px', fontWeight:700, color:AZ, fontSize:12 }}>
                  Total: {filtrados.length} consorcio{filtrados.length!==1?'s':''} administrado{filtrados.length!==1?'s':''}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      )}
    </div>
  )
}


function Dashboard({ consorcios, consorcioActivo, unidades, copropietarios,
  formCon, setFormCon, msgCon, guardarConsorcio, setConsorcioActivo,
  cargarConsorcio, setPagina }) {
  const totalUFs  = unidades.length
  const ocupadas  = unidades.filter(u => u.estado==='ocupada').length
  const coefTotal = unidades.reduce((a,u) => a + Number(u.porcentaje_fiscal||0), 0)
    return (
      <div>
        {consorcios.length>1 && (
          <div style={{ marginBottom:16, display:'flex', gap:10, alignItems:'center' }}>
            <span style={{ fontSize:13, color:GR, fontWeight:500, whiteSpace:'nowrap' }}>Consorcio:</span>
            <select
              value={consorcioActivo?.id||''}
              onChange={e => {
                const c = consorcios.find(x => x.id === e.target.value)
                if (c) { setConsorcioActivo(c); cargarConsorcio(c.id) }
              }}
              style={{ flex:1, padding:'7px 11px', borderRadius:8, border:'1px solid #d1d5db', fontSize:13, background:'#fff', cursor:'pointer' }}>
              {consorcios.map(c => <option key={c.id} value={c.id}>{c.nombre}</option>)}
            </select>
            <Btn small onClick={()=>setFormCon({})}>+ Nuevo</Btn>
          </div>
        )}
        {consorcios.length===0 && (
          <Card style={{ textAlign:'center', padding:40, marginBottom:20, border:`2px dashed ${AZ}` }}>
            <div style={{ fontSize:40, marginBottom:12 }}>🏢</div>
            <div style={{ fontWeight:700, fontSize:16, marginBottom:8 }}>Bienvenido a GASP Consorcios</div>
            <div style={{ color:GR, fontSize:13, marginBottom:20 }}>Creá tu primer consorcio para comenzar</div>
            <Btn onClick={()=>setFormCon({})}>+ Crear primer consorcio</Btn>
          </Card>
        )}
        {formCon && (
          <Card style={{ marginBottom:20, border:`1px solid ${AZ}` }}>
            <div style={{ fontWeight:700, color:AZ, marginBottom:14 }}>{formCon.id?'Editar consorcio':'Nuevo consorcio'}</div>
            {msgCon && <Msg data={msgCon} />}
            <div style={{ fontWeight:600, color:GR, fontSize:12, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.5px' }}>Datos generales</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <Input label="Nombre del consorcio" value={formCon.nombre} onChange={v=>setFormCon(x=>({...x,nombre:v}))} required />
              <Input label="CUIT" value={formCon.cuit} onChange={v=>setFormCon(x=>({...x,cuit:v}))} placeholder="30-XXXXXXXX-X" />
              <Input label="Dirección" value={formCon.direccion} onChange={v=>setFormCon(x=>({...x,direccion:v}))} />
              <Input label="Localidad" value={formCon.localidad} onChange={v=>setFormCon(x=>({...x,localidad:v}))} />
              <Input label="Clave SUTERH" value={formCon.clave_suterh} onChange={v=>setFormCon(x=>({...x,clave_suterh:v}))} />
              <Input label="Interés mora mensual %" value={formCon.interes_mora} onChange={v=>setFormCon(x=>({...x,interes_mora:v}))} type="number" placeholder="5" />
            </div>
            <div style={{ fontWeight:600, color:GR, fontSize:12, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.5px' }}>Datos bancarios</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <Input label="CBU" value={formCon.cbu||''} onChange={v=>setFormCon(x=>({...x,cbu:v}))} placeholder="28505909300941..." />
              <Input label="Alias CBU" value={formCon.alias_cbu||''} onChange={v=>setFormCon(x=>({...x,alias_cbu:v}))} placeholder="PALABRA.PALABRA.PALABRA" />
              <Input label="Banco" value={formCon.banco||''} onChange={v=>setFormCon(x=>({...x,banco:v}))} placeholder="Macro" />
              <Input label="Sucursal" value={formCon.sucursal||''} onChange={v=>setFormCon(x=>({...x,sucursal:v}))} placeholder="Pinamar" />
              <Input label="Nº de cuenta" value={formCon.nro_cuenta||''} onChange={v=>setFormCon(x=>({...x,nro_cuenta:v}))} />
            </div>
            <div style={{ fontWeight:600, color:GR, fontSize:12, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.5px' }}>📖 Reglamento de propiedad</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <Input label="Matrícula RPI" value={formCon.matricula_rpi||''} onChange={v=>setFormCon(x=>({...x,matricula_rpi:v}))} placeholder="21.525" />
              <Input label="Escritura N°" value={formCon.escritura_nro||''} onChange={v=>setFormCon(x=>({...x,escritura_nro:v}))} placeholder="395" />
              <div style={{ gridColumn:'span 2' }}>
                <Input label="Fecha escritura" value={formCon.escritura_fecha||''} onChange={v=>setFormCon(x=>({...x,escritura_fecha:v}))} placeholder="19 de mayo de 1994" />
              </div>
              <div style={{ gridColumn:'span 2' }}>
                <Input label="Escribano/a autorizante" value={formCon.escritura_escribano||''} onChange={v=>setFormCon(x=>({...x,escritura_escribano:v}))} placeholder="Horacio F. Ballestrin" />
              </div>
            </div>
            <div style={{ fontWeight:600, color:GR, fontSize:12, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.5px' }}>🛡️ Póliza de seguro</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:14 }}>
              <Input label="N° de póliza" value={formCon.poliza_nro||''} onChange={v=>setFormCon(x=>({...x,poliza_nro:v}))} placeholder="250230763671" />
              <div style={{ gridColumn:'span 1' }}>
                <Input label="Compañía aseguradora" value={formCon.poliza_compania||''} onChange={v=>setFormCon(x=>({...x,poliza_compania:v}))} placeholder="Allianz Argentina" />
              </div>
              <Input label="Vigencia desde" value={formCon.poliza_vto_desde||''} onChange={v=>setFormCon(x=>({...x,poliza_vto_desde:v}))} type="date" />
              <Input label="Vigencia hasta" value={formCon.poliza_vto_hasta||''} onChange={v=>setFormCon(x=>({...x,poliza_vto_hasta:v}))} type="date" />
              <div style={{ gridColumn:'span 2' }}>
                <Input label="Suma asegurada incendio edificio ($)" value={formCon.poliza_suma||''} onChange={v=>setFormCon(x=>({...x,poliza_suma:v}))} type="number" placeholder="720000000" />
              </div>
            </div>
            <div style={{ fontWeight:600, color:GR, fontSize:12, marginBottom:10, textTransform:'uppercase', letterSpacing:'0.5px' }}>📁 Google Drive</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12, marginBottom:16 }}>
              <div style={{ gridColumn:'span 2' }}>
                <Input label="URL carpeta Drive del consorcio" value={formCon.drive_folder_url||''} onChange={v=>setFormCon(x=>({...x,drive_folder_url:v}))} placeholder="https://drive.google.com/drive/folders/..." />
              </div>
              <div style={{ gridColumn:'span 2' }}>
                <Input label="ID carpeta Drive (último segmento de la URL)" value={formCon.drive_folder_id||''} onChange={v=>setFormCon(x=>({...x,drive_folder_id:v}))} placeholder="1EXlLiRq6G43qzwLvLGR_UkM-TB9BeH58" />
              </div>
            </div>
            <div style={{ display:'flex', gap:8 }}>
              <Btn onClick={guardarConsorcio}>{formCon.id?'💾 Actualizar':'Crear'}</Btn>
              <BtnSec onClick={()=>setFormCon(null)}>Cancelar</BtnSec>
            </div>
          </Card>
        )}
        {consorcioActivo && (
          <>
            <div style={{ background:`linear-gradient(135deg,${AZ} 0%,${AZ2} 100%)`, borderRadius:12, padding:24, marginBottom:20, color:'#fff' }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
                <div>
                  <div style={{ fontSize:11, opacity:0.7, textTransform:'uppercase', letterSpacing:1 }}>Consorcio activo</div>
                  <div style={{ fontSize:22, fontWeight:800, marginTop:4 }}>{consorcioActivo.nombre}</div>
                  {consorcioActivo.direccion && <div style={{ fontSize:13, opacity:0.8, marginTop:2 }}>📍 {consorcioActivo.direccion}{consorcioActivo.localidad?`, ${consorcioActivo.localidad}`:''}</div>}
                  {consorcioActivo.cbu && <div style={{ fontSize:11, opacity:0.7, marginTop:4 }}>CBU: {consorcioActivo.cbu} · Alias: {consorcioActivo.alias_cbu}</div>}
                </div>
                <BtnSec small onClick={()=>setFormCon({...consorcioActivo})} style={{ background:'rgba(255,255,255,0.15)', color:'#fff', border:'1px solid rgba(255,255,255,0.3)' }}>✏ Editar</BtnSec>
              </div>
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:14, marginBottom:24 }}>
              {[{l:'Unidades',v:totalUFs,c:AZ,icon:'🏢',action:'unidades'},{l:'Cta. Cte. UFs',v:'→',c:VD,icon:'📋',action:'cta_corriente'},{l:'Copropietarios',v:copropietarios.length,c:AM,icon:'👤',action:'copropietarios'},{l:'Coef. total',v:coefTotal.toFixed(2)+'%',c:'#6d28d9',icon:'📊',action:null}].map((k,i)=>(
                <button key={i} onClick={()=>{ if(k.action) setPagina(k.action) }}
                  style={{ textAlign:'center', cursor:k.action?'pointer':'default', background:'#fff', border:'0.5px solid #ddd', borderRadius:10, padding:16, width:'100%' }}>
                  <div style={{ fontSize:24, marginBottom:6 }}>{k.icon}</div>
                  <div style={{ fontSize:26, fontWeight:800, color:k.c }}>{k.v}</div>
                  <div style={{ fontSize:11, color:GR, marginTop:4 }}>{k.l}</div>
                </button>
              ))}
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
              {[{id:'cobranzas',icon:'💳',label:'Cobranzas',desc:'Registro de cobros y cobranza automática'},{id:'comprobantes',icon:'🧾',label:'Comprobantes',desc:'Facturas y comprobantes de proveedores'},{id:'morosos',icon:'⚠️',label:'Ver Morosos',desc:'Cuotas pendientes y contacto'},{id:'cta_corriente',icon:'📋',label:'Cta. corriente UF',desc:'Movimientos por unidad funcional'},{id:'sueldos',icon:'👷',label:'Sueldos',desc:'Liquidación de sueldos y cargas sociales'}].map(m=>(
                <button key={m.id} onClick={()=>{ setPagina(m.id) }}
                  style={{ cursor:'pointer', background:'#fff', border:'0.5px solid #ddd', borderRadius:10, padding:16, width:'100%', textAlign:'left' }}>
                  <div style={{ fontSize:28, marginBottom:8 }}>{m.icon}</div>
                  <div style={{ fontWeight:700, fontSize:15 }}>{m.label}</div>
                  <div style={{ fontSize:12, color:GR, marginTop:4 }}>{m.desc}</div>
                </button>
              ))}
            </div>
          </>
        )}
        {consorcios.length===1 && (
          <div style={{ marginTop:20, textAlign:'right' }}>
            <BtnSec small onClick={()=>setFormCon({})}>+ Agregar otro consorcio</BtnSec>
          </div>
        )}
      </div>
    )
}



// ════════════════════════════════════════════════════════════════════════════
// EMAIL TRACKING — Seguimiento de liquidaciones enviadas
function EmailTracking({ session, consorcioId }) {
  const [logs, setLogs]           = useState([])
  const [cargando, setCargando]   = useState(true)
  const [filtroEstado, setFiltroEstado] = useState('')
  const [filtroExp, setFiltroExp] = useState('')
  const [expensas, setExpensas2]  = useState([])
  const [stats, setStats]         = useState(null)

  const cargar = async () => {
    setCargando(true)
    const [{ data: logsData }, { data: exps }] = await Promise.all([
      supabase.from('con_email_log').select('*')
        .eq('consorcio_id', consorcioId)
        .order('created_at', { ascending: false })
        .limit(500),
      supabase.from('con_expensas').select('id,periodo')
        .eq('consorcio_id', consorcioId)
        .order('periodo', { ascending: false }),
    ])
    const data = logsData || []
    setLogs(data)
    setExpensas2(exps || [])

    // Calcular stats
    const total    = data.length
    const enviados = data.filter(l => l.estado === 'enviado').length
    const errores  = data.filter(l => l.estado === 'error').length
    const abiertos = data.filter(l => l.abierto).length
    setStats({ total, enviados, errores, abiertos,
      tasa_entrega: total > 0 ? Math.round(enviados/total*100) : 0,
      tasa_apertura: enviados > 0 ? Math.round(abiertos/enviados*100) : 0,
    })
    setCargando(false)
  }

  const verificarEstado = async (log) => {
    if (!log.resend_id) return
    setMsg({ tipo:'info', texto:'⏳ Verificando estado en Resend...' })
    try {
      const { data: { session: sess } } = await supabase.auth.getSession()
      const res = await fetch(`${SUPA_URL}/functions/v1/verificar-email-estado`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${sess?.access_token}`,
          'apikey': process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
        },
        body: JSON.stringify({ resend_id: log.resend_id, log_id: log.id })
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error || `Error ${res.status}`)
      const eventos = data.eventos || []
      const resumen = eventos.length > 0
        ? eventos.map(e => e.name).join(', ')
        : 'Sin eventos registrados'
      setMsg({ tipo:'ok', texto:`✓ ${data.abierto ? '👁 Abierto' : data.entregado ? '✓ Entregado' : '📤 Enviado'} — Eventos: ${resumen}` })
      cargar()
    } catch(e) {
      setMsg({ tipo:'error', texto: 'Error: ' + e.message })
    }
  }

  const reenviar = async (log) => {
    if (!confirm(`¿Reenviar el email a ${log.destinatario}?`)) return
    // Marcar como pendiente y disparar reenvío
    await supabase.from('con_email_log').update({ estado:'pendiente_reenvio' }).eq('id', log.id)
    cargar()
  }

  const verificarTodos = async () => {
    const conResendId = logs.filter(l => l.resend_id && !l.abierto)
    if (conResendId.length === 0) { setMsg({ tipo:'info', texto:'Todos los emails ya están verificados' }); return }
    setMsg({ tipo:'info', texto:`⏳ Verificando ${conResendId.length} emails...` })
    let actualizados = 0
    for (const log of conResendId.slice(0, 20)) {  // máximo 20 a la vez
      try {
        const { data: { session: sess } } = await supabase.auth.getSession()
        const res = await fetch(`${SUPA_URL}/functions/v1/verificar-email-estado`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${sess?.access_token}`,
            'apikey': process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || '',
          },
          body: JSON.stringify({ resend_id: log.resend_id, log_id: log.id })
        })
        if (res.ok) actualizados++
      } catch(e) {}
    }
    setMsg({ tipo:'ok', texto:`✓ ${actualizados} emails verificados` })
    cargar()
  }

  useEffect(() => { if (consorcioId) cargar() }, [consorcioId])

  const fmtD = d => d ? new Date(d).toLocaleString('es-AR', {
    day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit'
  }) : '—'

  const periodoLabel = pid => {
    const exp = expensas.find(e=>e.id===pid)
    if (!exp) return '—'
    const [y,m] = (exp.periodo||'').split('-')
    const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
    return m ? `${meses[parseInt(m)-1]} ${y}` : exp.periodo
  }

  const ESTADOS = {
    enviado:          { label:'Enviado',    color:VD,  bg:'#dcfce7', icon:'✓' },
    error:            { label:'Error',      color:RJ,  bg:'#fee2e2', icon:'✕' },
    rebotado:         { label:'Rebotado',   color:RJ,  bg:'#fee2e2', icon:'↩' },
    pendiente_reenvio:{ label:'Reenviando', color:AM,  bg:'#fef9c3', icon:'⟳' },
  }

  const logsFiltrados = logs.filter(l => {
    if (filtroEstado && l.estado !== filtroEstado) return false
    if (filtroExp && l.expensa_id !== filtroExp) return false
    return true
  })

  // Agrupar por período para vista resumida
  const porPeriodo = {}
  for (const l of logs) {
    const k = l.expensa_id || 'sin_periodo'
    if (!porPeriodo[k]) porPeriodo[k] = { enviados:0, errores:0, abiertos:0, total:0 }
    porPeriodo[k].total++
    if (l.estado === 'enviado') porPeriodo[k].enviados++
    if (l.estado === 'error')   porPeriodo[k].errores++
    if (l.abierto)              porPeriodo[k].abiertos++
  }

  return (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4 }}>
        <div style={{ fontWeight:700, fontSize:15 }}>📬 Seguimiento de emails</div>
        <div style={{ display:'flex', gap:8 }}>
          <Btn small onClick={verificarTodos} style={{ background:'#eff6ff', color:AZ }}>⟳ Verificar todos</Btn>
          <Btn small onClick={cargar} style={{ background:'#f3f4f6', color:'#374151' }}>↺ Recargar</Btn>
        </div>
      </div>
      <div style={{ fontSize:12, color:GR, marginBottom:16 }}>
        Estado de entrega y apertura de liquidaciones enviadas por email
      </div>

      {/* KPIs */}
      {stats && (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(5,1fr)', gap:10, marginBottom:16 }}>
          {[
            { l:'Total enviados', v:stats.total,         c:AZ, bg:'#eff6ff' },
            { l:'Entregados',     v:stats.enviados,       c:VD, bg:'#f0fdf4' },
            { l:'Con error',      v:stats.errores,        c:RJ, bg:'#fff1f2' },
            { l:'Tasa entrega',   v:stats.tasa_entrega+'%', c:AZ, bg:'#f8fafc' },
            { l:'Aperturas',      v:stats.abiertos,       c:'#7c3aed', bg:'#faf5ff' },
          ].map((k,i) => (
            <div key={i} style={{ background:k.bg, borderRadius:10, padding:'12px 14px', textAlign:'center' }}>
              <div style={{ fontSize:11, color:k.c, fontWeight:600, textTransform:'uppercase', marginBottom:4 }}>{k.l}</div>
              <div style={{ fontSize:20, fontWeight:800, color:k.c }}>{k.v}</div>
            </div>
          ))}
        </div>
      )}

      {/* Resumen por período */}
      {Object.keys(porPeriodo).length > 0 && (
        <Card style={{ marginBottom:16 }}>
          <div style={{ fontWeight:600, fontSize:13, color:AZ, marginBottom:12 }}>Resumen por período</div>
          <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
            <thead>
              <tr style={{ background:'#f3f4f6' }}>
                {['Período','Enviados','Errores','Aperturas','Progreso'].map((h,i) => (
                  <th key={i} style={{ padding:'6px 10px', textAlign:i===0?'left':'center',
                    fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Object.entries(porPeriodo).map(([pid, s]) => {
                const pct = s.total > 0 ? Math.round(s.enviados/s.total*100) : 0
                return (
                  <tr key={pid} style={{ borderBottom:'1px solid #f3f4f6' }}>
                    <td style={{ padding:'8px 10px', fontWeight:600 }}>{periodoLabel(pid)}</td>
                    <td style={{ padding:'8px 10px', textAlign:'center' }}>
                      <span style={{ color:VD, fontWeight:700 }}>{s.enviados}</span>
                      <span style={{ color:GR }}> / {s.total}</span>
                    </td>
                    <td style={{ padding:'8px 10px', textAlign:'center' }}>
                      {s.errores > 0
                        ? <span style={{ color:RJ, fontWeight:700 }}>{s.errores}</span>
                        : <span style={{ color:VD }}>✓</span>}
                    </td>
                    <td style={{ padding:'8px 10px', textAlign:'center', color:'#7c3aed', fontWeight:600 }}>
                      {s.abiertos || '—'}
                    </td>
                    <td style={{ padding:'8px 10px' }}>
                      <div style={{ display:'flex', alignItems:'center', gap:6 }}>
                        <div style={{ flex:1, background:'#f3f4f6', borderRadius:4, height:6 }}>
                          <div style={{ width:`${pct}%`, background: pct===100?VD:AZ,
                            height:6, borderRadius:4 }} />
                        </div>
                        <span style={{ fontSize:10, color:GR, whiteSpace:'nowrap' }}>{pct}%</span>
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </Card>
      )}

      {/* Filtros */}
      <Card style={{ marginBottom:12 }}>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
          <div>
            <div style={{ fontSize:12, color:GR, marginBottom:4, fontWeight:500 }}>Estado</div>
            <select value={filtroEstado} onChange={e=>setFiltroEstado(e.target.value)}
              style={{ width:'100%', padding:'8px 11px', border:'1px solid #d1d5db', borderRadius:7, fontSize:13, background:'#fff' }}>
              <option value="">Todos</option>
              <option value="enviado">Enviados</option>
              <option value="error">Con error</option>
              <option value="rebotado">Rebotados</option>
            </select>
          </div>
          <Sel label="Período" value={filtroExp} onChange={setFiltroExp}
            opts={[{v:'',l:'Todos los períodos'},
              ...expensas.map(e => {
                const [y,m] = (e.periodo||'').split('-')
                const meses = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic']
                return { v:e.id, l:m?`${meses[parseInt(m)-1]} ${y}`:e.periodo }
              })
            ]} />
        </div>
      </Card>

      {/* Tabla detalle */}
      <Card>
        <div style={{ fontWeight:600, fontSize:13, marginBottom:10 }}>
          Detalle ({logsFiltrados.length} registros)
        </div>
        {cargando ? (
          <div style={{ textAlign:'center', padding:24, color:GR }}>⏳ Cargando...</div>
        ) : logsFiltrados.length === 0 ? (
          <div style={{ textAlign:'center', padding:24, color:GR }}>
            <div style={{ fontSize:28, marginBottom:8 }}>📭</div>
            <div>Sin emails registrados</div>
          </div>
        ) : (
          <div style={{ overflowX:'auto' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:12 }}>
              <thead>
                <tr style={{ background:'#f3f4f6' }}>
                  {['Fecha/Hora','Destinatario','Asunto','Estado','Abierto','Resend ID',''].map((h,i) => (
                    <th key={i} style={{ padding:'7px 10px', textAlign:'left',
                      fontSize:11, fontWeight:700, color:GR, borderBottom:'1px solid #e5e7eb',
                      whiteSpace:'nowrap' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {logsFiltrados.map(log => {
                  const est = ESTADOS[log.estado] || { label:log.estado, color:GR, bg:'#f3f4f6', icon:'?' }
                  return (
                    <tr key={log.id} style={{ borderBottom:'1px solid #f3f4f6' }}>
                      <td style={{ padding:'7px 10px', color:GR, fontSize:11, whiteSpace:'nowrap' }}>
                        {fmtD(log.created_at)}
                      </td>
                      <td style={{ padding:'7px 10px', maxWidth:160 }}>
                        <div style={{ fontWeight:500 }}>{log.destinatario}</div>
                      </td>
                      <td style={{ padding:'7px 10px', color:GR, fontSize:11, maxWidth:200 }}>
                        {log.asunto?.replace('Expensas ','').slice(0,50)}
                      </td>
                      <td style={{ padding:'7px 10px', whiteSpace:'nowrap' }}>
                        <Badge text={`${est.icon} ${est.label}`} color={est.color} bg={est.bg} />
                        {log.estado === 'error' && log.error_msg && (
                          <div style={{ fontSize:9, color:RJ, marginTop:2, maxWidth:120 }}>
                            {(() => { try { return JSON.parse(log.error_msg).message } catch { return log.error_msg?.slice(0,40) } })()}
                          </div>
                        )}
                      </td>
                      <td style={{ padding:'7px 10px', textAlign:'center' }}>
                        {log.abierto
                          ? <div>
                              <span style={{ color:'#7c3aed', fontWeight:700, fontSize:12 }}>👁 Sí</span>
                              {log.fecha_apertura && <div style={{ fontSize:10, color:GR }}>
                                {new Date(log.fecha_apertura).toLocaleDateString('es-AR')}
                              </div>}
                            </div>
                          : log.entregado
                            ? <span style={{ color:VD, fontSize:11 }}>✓ Entregado</span>
                            : log.rebotado
                              ? <span style={{ color:RJ, fontSize:11 }}>↩ Rebotado</span>
                              : <span style={{ color:GR, fontSize:11 }}>— Pendiente</span>
                        }
                      </td>
                      <td style={{ padding:'7px 10px', fontSize:10, color:GR, fontFamily:'monospace' }}>
                        {log.resend_id ? log.resend_id.slice(0,20)+'…' : '—'}
                      </td>
                      <td style={{ padding:'7px 10px' }}>
                        <div style={{ display:'flex', gap:4 }}>
                          {log.resend_id && (
                            <Btn small onClick={()=>verificarEstado(log)}
                              style={{ background:'#eff6ff', color:AZ }} title="Verificar estado en Resend">
                              ⟳
                            </Btn>
                          )}
                          {log.estado === 'error' && (
                            <Btn small onClick={()=>reenviar(log)}
                              style={{ background:'#fef9c3', color:AM }} title="Reenviar">
                              ↩
                            </Btn>
                          )}
                        </div>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        )}
      </Card>

      {/* Nota sobre tracking de aperturas */}
      <div style={{ marginTop:12, padding:'12px 14px', background:'#eff6ff',
        borderRadius:8, fontSize:11, color:'#1e40af', border:'1px solid #bfdbfe' }}>
        <strong>ℹ️ Sobre el tracking de aperturas:</strong>
        <div style={{ marginTop:4, lineHeight:1.7 }}>
          • El tracking de entrega funciona automáticamente con Resend.<br/>
          • El tracking de <strong>apertura</strong> requiere que el copropietario permita la carga de imágenes en su cliente de email (Gmail, Outlook, etc.).<br/>
          • Para activar el tracking completo, verificar el dominio <strong>administracionpinamar.com</strong> en resend.com → Domains.<br/>
          • Presionar <strong>"⟳ Verificar todos"</strong> para actualizar el estado de todos los emails desde Resend.
        </div>
      </div>
    </div>
  )
}



